export const allQuestions: Question[] = [
  { id: "lc-1", subject: "lectura-critica", topic: "Comprensi\u00f3n literal", difficulty: "facil", text: "Lee el siguiente texto:\n\n\"La biodiversidad en Colombia es una de las m\u00e1s ricas del mundo. El pa\u00eds alberga cerca del 10% de las especies del planeta, a pesar de ocupar menos del 1% de la superficie terrestre. Esta riqueza se debe a su variedad de ecosistemas, que incluyen selvas tropicales, p\u00e1ramos, manglares y arrecifes de coral.\"\n\n\u00bfCu\u00e1l es la idea principal del texto?", options: [{ label: "A", text: "Colombia ocupa el 1% de la superficie terrestre" }, { label: "B", text: "Colombia tiene una biodiversidad excepcionalmente rica gracias a sus diversos ecosistemas" }, { label: "C", text: "Los p\u00e1ramos son el ecosistema m\u00e1s importante de Colombia" }, { label: "D", text: "El 10% de las especies viven en las selvas tropicales colombianas" }], correctAnswer: "B", explanation: "La idea principal resume el mensaje central del texto: Colombia posee una gran biodiversidad gracias a la variedad de ecosistemas.", tip: "\ud83c\udfaf TRUCO ICFES: La idea principal es la oraci\u00f3n que, si la quitas, el texto pierde todo su sentido. Preg\u00fantate: '\u00bfDe qu\u00e9 habla TODO el texto?'" },
  { id: "lc-2", subject: "lectura-critica", topic: "Comprensi\u00f3n literal", difficulty: "facil", text: "\"El caf\u00e9 colombiano es reconocido mundialmente por su suavidad y aroma. Se cultiva principalmente en la zona cafetera, que comprende los departamentos de Caldas, Quind\u00edo y Risaralda. La altitud de estas regiones, entre 1.200 y 1.800 metros sobre el nivel del mar, proporciona las condiciones ideales para su cultivo.\"\n\n\u00bfCu\u00e1l es la altitud ideal para el cultivo del caf\u00e9 seg\u00fan el texto?", options: [{ label: "A", text: "Entre 800 y 1.200 metros" }, { label: "B", text: "Entre 1.200 y 1.800 metros" }, { label: "C", text: "M\u00e1s de 2.000 metros" }, { label: "D", text: "Menos de 1.000 metros" }], correctAnswer: "B", explanation: "El texto dice expl\u00edcitamente 'entre 1.200 y 1.800 metros sobre el nivel del mar'.", tip: "\ud83d\udccc TRUCO ICFES: En preguntas literales, la respuesta SIEMPRE est\u00e1 escrita en el texto. Subraya mentalmente los n\u00fameros y datos clave." },
  { id: "lc-3", subject: "lectura-critica", topic: "Comprensi\u00f3n literal", difficulty: "facil", text: "\"Gabriel Garc\u00eda M\u00e1rquez naci\u00f3 en Aracataca, Magdalena, el 6 de marzo de 1927. Es considerado uno de los m\u00e1s grandes escritores del siglo XX y recibi\u00f3 el Premio Nobel de Literatura en 1982 por su obra cumbre, Cien a\u00f1os de soledad.\"\n\n\u00bfEn qu\u00e9 a\u00f1o recibi\u00f3 Garc\u00eda M\u00e1rquez el Premio Nobel?", options: [{ label: "A", text: "1927" }, { label: "B", text: "1967" }, { label: "C", text: "1982" }, { label: "D", text: "2014" }], correctAnswer: "C", explanation: "El texto establece claramente que recibi\u00f3 el Nobel en 1982.", tip: "\ud83d\udccc TRUCO: Cuando la pregunta pide un dato espec\u00edfico (fecha, nombre, lugar), busca ESE dato exacto en el texto. No confundas con otros n\u00fameros que aparezcan." },
  { id: "lc-4", subject: "lectura-critica", topic: "Comprensi\u00f3n literal", difficulty: "facil", text: "\"El r\u00edo Amazonas es el m\u00e1s caudaloso del mundo y atraviesa varios pa\u00edses de Sudam\u00e9rica, incluyendo Brasil, Per\u00fa y Colombia. Su cuenca hidrogr\u00e1fica abarca aproximadamente 7 millones de kil\u00f3metros cuadrados.\"\n\n\u00bfQu\u00e9 caracter\u00edstica principal se menciona del r\u00edo Amazonas?", options: [{ label: "A", text: "Es el r\u00edo m\u00e1s largo del mundo" }, { label: "B", text: "Es el m\u00e1s caudaloso del mundo" }, { label: "C", text: "Es el m\u00e1s profundo del mundo" }, { label: "D", text: "Es el m\u00e1s ancho del mundo" }], correctAnswer: "B", explanation: "El texto dice 'el m\u00e1s caudaloso del mundo'. Caudaloso se refiere al volumen de agua que transporta.", tip: "\ud83c\udfaf TRUCO: Lee cada opci\u00f3n y preg\u00fantate '\u00bfesto lo dice el texto o me lo estoy inventando?'. Solo una opci\u00f3n coincide exactamente." },
  { id: "lc-5", subject: "lectura-critica", topic: "Comprensi\u00f3n literal", difficulty: "facil", text: "\"La Constituci\u00f3n de Colombia de 1991 establece que Colombia es un Estado social de derecho, organizado en forma de rep\u00fablica unitaria, descentralizada, con autonom\u00eda de sus entidades territoriales, democr\u00e1tica, participativa y pluralista.\"\n\n\u00bfC\u00f3mo se define a Colombia seg\u00fan la Constituci\u00f3n?", options: [{ label: "A", text: "Una monarqu\u00eda constitucional" }, { label: "B", text: "Un Estado social de derecho organizado como rep\u00fablica unitaria" }, { label: "C", text: "Una federaci\u00f3n de estados independientes" }, { label: "D", text: "Un estado centralizado sin autonom\u00eda territorial" }], correctAnswer: "B", explanation: "El texto lo dice directamente: 'Estado social de derecho, organizado en forma de rep\u00fablica unitaria'.", tip: "\ud83d\udccc TRUCO: Las preguntas sobre la Constituci\u00f3n suelen ser literales. Memoriza las definiciones clave del art\u00edculo 1." },
  { id: "lc-6", subject: "lectura-critica", topic: "Comprensi\u00f3n literal", difficulty: "facil", text: "\"El sistema digestivo humano comienza en la boca, donde los alimentos son triturados por los dientes y mezclados con la saliva. Luego pasan por el es\u00f3fago hasta el est\u00f3mago, donde se mezclan con jugos g\u00e1stricos para continuar su descomposici\u00f3n.\"\n\n\u00bfD\u00f3nde comienza el proceso digestivo seg\u00fan el texto?", options: [{ label: "A", text: "En el est\u00f3mago" }, { label: "B", text: "En el es\u00f3fago" }, { label: "C", text: "En la boca" }, { label: "D", text: "En el intestino" }], correctAnswer: "C", explanation: "El texto dice claramente: 'comienza en la boca'.", tip: "\ud83d\udccc TRUCO: Las preguntas que empiezan con '\u00bfD\u00f3nde...?' o '\u00bfCu\u00e1ndo...?' buscan datos puntuales. Local\u00edzalos en el texto." },
  { id: "lc-7", subject: "lectura-critica", topic: "Comprensi\u00f3n literal", difficulty: "facil", text: "\"En Colombia, la educaci\u00f3n b\u00e1sica comprende cinco a\u00f1os de educaci\u00f3n primaria y cuatro a\u00f1os de educaci\u00f3n secundaria. La educaci\u00f3n media abarca los grados d\u00e9cimo y und\u00e9cimo, y es obligatoria hasta los 15 a\u00f1os de edad.\"\n\n\u00bfCu\u00e1ntos a\u00f1os dura la educaci\u00f3n primaria en Colombia?", options: [{ label: "A", text: "Cuatro a\u00f1os" }, { label: "B", text: "Cinco a\u00f1os" }, { label: "C", text: "Seis a\u00f1os" }, { label: "D", text: "Tres a\u00f1os" }], correctAnswer: "B", explanation: "El texto indica: 'cinco a\u00f1os de educaci\u00f3n primaria'.", tip: "\ud83d\udccc TRUCO: Subraya mentalmente TODOS los n\u00fameros del texto antes de leer las opciones." },
  { id: "lc-8", subject: "lectura-critica", topic: "Comprensi\u00f3n literal", difficulty: "facil", text: "\"El volc\u00e1n Nevado del Ruiz, ubicado en el departamento de Caldas, hizo erupci\u00f3n el 13 de noviembre de 1985, causando una avalancha de lodo que sepult\u00f3 la ciudad de Armero, Tolima, dejando m\u00e1s de 23.000 v\u00edctimas.\"\n\n\u00bfEn qu\u00e9 departamento est\u00e1 ubicado el Nevado del Ruiz?", options: [{ label: "A", text: "Tolima" }, { label: "B", text: "Risaralda" }, { label: "C", text: "Caldas" }, { label: "D", text: "Nari\u00f1o" }], correctAnswer: "C", explanation: "El texto dice 'ubicado en el departamento de Caldas'. Armero est\u00e1 en Tolima, pero el volc\u00e1n est\u00e1 en Caldas.", tip: "\ud83c\udfaf TRUCO: Cuidado con las trampas. La pregunta es sobre D\u00d3NDE est\u00e1 el volc\u00e1n, no d\u00f3nde ocurri\u00f3 la tragedia. Lee con precisi\u00f3n." },
  { id: "lc-9", subject: "lectura-critica", topic: "Comprensi\u00f3n literal", difficulty: "medio", text: "\"La salsa es un g\u00e9nero musical que naci\u00f3 en Nueva York en la d\u00e9cada de 1960, fusionando ritmos cubanos, puertorrique\u00f1os y otros sonidos caribe\u00f1os. Sin embargo, fue en Cali, Colombia, donde se convirti\u00f3 en un fen\u00f3meno cultural masivo.\"\n\n\u00bfD\u00f3nde naci\u00f3 la salsa seg\u00fan el texto?", options: [{ label: "A", text: "En Cuba" }, { label: "B", text: "En Cali, Colombia" }, { label: "C", text: "En Nueva York" }, { label: "D", text: "En Puerto Rico" }], correctAnswer: "C", explanation: "El texto dice 'naci\u00f3 en Nueva York'. Cali es donde se convirti\u00f3 en fen\u00f3meno cultural, pero no donde naci\u00f3.", tip: "\ud83c\udfaf TRUCO: Cuidado con los distractores. Lee EXACTAMENTE lo que pregunta. No es lo mismo 'd\u00f3nde naci\u00f3' que 'd\u00f3nde se hizo popular'." },
  { id: "lc-10", subject: "lectura-critica", topic: "Comprensi\u00f3n literal", difficulty: "facil", text: "\"Los manglares son ecosistemas costeros donde los \u00e1rboles crecen en aguas saladas o salobres. En Colombia, se encuentran principalmente en las costas del Pac\u00edfico y del Caribe. Estos ecosistemas son fundamentales como criaderos de peces y como barrera natural contra tsunamis.\"\n\n\u00bfQu\u00e9 funci\u00f3n cumplen los manglares como barrera?", options: [{ label: "A", text: "Protegen contra la deforestaci\u00f3n" }, { label: "B", text: "Protegen contra tsunamis" }, { label: "C", text: "Protegen contra la contaminaci\u00f3n del aire" }, { label: "D", text: "Protegen contra las sequ\u00edas" }], correctAnswer: "B", explanation: "El texto menciona expl\u00edcitamente 'barrera natural contra tsunamis'.", tip: "\ud83d\udccc TRUCO: Busca la frase exacta del texto. Si la pregunta dice 'barrera', busca esa palabra en el texto y lee qu\u00e9 dice alrededor." },
  { id: "lc-11", subject: "lectura-critica", topic: "Comprensi\u00f3n literal", difficulty: "facil", text: "\"El vallenato es un g\u00e9nero musical originario de la regi\u00f3n Caribe colombiana. Sus instrumentos principales son la caja vallenata, la guacharaca y el acorde\u00f3n. En 2015, la UNESCO lo declar\u00f3 Patrimonio Inmaterial de la Humanidad.\"\n\n\u00bfCu\u00e1les son los tres instrumentos principales del vallenato?", options: [{ label: "A", text: "Guitarra, tambor y flauta" }, { label: "B", text: "Caja vallenata, guacharaca y acorde\u00f3n" }, { label: "C", text: "Maracas, gaita y tambora" }, { label: "D", text: "Piano, guitarra y bajo" }], correctAnswer: "B", explanation: "El texto enumera directamente: 'la caja vallenata, la guacharaca y el acorde\u00f3n'.", tip: "\ud83d\udccc TRUCO: Cuando la pregunta pide una lista, verifica que TODOS los elementos coincidan con el texto, no solo uno o dos." },
  { id: "lc-12", subject: "lectura-critica", topic: "Comprensi\u00f3n literal", difficulty: "facil", text: "\"El departamento del Amazonas colombiano tiene una extensi\u00f3n de aproximadamente 109.665 kil\u00f3metros cuadrados, lo que lo convierte en el departamento m\u00e1s grande de Colombia. Su capital es Leticia, una ciudad fronteriza con Brasil y Per\u00fa.\"\n\nSeg\u00fan el texto, \u00bfcon qu\u00e9 pa\u00edses hace frontera Leticia?", options: [{ label: "A", text: "Venezuela y Ecuador" }, { label: "B", text: "Brasil y Per\u00fa" }, { label: "C", text: "Per\u00fa y Ecuador" }, { label: "D", text: "Brasil y Venezuela" }], correctAnswer: "B", explanation: "El texto dice claramente: 'fronteriza con Brasil y Per\u00fa'.", tip: "\ud83d\udccc TRUCO: En preguntas de datos geogr\u00e1ficos, busca la informaci\u00f3n exacta. No conf\u00edes en lo que crees saber, conf\u00eda en lo que dice el texto." },
  { id: "lc-13", subject: "lectura-critica", topic: "Comprensi\u00f3n inferencial", difficulty: "medio", text: "\"Marta lleg\u00f3 a casa empapada, dej\u00f3 el paraguas roto en la entrada y suspir\u00f3 mientras miraba por la ventana el cielo gris que no parec\u00eda querer aclararse.\"\n\n\u00bfQu\u00e9 se puede inferir de esta situaci\u00f3n?", options: [{ label: "A", text: "Marta olvid\u00f3 comprar un paraguas nuevo" }, { label: "B", text: "Fue sorprendida por una fuerte lluvia que da\u00f1\u00f3 su paraguas" }, { label: "C", text: "Marta disfruta caminar bajo la lluvia" }, { label: "D", text: "El cielo gris indica que es de noche" }], correctAnswer: "B", explanation: "Inferimos que llovi\u00f3 fuerte: est\u00e1 empapada, el paraguas roto, cielo gris.", tip: "\ud83d\udd0d TRUCO ICFES: Inferir NO es inventar. Junta las PISTAS del texto como un detective." },
  { id: "lc-14", subject: "lectura-critica", topic: "Comprensi\u00f3n inferencial", difficulty: "medio", text: "\"El abuelo se sent\u00f3 lentamente en su mecedora, acariciando la fotograf\u00eda amarillenta mientras una l\u00e1grima silenciosa recorr\u00eda su mejilla arrugada.\"\n\n\u00bfQu\u00e9 se puede inferir sobre el abuelo?", options: [{ label: "A", text: "Est\u00e1 enojado con alguien de la foto" }, { label: "B", text: "Est\u00e1 recordando con nostalgia a alguien que ya no est\u00e1" }, { label: "C", text: "Est\u00e1 feliz porque encontr\u00f3 la fotograf\u00eda" }, { label: "D", text: "La foto es nueva y le causa sorpresa" }], correctAnswer: "B", explanation: "La fotograf\u00eda amarillenta (vieja), la l\u00e1grima y la actitud melanc\u00f3lica sugieren nostalgia por alguien ausente.", tip: "\ud83d\udd0d TRUCO: Los sentimientos se infieren por las ACCIONES. L\u00e1grima + foto vieja + lentitud = melancol\u00eda/nostalgia." },
  { id: "lc-15", subject: "lectura-critica", topic: "Comprensi\u00f3n inferencial", difficulty: "medio", text: "\"Cuando Pedro vio el resultado del examen, guard\u00f3 la hoja r\u00e1pidamente en su mochila, evit\u00f3 la mirada de sus compa\u00f1eros y sali\u00f3 del sal\u00f3n sin despedirse.\"\n\n\u00bfQu\u00e9 se puede inferir sobre el resultado de Pedro?", options: [{ label: "A", text: "Obtuvo la mejor nota del curso" }, { label: "B", text: "El resultado fue malo y siente verg\u00fcenza" }, { label: "C", text: "Est\u00e1 apurado por llegar a otro compromiso" }, { label: "D", text: "Quiere mostrar el resultado a sus padres primero" }], correctAnswer: "B", explanation: "Esconder la hoja + evitar miradas + salir sin despedirse = verg\u00fcenza por un mal resultado.", tip: "\ud83d\udd0d TRUCO: Las personas felices COMPARTEN sus logros. Si alguien esconde algo, probablemente no es bueno." },
  { id: "lc-16", subject: "lectura-critica", topic: "Comprensi\u00f3n inferencial", difficulty: "medio", text: "\"La empresa anunci\u00f3 que reducir\u00e1 su plantilla en un 30% durante el pr\u00f3ximo trimestre. Los empleados de la oficina central se miraron en silencio cuando el gerente termin\u00f3 de hablar.\"\n\n\u00bfQu\u00e9 se puede inferir del silencio de los empleados?", options: [{ label: "A", text: "Est\u00e1n contentos con la noticia" }, { label: "B", text: "No entendieron el anuncio" }, { label: "C", text: "Sienten miedo e incertidumbre por sus empleos" }, { label: "D", text: "Ya sab\u00edan la noticia de antemano" }], correctAnswer: "C", explanation: "Reducci\u00f3n de 30% + silencio = miedo e incertidumbre. El silencio expresa preocupaci\u00f3n.", tip: "\ud83d\udd0d TRUCO: El silencio como reacci\u00f3n a una mala noticia = miedo/preocupaci\u00f3n. Si fuera esperada, habr\u00eda otra reacci\u00f3n." },
  { id: "lc-17", subject: "lectura-critica", topic: "Comprensi\u00f3n inferencial", difficulty: "medio", text: "\"Ana revis\u00f3 por tercera vez la lista de ingredientes, mir\u00f3 el reloj que marcaba las 5 de la tarde, y aceler\u00f3 el paso por los pasillos del supermercado. Los invitados llegar\u00edan a las 7.\"\n\n\u00bfQu\u00e9 se puede inferir?", options: [{ label: "A", text: "Ana est\u00e1 haciendo las compras semanales sin prisa" }, { label: "B", text: "Est\u00e1 preparando una cena o reuni\u00f3n y tiene poco tiempo" }, { label: "C", text: "El supermercado est\u00e1 a punto de cerrar" }, { label: "D", text: "Ana olvid\u00f3 comprar un regalo" }], correctAnswer: "B", explanation: "Lista de ingredientes + invitados a las 7 + prisa = est\u00e1 preparando una comida para invitados.", tip: "\ud83d\udd0d TRUCO: Conecta TODAS las pistas. Ingredientes + invitados + hora = est\u00e1 cocinando para una reuni\u00f3n." },
  { id: "lc-18", subject: "lectura-critica", topic: "Comprensi\u00f3n inferencial", difficulty: "facil", text: "\"Los \u00e1rboles del parque ya no ten\u00edan hojas, las bancas estaban h\u00famedas y cubiertas de escarcha, y los pocos caminantes llevaban bufandas y guantes gruesos.\"\n\n\u00bfQu\u00e9 estaci\u00f3n del a\u00f1o se describe?", options: [{ label: "A", text: "Verano" }, { label: "B", text: "Primavera" }, { label: "C", text: "Invierno" }, { label: "D", text: "Oto\u00f1o" }], correctAnswer: "C", explanation: "\u00c1rboles sin hojas + escarcha + bufandas y guantes = invierno.", tip: "\ud83d\udd0d TRUCO: Identifica los indicadores clim\u00e1ticos: temperatura, vestimenta, estado de la naturaleza." },
  { id: "lc-19", subject: "lectura-critica", topic: "Comprensi\u00f3n inferencial", difficulty: "medio", text: "\"La doctora revis\u00f3 los resultados con expresi\u00f3n seria, llam\u00f3 a su colega para una segunda opini\u00f3n y pidi\u00f3 que programaran m\u00e1s ex\u00e1menes lo antes posible.\"\n\n\u00bfQu\u00e9 se puede inferir?", options: [{ label: "A", text: "Los resultados son normales y la doctora es muy cuidadosa" }, { label: "B", text: "Los resultados muestran algo preocupante que requiere m\u00e1s investigaci\u00f3n" }, { label: "C", text: "La doctora no sabe leer los resultados" }, { label: "D", text: "El paciente pidi\u00f3 una segunda opini\u00f3n" }], correctAnswer: "B", explanation: "Expresi\u00f3n seria + segunda opini\u00f3n + m\u00e1s ex\u00e1menes urgentes = algo preocupante.", tip: "\ud83d\udd0d TRUCO: Si un profesional pide m\u00e1s pruebas con urgencia, los primeros resultados no son buenos." },
  { id: "lc-20", subject: "lectura-critica", topic: "Comprensi\u00f3n inferencial", difficulty: "medio", text: "\"Juan cerr\u00f3 su laptop frustrado, arrug\u00f3 tres hojas que ten\u00eda en su escritorio y mir\u00f3 el calendario donde la fecha de entrega estaba marcada con rojo: ma\u00f1ana.\"\n\n\u00bfQu\u00e9 se puede inferir?", options: [{ label: "A", text: "Juan termin\u00f3 su trabajo exitosamente" }, { label: "B", text: "Est\u00e1 teniendo dificultades con un trabajo que debe entregar ma\u00f1ana" }, { label: "C", text: "Decidi\u00f3 no entregar el trabajo" }, { label: "D", text: "Le gusta planificar con anticipaci\u00f3n" }], correctAnswer: "B", explanation: "Frustraci\u00f3n + hojas arrugadas (borradores fallidos) + fecha de entrega ma\u00f1ana = dificultades con el trabajo.", tip: "\ud83d\udd0d TRUCO: La frustraci\u00f3n combinada con una fecha l\u00edmite cercana indica problemas con la tarea." },
  { id: "lc-21", subject: "lectura-critica", topic: "Comprensi\u00f3n inferencial", difficulty: "medio", text: "\"El restaurante que antes ten\u00eda fila de espera todos los viernes ahora tiene m\u00e1s meseros que clientes. El due\u00f1o decidi\u00f3 cambiar de chef el mes pasado.\"\n\n\u00bfQu\u00e9 se puede inferir?", options: [{ label: "A", text: "El restaurante mejor\u00f3 su servicio" }, { label: "B", text: "El cambio de chef afect\u00f3 negativamente al negocio" }, { label: "C", text: "Los viernes ya no son populares para cenar" }, { label: "D", text: "Contrataron m\u00e1s meseros para mejorar la atenci\u00f3n" }], correctAnswer: "B", explanation: "Antes lleno \u2192 ahora vac\u00edo + cambio reciente de chef = el nuevo chef no atrajo a los clientes.", tip: "\ud83d\udd0d TRUCO: Cuando hay un cambio de situaci\u00f3n (antes vs. ahora), busca qu\u00e9 evento ocurri\u00f3 entre ambos momentos." },
  { id: "lc-22", subject: "lectura-critica", topic: "Comprensi\u00f3n inferencial", difficulty: "facil", text: "\"Mar\u00eda sali\u00f3 de la entrevista de trabajo con una sonrisa amplia, llam\u00f3 inmediatamente a su mam\u00e1 y le dijo: 'Empiezo el lunes'.\"\n\n\u00bfQu\u00e9 se puede inferir?", options: [{ label: "A", text: "La entrevista fue cancelada" }, { label: "B", text: "Mar\u00eda consigui\u00f3 el trabajo" }, { label: "C", text: "Empezar\u00e1 un curso el lunes" }, { label: "D", text: "No le fue bien pero es optimista" }], correctAnswer: "B", explanation: "Sonrisa + 'Empiezo el lunes' = le dieron el trabajo.", tip: "\ud83d\udd0d TRUCO: Las emociones positivas + acciones concretas (empezar el lunes) confirman un resultado positivo." },
  { id: "lc-23", subject: "lectura-critica", topic: "Comprensi\u00f3n inferencial", difficulty: "medio", text: "\"El pol\u00edtico prometi\u00f3 construir un hospital en cada municipio durante su campa\u00f1a. Tres a\u00f1os despu\u00e9s de asumir el cargo, el presupuesto de salud hab\u00eda disminuido un 15%.\"\n\n\u00bfQu\u00e9 se puede inferir?", options: [{ label: "A", text: "El pol\u00edtico cumpli\u00f3 sus promesas de campa\u00f1a" }, { label: "B", text: "Es probable que no haya cumplido su promesa sobre los hospitales" }, { label: "C", text: "Los hospitales se construyeron con otros fondos" }, { label: "D", text: "La reducci\u00f3n del presupuesto mejor\u00f3 la salud" }], correctAnswer: "B", explanation: "Prometi\u00f3 hospitales pero redujo el presupuesto de salud \u2192 probablemente no cumpli\u00f3.", tip: "\ud83d\udd0d TRUCO: Compara PROMESA vs. ACCI\u00d3N. Si la acci\u00f3n contradice la promesa, la conclusi\u00f3n es incumplimiento." },
  { id: "lc-24", subject: "lectura-critica", topic: "Comprensi\u00f3n inferencial", difficulty: "dificil", text: "\"En el colegio de Laura, este a\u00f1o hay 3 salones de primero, pero solo 1 sal\u00f3n de und\u00e9cimo. Hace cinco a\u00f1os era al rev\u00e9s: 1 sal\u00f3n de primero y 3 de und\u00e9cimo.\"\n\n\u00bfQu\u00e9 se puede inferir sobre el colegio?", options: [{ label: "A", text: "El colegio est\u00e1 perdiendo prestigio" }, { label: "B", text: "Ha habido un aumento en la demanda de matr\u00edcula en primaria" }, { label: "C", text: "Los estudiantes de und\u00e9cimo se graduaron temprano" }, { label: "D", text: "El colegio cerr\u00f3 algunos salones por falta de presupuesto" }], correctAnswer: "B", explanation: "M\u00e1s salones de primero ahora = m\u00e1s ni\u00f1os entrando. Antes era al rev\u00e9s, lo que muestra un cambio en la demanda.", tip: "\ud83d\udd0d TRUCO: Los n\u00fameros cuentan historias. Compara el antes y el despu\u00e9s para identificar tendencias." },
  { id: "lc-25", subject: "lectura-critica", topic: "Comprensi\u00f3n cr\u00edtica", difficulty: "medio", text: "\"Los videojuegos son una p\u00e9rdida de tiempo. Los j\u00f3venes deber\u00edan dedicar sus horas libres a leer libros o practicar deportes, actividades que realmente contribuyen a su desarrollo personal y social.\"\n\n\u00bfQu\u00e9 tipo de texto es este?", options: [{ label: "A", text: "Un texto informativo que presenta datos objetivos" }, { label: "B", text: "Un texto argumentativo que expresa una opini\u00f3n personal" }, { label: "C", text: "Un texto narrativo que cuenta una historia" }, { label: "D", text: "Un texto descriptivo que detalla los videojuegos" }], correctAnswer: "B", explanation: "Es argumentativo: expresa una posici\u00f3n ('p\u00e9rdida de tiempo') e intenta convencer.", tip: "\ud83d\udcdd TRUCO: \u00bfMe cuenta algo? (narrativo) \u00bfMe da datos? (informativo) \u00bfMe intenta convencer? (argumentativo)" },
  { id: "lc-26", subject: "lectura-critica", topic: "Comprensi\u00f3n cr\u00edtica", difficulty: "dificil", text: "\"Un estudio revel\u00f3 que el 80% de los estudiantes que desayunan tienen mejor rendimiento acad\u00e9mico. Por lo tanto, desayunar es la causa directa del \u00e9xito escolar.\"\n\n\u00bfQu\u00e9 error l\u00f3gico contiene esta conclusi\u00f3n?", options: [{ label: "A", text: "Generalizaci\u00f3n correcta basada en datos" }, { label: "B", text: "Confunde correlaci\u00f3n con causalidad" }, { label: "C", text: "El porcentaje es muy bajo para concluir" }, { label: "D", text: "No hay error, la conclusi\u00f3n es v\u00e1lida" }], correctAnswer: "B", explanation: "Que dos cosas ocurran juntas (correlaci\u00f3n) no significa que una cause la otra (causalidad). Podr\u00eda haber otros factores.", tip: "\ud83e\udde0 TRUCO ICFES: Cuidado con el 'por lo tanto'. Que A y B ocurran juntos NO significa que A cause B. Siempre preg\u00fantate: \u00bfhabr\u00e1 otro factor?" },
  { id: "lc-27", subject: "lectura-critica", topic: "Comprensi\u00f3n cr\u00edtica", difficulty: "dificil", text: "\"Todos los pol\u00edticos son corruptos. Mi vecino, que es concejal, seguramente tambi\u00e9n roba.\"\n\n\u00bfQu\u00e9 falacia se evidencia en este razonamiento?", options: [{ label: "A", text: "Argumento de autoridad" }, { label: "B", text: "Generalizaci\u00f3n apresurada" }, { label: "C", text: "Argumento ad hominem" }, { label: "D", text: "Falsa analog\u00eda" }], correctAnswer: "B", explanation: "Toma una caracter\u00edstica de algunos y la aplica a TODOS sin evidencia suficiente.", tip: "\ud83e\udde0 TRUCO: Palabras como 'todos', 'siempre', 'nunca' son se\u00f1ales de generalizaci\u00f3n. En la vida real, casi nada es absoluto." },
  { id: "lc-28", subject: "lectura-critica", topic: "Comprensi\u00f3n cr\u00edtica", difficulty: "dificil", text: "\"No deber\u00edamos escuchar las opiniones de Carlos sobre nutrici\u00f3n porque \u00e9l est\u00e1 gordo.\"\n\n\u00bfQu\u00e9 tipo de falacia se usa aqu\u00ed?", options: [{ label: "A", text: "Falacia ad hominem: ataca a la persona, no al argumento" }, { label: "B", text: "Argumento de autoridad" }, { label: "C", text: "Falsa dicotom\u00eda" }, { label: "D", text: "Petici\u00f3n de principio" }], correctAnswer: "A", explanation: "Se desacredita la opini\u00f3n atacando a la persona (su apariencia) en vez de refutar sus argumentos.", tip: "\ud83e\udde0 TRUCO: Si atacan a quien habla en vez de lo que dice, es ad hominem. El aspecto de alguien no invalida sus conocimientos." },
  { id: "lc-29", subject: "lectura-critica", topic: "Comprensi\u00f3n cr\u00edtica", difficulty: "dificil", text: "\"O est\u00e1s conmigo o est\u00e1s contra m\u00ed.\"\n\n\u00bfQu\u00e9 falacia l\u00f3gica representa esta afirmaci\u00f3n?", options: [{ label: "A", text: "Generalizaci\u00f3n apresurada" }, { label: "B", text: "Argumento circular" }, { label: "C", text: "Falsa dicotom\u00eda: presenta solo dos opciones cuando hay m\u00e1s" }, { label: "D", text: "Argumento de autoridad" }], correctAnswer: "C", explanation: "Presenta solo dos opciones extremas cuando en realidad existen posiciones intermedias.", tip: "\ud83e\udde0 TRUCO: Si te dan solo 2 opciones extremas ('o esto o lo otro'), probablemente es falsa dicotom\u00eda. La vida tiene matices." },
  { id: "lc-30", subject: "lectura-critica", topic: "Comprensi\u00f3n cr\u00edtica", difficulty: "dificil", text: "\"El peri\u00f3dico local public\u00f3: 'Seg\u00fan fuentes cercanas al alcalde, el proyecto del parque beneficiar\u00e1 a miles de familias'. \u00bfCu\u00e1l es la debilidad principal de esta informaci\u00f3n?\"\n\nSeleccione la opci\u00f3n correcta:", options: [{ label: "A", text: "El proyecto no es importante" }, { label: "B", text: "La fuente es vaga e interesada: no hay datos verificables" }, { label: "C", text: "Los peri\u00f3dicos siempre mienten" }, { label: "D", text: "Miles de familias es un n\u00famero exacto" }], correctAnswer: "B", explanation: "'Fuentes cercanas al alcalde' es vaga y posiblemente sesgada. No hay datos concretos ni fuentes independientes.", tip: "\ud83e\udde0 TRUCO ICFES: Eval\u00faa la FUENTE. \u00bfQui\u00e9n lo dice? \u00bfTiene inter\u00e9s en que creas algo? \u00bfHay datos concretos o solo opiniones?" },
  { id: "lc-31", subject: "lectura-critica", topic: "Comprensi\u00f3n cr\u00edtica", difficulty: "dificil", text: "\"Mi abuela fum\u00f3 toda su vida y vivi\u00f3 hasta los 95 a\u00f1os. Eso demuestra que fumar no es peligroso.\"\n\n\u00bfPor qu\u00e9 este argumento es inv\u00e1lido?", options: [{ label: "A", text: "Porque la abuela era una persona especial" }, { label: "B", text: "Porque un caso individual no puede refutar evidencia estad\u00edstica de millones de casos" }, { label: "C", text: "Porque 95 a\u00f1os no es mucho" }, { label: "D", text: "Porque no se sabe qu\u00e9 marca fumaba" }], correctAnswer: "B", explanation: "Un caso aislado no invalida la evidencia cient\u00edfica basada en millones de estudios.", tip: "\ud83e\udde0 TRUCO: Un ejemplo personal NUNCA refuta una tendencia general. La ciencia se basa en estad\u00edsticas, no en an\u00e9cdotas." },
  { id: "lc-32", subject: "lectura-critica", topic: "Comprensi\u00f3n cr\u00edtica", difficulty: "medio", text: "\"Lee el siguiente editorial:\n\n'Es evidente que la educaci\u00f3n en Colombia ha mejorado significativamente en los \u00faltimos a\u00f1os. Los resultados as\u00ed lo demuestran.'\n\n\u00bfQu\u00e9 debilidad tiene este argumento?\"", options: [{ label: "A", text: "Es completamente falso" }, { label: "B", text: "Afirma que algo es evidente sin presentar datos o resultados espec\u00edficos" }, { label: "C", text: "La educaci\u00f3n no puede mejorar" }, { label: "D", text: "No menciona otros pa\u00edses" }], correctAnswer: "B", explanation: "Dice 'los resultados lo demuestran' pero no muestra cu\u00e1les son esos resultados. Es una afirmaci\u00f3n sin evidencia.", tip: "\ud83e\udde0 TRUCO: Desconf\u00eda de frases como 'es evidente', 'todos saben', 'los datos demuestran' si no te muestran los datos." },
  { id: "lc-33", subject: "lectura-critica", topic: "Comprensi\u00f3n cr\u00edtica", difficulty: "medio", text: "\"Un comercial de televisi\u00f3n muestra a un futbolista famoso bebiendo una marca de leche y diciendo: 'Yo tomo esta leche porque es la m\u00e1s nutritiva'.\"\n\n\u00bfQu\u00e9 tipo de recurso persuasivo se usa?", options: [{ label: "A", text: "Evidencia cient\u00edfica" }, { label: "B", text: "Argumento de autoridad: usar una figura famosa para dar credibilidad" }, { label: "C", text: "Argumento l\u00f3gico basado en datos" }, { label: "D", text: "Testimonio de un experto en nutrici\u00f3n" }], correctAnswer: "B", explanation: "Un futbolista no es experto en nutrici\u00f3n. Se usa su fama para persuadir, no su conocimiento.", tip: "\ud83e\udde0 TRUCO: \u00bfQui\u00e9n lo dice? Si es famoso pero NO experto en el tema, es argumento de autoridad falso. Un futbolista sabe de f\u00fatbol, no de nutrici\u00f3n." },
  { id: "lc-34", subject: "lectura-critica", topic: "Comprensi\u00f3n cr\u00edtica", difficulty: "dificil", text: "\"Un texto dice: 'La energ\u00eda nuclear es la soluci\u00f3n perfecta para la crisis energ\u00e9tica mundial. No produce gases de efecto invernadero y es muy eficiente.'\n\n\u00bfQu\u00e9 omite este argumento?\"", options: [{ label: "A", text: "No omite nada, es un argumento completo" }, { label: "B", text: "Omite los riesgos y desventajas de la energ\u00eda nuclear" }, { label: "C", text: "Omite que otras energ\u00edas son m\u00e1s baratas" }, { label: "D", text: "Omite datos sobre producci\u00f3n de electricidad" }], correctAnswer: "B", explanation: "El argumento presenta solo las ventajas sin mencionar los riesgos (residuos radiactivos, accidentes nucleares, etc.).", tip: "\ud83e\udde0 TRUCO: Un argumento que solo muestra UN lado es sospechoso. Siempre preg\u00fantate: \u00bfQu\u00e9 NO me est\u00e1n diciendo?" },
  { id: "lc-35", subject: "lectura-critica", topic: "Comprensi\u00f3n cr\u00edtica", difficulty: "dificil", text: "\"'Colombia deber\u00eda invertir m\u00e1s en deportes. Despu\u00e9s de todo, Nairo Quintana gan\u00f3 etapas en el Tour de Francia, y la selecci\u00f3n de f\u00fatbol clasific\u00f3 al mundial.'\n\n\u00bfQu\u00e9 relaci\u00f3n hay entre la premisa y la conclusi\u00f3n?\"", options: [{ label: "A", text: "La conclusi\u00f3n se deduce l\u00f3gicamente de las premisas" }, { label: "B", text: "Los \u00e9xitos deportivos individuales no justifican necesariamente m\u00e1s inversi\u00f3n gubernamental" }, { label: "C", text: "No hay ninguna relaci\u00f3n" }, { label: "D", text: "Las premisas son falsas" }], correctAnswer: "B", explanation: "Que algunos deportistas tengan \u00e9xito no demuestra autom\u00e1ticamente que se necesite m\u00e1s inversi\u00f3n estatal.", tip: "\ud83e\udde0 TRUCO: Eval\u00faa si las PREMISAS realmente apoyan la CONCLUSI\u00d3N. A veces los ejemplos son v\u00e1lidos pero no prueban lo que se quiere concluir." },
  { id: "lc-36", subject: "lectura-critica", topic: "Comprensi\u00f3n cr\u00edtica", difficulty: "dificil", text: "\"Un blog dice: 'Los colombianos son las personas m\u00e1s felices del mundo, seg\u00fan una encuesta a 200 turistas en Cartagena.'\n\n\u00bfCu\u00e1l es el problema metodol\u00f3gico?\"", options: [{ label: "A", text: "200 personas es suficiente muestra" }, { label: "B", text: "La muestra es sesgada: solo turistas en una ciudad tur\u00edstica no representan la opini\u00f3n general" }, { label: "C", text: "Cartagena es representativa de todo Colombia" }, { label: "D", text: "Los turistas son los mejores jueces" }], correctAnswer: "B", explanation: "Encuestar turistas (que est\u00e1n de vacaciones) en una ciudad tur\u00edstica no es representativo de toda Colombia.", tip: "\ud83e\udde0 TRUCO: Eval\u00faa la MUESTRA. \u00bfA qui\u00e9n preguntaron? \u00bfD\u00f3nde? \u00bfEs representativo? Una encuesta en una playa siempre dar\u00e1 resultados positivos." },
  { id: "lc-37", subject: "lectura-critica", topic: "An\u00e1lisis de argumentos", difficulty: "medio", text: "\"Seg\u00fan la OMS, el consumo excesivo de az\u00facar est\u00e1 relacionado con la diabetes tipo 2. Un reporte del Ministerio de Salud colombiano indica que el consumo de bebidas azucaradas ha aumentado un 40% en la \u00faltima d\u00e9cada.\"\n\n\u00bfCu\u00e1l ser\u00eda la conclusi\u00f3n m\u00e1s l\u00f3gica?", options: [{ label: "A", text: "Se debe prohibir el az\u00facar completamente" }, { label: "B", text: "Es probable que los casos de diabetes aumenten si no se controla el consumo de bebidas azucaradas" }, { label: "C", text: "Todas las bebidas azucaradas causan diabetes" }, { label: "D", text: "La OMS exagera los riesgos del az\u00facar" }], correctAnswer: "B", explanation: "Si el az\u00facar est\u00e1 relacionado con diabetes Y el consumo ha aumentado, l\u00f3gicamente los casos podr\u00edan aumentar.", tip: "\ud83e\udde0 TRUCO: La conclusi\u00f3n l\u00f3gica CONECTA las premisas. Busca la opci\u00f3n que use AMBOS datos sin exagerar." },
  { id: "lc-38", subject: "lectura-critica", topic: "An\u00e1lisis de argumentos", difficulty: "medio", text: "\"Premisa 1: Todos los mam\u00edferos respiran con pulmones.\nPremisa 2: Las ballenas son mam\u00edferos.\n\n\u00bfCu\u00e1l es la conclusi\u00f3n l\u00f3gica?\"", options: [{ label: "A", text: "Las ballenas viven en el agua" }, { label: "B", text: "Las ballenas respiran con pulmones" }, { label: "C", text: "Todos los animales acu\u00e1ticos son mam\u00edferos" }, { label: "D", text: "Los pulmones solo sirven para respirar en tierra" }], correctAnswer: "B", explanation: "Silogismo cl\u00e1sico: Si todos los mam\u00edferos tienen pulmones Y las ballenas son mam\u00edferos \u2192 las ballenas tienen pulmones.", tip: "\ud83e\udde0 TRUCO ICFES: En silogismos, la conclusi\u00f3n COMBINA las dos premisas. Si A\u2192B y C es A, entonces C\u2192B." },
  { id: "lc-39", subject: "lectura-critica", topic: "An\u00e1lisis de argumentos", difficulty: "medio", text: "\"Un candidato pol\u00edtico dice: 'Mi oponente estuvo involucrado en un esc\u00e1ndalo hace 20 a\u00f1os, as\u00ed que no se le puede confiar el manejo de la econom\u00eda.'\n\n\u00bfPor qu\u00e9 este argumento es d\u00e9bil?\"", options: [{ label: "A", text: "Porque el esc\u00e1ndalo es muy antiguo" }, { label: "B", text: "Porque ataca al oponente personalmente sin discutir sus propuestas econ\u00f3micas" }, { label: "C", text: "Porque todos los pol\u00edticos tienen esc\u00e1ndalos" }, { label: "D", text: "Porque la econom\u00eda no es importante" }], correctAnswer: "B", explanation: "Ataca a la persona (ad hominem) en vez de analizar sus propuestas econ\u00f3micas concretas.", tip: "\ud83e\udde0 TRUCO: El argumento fuerte discute IDEAS y PROPUESTAS. El argumento d\u00e9bil ataca PERSONAS." },
  { id: "lc-40", subject: "lectura-critica", topic: "An\u00e1lisis de argumentos", difficulty: "dificil", text: "\"'No podemos confiar en el estudio sobre el cambio clim\u00e1tico porque fue financiado por una empresa petrolera.'\n\n\u00bfQu\u00e9 tipo de razonamiento es este?\"", options: [{ label: "A", text: "Un argumento v\u00e1lido porque las empresas petroleras siempre mienten" }, { label: "B", text: "Un se\u00f1alamiento leg\u00edtimo sobre posible conflicto de inter\u00e9s, aunque no invalida autom\u00e1ticamente el estudio" }, { label: "C", text: "Un argumento irrelevante" }, { label: "D", text: "Un argumento basado en evidencia cient\u00edfica" }], correctAnswer: "B", explanation: "Es v\u00e1lido cuestionar la fuente de financiaci\u00f3n (conflicto de inter\u00e9s), pero esto por s\u00ed solo no invalida los resultados.", tip: "\ud83e\udde0 TRUCO: El conflicto de inter\u00e9s es una se\u00f1al de alerta, no una prueba de falsedad. Hay que evaluar TAMBI\u00c9N la metodolog\u00eda del estudio." },
  { id: "lc-41", subject: "lectura-critica", topic: "An\u00e1lisis de argumentos", difficulty: "dificil", text: "\"'Deber\u00edamos eliminar las tareas escolares. Un estudio en Finlandia mostr\u00f3 que los estudiantes finlandeses no tienen tareas y obtienen los mejores resultados del mundo.'\n\n\u00bfCu\u00e1l es la debilidad principal?\"", options: [{ label: "A", text: "No se puede comparar directamente dos sistemas educativos muy diferentes" }, { label: "B", text: "Finlandia no existe" }, { label: "C", text: "Las tareas son siempre necesarias" }, { label: "D", text: "El estudio es falso" }], correctAnswer: "A", explanation: "Los sistemas educativos tienen contextos muy diferentes. Lo que funciona en Finlandia no necesariamente funciona en Colombia.", tip: "\ud83e\udde0 TRUCO: Cuidado con comparar contextos muy diferentes. Lo que funciona en un pa\u00eds con otra cultura, econom\u00eda y sistema educativo no se puede copiar directamente." },
  { id: "lc-42", subject: "lectura-critica", topic: "An\u00e1lisis de argumentos", difficulty: "dificil", text: "\"Texto: 'Seg\u00fan el art\u00edculo 67 de la Constituci\u00f3n colombiana, la educaci\u00f3n es un derecho fundamental y un servicio p\u00fablico. El Estado debe garantizar su acceso y calidad.'\n\nUn padre dice: 'El colegio de mi hijo debe ser gratuito porque la educaci\u00f3n es un derecho.'\n\n\u00bfEs correcto su razonamiento?\"", options: [{ label: "A", text: "S\u00ed, toda la educaci\u00f3n debe ser gratuita sin excepci\u00f3n" }, { label: "B", text: "Parcialmente: la educaci\u00f3n b\u00e1sica es gratuita en instituciones p\u00fablicas, pero no toda educaci\u00f3n es gratuita" }, { label: "C", text: "No, la Constituci\u00f3n no habla de educaci\u00f3n gratuita" }, { label: "D", text: "No, los derechos no aplican a los ni\u00f1os" }], correctAnswer: "B", explanation: "La Constituci\u00f3n garantiza el derecho a la educaci\u00f3n, y la educaci\u00f3n b\u00e1sica es gratuita en instituciones p\u00fablicas, pero la educaci\u00f3n privada y superior tienen costos.", tip: "\ud83e\udde0 TRUCO: Los derechos constitucionales tienen alcances espec\u00edficos. Lee con cuidado qu\u00e9 EXACTAMENTE garantiza la norma." },
  { id: "lc-43", subject: "lectura-critica", topic: "Comprensi\u00f3n inferencial", difficulty: "dificil", text: "\"Desde que instalaron c\u00e1maras de seguridad en el barrio, los robos disminuyeron un 60%. Sin embargo, en los barrios vecinos sin c\u00e1maras, los robos aumentaron un 35%.\"\n\n\u00bfQu\u00e9 se puede inferir?", options: [{ label: "A", text: "Las c\u00e1maras eliminaron el crimen" }, { label: "B", text: "Los delincuentes se desplazaron a zonas sin c\u00e1maras" }, { label: "C", text: "Los barrios vecinos son m\u00e1s peligrosos por naturaleza" }, { label: "D", text: "Las c\u00e1maras no son efectivas" }], correctAnswer: "B", explanation: "La disminuci\u00f3n en un lugar y el aumento en zonas cercanas sugiere desplazamiento del delito.", tip: "\ud83d\udd0d TRUCO: Cuando un problema disminuye en un lugar pero aumenta en otro cercano, probablemente se DESPLAZ\u00d3, no desapareci\u00f3." },
  { id: "lc-44", subject: "lectura-critica", topic: "Comprensi\u00f3n inferencial", difficulty: "medio", text: "\"Las ventas de helado aumentan en los mismos meses en que aumentan los casos de insolaci\u00f3n.\"\n\n\u00bfQu\u00e9 conclusi\u00f3n es m\u00e1s acertada?", options: [{ label: "A", text: "El helado causa insolaci\u00f3n" }, { label: "B", text: "La insolaci\u00f3n hace que la gente compre m\u00e1s helado" }, { label: "C", text: "Ambos fen\u00f3menos se deben a un tercer factor: el calor" }, { label: "D", text: "No hay ninguna relaci\u00f3n entre estos fen\u00f3menos" }], correctAnswer: "C", explanation: "Ambos aumentan cuando hace calor. El calor es la causa com\u00fan, no existe causalidad entre helado e insolaci\u00f3n.", tip: "\ud83e\udde0 TRUCO: Cuando dos cosas suben o bajan juntas, busca el TERCER FACTOR que las explica a ambas." },
  { id: "lc-45", subject: "lectura-critica", topic: "Comprensi\u00f3n cr\u00edtica", difficulty: "medio", text: "\"Un art\u00edculo titula: '\u00a1ALERTA! Qu\u00edmico mortal encontrado en el agua potable de toda Colombia.' El art\u00edculo luego explica que se encontr\u00f3 cloro, el cual es usado mundialmente para purificar el agua.\"\n\n\u00bfQu\u00e9 recurso usa el titular?", options: [{ label: "A", text: "Informaci\u00f3n precisa y responsable" }, { label: "B", text: "Sensacionalismo: usa lenguaje alarmista para una pr\u00e1ctica normal y segura" }, { label: "C", text: "Denuncia leg\u00edtima de un peligro real" }, { label: "D", text: "Sarcasmo" }], correctAnswer: "B", explanation: "El cloro se usa mundialmente para purificar agua y es seguro en las cantidades usadas. El titular es sensacionalista.", tip: "\ud83e\udde0 TRUCO: Lee siempre M\u00c1S ALL\u00c1 del titular. Si el titular dice 'ALERTA' o '\u00a1PELIGRO!' pero el contenido es algo normal, es sensacionalismo." },
  { id: "lc-46", subject: "lectura-critica", topic: "Comprensi\u00f3n literal", difficulty: "facil", text: "\"El proceso de fotos\u00edntesis permite a las plantas convertir la energ\u00eda solar, el agua y el di\u00f3xido de carbono en glucosa y ox\u00edgeno. Este proceso es fundamental para la vida en la Tierra.\"\n\n\u00bfQu\u00e9 produce la fotos\u00edntesis seg\u00fan el texto?", options: [{ label: "A", text: "Energ\u00eda solar y agua" }, { label: "B", text: "Glucosa y ox\u00edgeno" }, { label: "C", text: "Di\u00f3xido de carbono y minerales" }, { label: "D", text: "Clorofila y luz" }], correctAnswer: "B", explanation: "El texto dice claramente que la fotos\u00edntesis convierte los insumos 'en glucosa y ox\u00edgeno'.", tip: "\ud83d\udccc TRUCO: Distingue entre lo que ENTRA y lo que SALE de un proceso. Los insumos no son los productos." },
  { id: "lc-47", subject: "lectura-critica", topic: "Comprensi\u00f3n literal", difficulty: "facil", text: "\"Sim\u00f3n Bol\u00edvar lider\u00f3 la independencia de cinco naciones sudamericanas: Venezuela, Colombia, Ecuador, Per\u00fa y Bolivia. Por esta raz\u00f3n se le conoce como 'El Libertador'.\"\n\n\u00bfCu\u00e1ntas naciones liber\u00f3 Bol\u00edvar seg\u00fan el texto?", options: [{ label: "A", text: "Tres" }, { label: "B", text: "Cuatro" }, { label: "C", text: "Cinco" }, { label: "D", text: "Seis" }], correctAnswer: "C", explanation: "El texto enumera cinco naciones y dice 'cinco naciones sudamericanas'.", tip: "\ud83d\udccc TRUCO: Cuando la respuesta es un n\u00famero, verifica contando los elementos de la lista en el texto." },
  { id: "lc-48", subject: "lectura-critica", topic: "Comprensi\u00f3n inferencial", difficulty: "medio", text: "\"En la reuni\u00f3n de padres de familia, solo asistieron 5 de los 35 padres convocados. La directora suspendi\u00f3 la reuni\u00f3n y reprogram\u00f3 para el s\u00e1bado.\"\n\n\u00bfQu\u00e9 se puede inferir sobre la reprogramaci\u00f3n?", options: [{ label: "A", text: "La directora quiere castigar a los padres" }, { label: "B", text: "La directora asume que el s\u00e1bado m\u00e1s padres podr\u00e1n asistir porque probablemente no trabajan" }, { label: "C", text: "El s\u00e1bado hay otra actividad en el colegio" }, { label: "D", text: "A los padres no les importa la educaci\u00f3n de sus hijos" }], correctAnswer: "B", explanation: "Reprogramar al s\u00e1bado sugiere que la baja asistencia se debi\u00f3 a que los padres trabajan entre semana.", tip: "\ud83d\udd0d TRUCO: Las acciones de las personas revelan sus suposiciones. Si reprograma al s\u00e1bado, asume que el problema es laboral." },
  { id: "lc-49", subject: "lectura-critica", topic: "Comprensi\u00f3n cr\u00edtica", difficulty: "dificil", text: "\"Un influencer con 2 millones de seguidores publica: 'Dej\u00e9 de vacunarme hace 3 a\u00f1os y no me he enfermado. Las vacunas son innecesarias.'\"\n\n\u00bfQu\u00e9 problemas tiene este razonamiento?", options: [{ label: "A", text: "Es correcto porque la experiencia personal es v\u00e1lida" }, { label: "B", text: "Usa evidencia anecd\u00f3tica personal para contradecir evidencia cient\u00edfica global, y confunde correlaci\u00f3n con causalidad" }, { label: "C", text: "Los influencers siempre tienen raz\u00f3n sobre salud" }, { label: "D", text: "3 a\u00f1os es tiempo suficiente para probar su punto" }], correctAnswer: "B", explanation: "Un caso personal no refuta d\u00e9cadas de evidencia cient\u00edfica. Adem\u00e1s, no enfermarse no se debe necesariamente a no vacunarse.", tip: "\ud83e\udde0 TRUCO: La experiencia personal de UNA persona NUNCA refuta la ciencia basada en MILLONES de casos. Es la falacia de la evidencia anecd\u00f3tica." },
  { id: "lc-50", subject: "lectura-critica", topic: "Comprensi\u00f3n inferencial", difficulty: "medio", text: "\"Los precios del arroz subieron un 25% en el \u00faltimo mes. Las tiendas de barrio comenzaron a vender arroz en presentaciones m\u00e1s peque\u00f1as.\"\n\n\u00bfQu\u00e9 se puede inferir?", options: [{ label: "A", text: "El arroz se est\u00e1 acabando en el mundo" }, { label: "B", text: "Las tiendas se adaptan para que la gente pueda seguir comprando a pesar del alza de precio" }, { label: "C", text: "Las tiendas quieren ganar m\u00e1s dinero" }, { label: "D", text: "La gente dej\u00f3 de comer arroz" }], correctAnswer: "B", explanation: "Presentaciones m\u00e1s peque\u00f1as = precio por unidad m\u00e1s accesible. Es una estrategia de adaptaci\u00f3n al poder adquisitivo.", tip: "\ud83d\udd0d TRUCO: Los negocios se adaptan a la capacidad de compra de sus clientes. Empaques m\u00e1s peque\u00f1os = mantener ventas con precios m\u00e1s bajos por unidad." },
  { id: "lc-51", subject: "lectura-critica", topic: "Comprensi\u00f3n literal", difficulty: "facil", text: "\"La Ci\u00e9naga Grande de Santa Marta es el complejo lagunar m\u00e1s grande de Colombia, con una superficie de 4.280 km\u00b2. Es un ecosistema vital para aves migratorias y fue declarada Reserva de la Biosfera por la UNESCO.\"\n\n\u00bfQu\u00e9 organismo declar\u00f3 este lugar como Reserva?", options: [{ label: "A", text: "La ONU" }, { label: "B", text: "La UNESCO" }, { label: "C", text: "El Ministerio de Ambiente de Colombia" }, { label: "D", text: "La OMS" }], correctAnswer: "B", explanation: "El texto dice expresamente 'declarada Reserva de la Biosfera por la UNESCO'.", tip: "\ud83d\udccc TRUCO: Busca la frase exacta con el nombre de la organizaci\u00f3n. No asumas, lee." },
  { id: "lc-52", subject: "lectura-critica", topic: "Comprensi\u00f3n literal", difficulty: "facil", text: "\"Los tres poderes del Estado colombiano son: el poder ejecutivo, el poder legislativo y el poder judicial. El poder ejecutivo est\u00e1 encabezado por el Presidente de la Rep\u00fablica.\"\n\n\u00bfQui\u00e9n encabeza el poder ejecutivo?", options: [{ label: "A", text: "El Congreso" }, { label: "B", text: "La Corte Suprema" }, { label: "C", text: "El Presidente de la Rep\u00fablica" }, { label: "D", text: "El Fiscal General" }], correctAnswer: "C", explanation: "El texto indica directamente: 'El poder ejecutivo est\u00e1 encabezado por el Presidente de la Rep\u00fablica'.", tip: "\ud83d\udccc TRUCO: En preguntas sobre estructura del Estado, recuerda: Ejecutivo=Presidente, Legislativo=Congreso, Judicial=Cortes." },
  { id: "mat-1", subject: "matematicas", topic: "Aritm\u00e9tica", difficulty: "facil", text: "Un producto cuesta $45.000 y tiene un descuento del 20%. \u00bfCu\u00e1l es el precio con descuento?", options: [{ label: "A", text: "$36.000" }, { label: "B", text: "$40.000" }, { label: "C", text: "$35.000" }, { label: "D", text: "$38.000" }], correctAnswer: "A", explanation: "20% de $45.000 = $9.000. Precio final = $45.000 - $9.000 = $36.000.", tip: "\ud83d\udca1 TRUCO: Para calcular 20% r\u00e1pido: divide entre 5. $45.000 \u00f7 5 = $9.000." },
  { id: "mat-2", subject: "matematicas", topic: "Aritm\u00e9tica", difficulty: "facil", text: "Si Mar\u00eda gana $1.200.000 mensuales y gasta el 35% en arriendo, \u00bfcu\u00e1nto paga de arriendo?", options: [{ label: "A", text: "$420.000" }, { label: "B", text: "$380.000" }, { label: "C", text: "$450.000" }, { label: "D", text: "$400.000" }], correctAnswer: "A", explanation: "35% de $1.200.000 = $1.200.000 \u00d7 0.35 = $420.000.", tip: "\ud83d\udca1 TRUCO: 35% = 30% + 5%. Calcula 30% ($360.000) + 5% ($60.000) = $420.000. Divide porcentajes dif\u00edciles en f\u00e1ciles." },
  { id: "mat-3", subject: "matematicas", topic: "Aritm\u00e9tica", difficulty: "facil", text: "\u00bfCu\u00e1l es el resultado de (-3) \u00d7 (-5) + 2?", options: [{ label: "A", text: "-13" }, { label: "B", text: "17" }, { label: "C", text: "13" }, { label: "D", text: "-17" }], correctAnswer: "B", explanation: "(-3) \u00d7 (-5) = 15 (negativo \u00d7 negativo = positivo). 15 + 2 = 17.", tip: "\ud83d\udca1 TRUCO: Negativo \u00d7 Negativo = Positivo (dos negativos se cancelan). Negativo \u00d7 Positivo = Negativo." },
  { id: "mat-4", subject: "matematicas", topic: "Aritm\u00e9tica", difficulty: "facil", text: "Un tanque tiene capacidad para 500 litros. Si est\u00e1 al 60%, \u00bfcu\u00e1ntos litros tiene?", options: [{ label: "A", text: "300 litros" }, { label: "B", text: "250 litros" }, { label: "C", text: "350 litros" }, { label: "D", text: "200 litros" }], correctAnswer: "A", explanation: "60% de 500 = 500 \u00d7 0.60 = 300 litros.", tip: "\ud83d\udca1 TRUCO: 60% = 6/10. Entonces 500 \u00d7 6 \u00f7 10 = 300. Convierte porcentajes a fracciones simples." },
  { id: "mat-5", subject: "matematicas", topic: "Aritm\u00e9tica", difficulty: "facil", text: "Si 3 cuadernos cuestan $7.500, \u00bfcu\u00e1nto cuestan 7 cuadernos?", options: [{ label: "A", text: "$15.000" }, { label: "B", text: "$17.500" }, { label: "C", text: "$22.500" }, { label: "D", text: "$12.500" }], correctAnswer: "B", explanation: "Precio por cuaderno = $7.500 \u00f7 3 = $2.500. Precio de 7 = $2.500 \u00d7 7 = $17.500.", tip: "\ud83d\udca1 TRUCO: Regla de tres: primero encuentra el valor UNITARIO (de uno solo), luego multiplica." },
  { id: "mat-6", subject: "matematicas", topic: "\u00c1lgebra", difficulty: "facil", text: "Si 2x + 5 = 13, \u00bfcu\u00e1l es el valor de x?", options: [{ label: "A", text: "3" }, { label: "B", text: "4" }, { label: "C", text: "5" }, { label: "D", text: "6" }], correctAnswer: "B", explanation: "2x + 5 = 13 \u2192 2x = 13 - 5 \u2192 2x = 8 \u2192 x = 4.", tip: "\ud83d\udca1 TRUCO: Para despejar x: 1) pasa los n\u00fameros al otro lado cambiando de signo, 2) divide por el coeficiente de x." },
  { id: "mat-7", subject: "matematicas", topic: "\u00c1lgebra", difficulty: "facil", text: "Si 3(x - 2) = 12, \u00bfcu\u00e1l es el valor de x?", options: [{ label: "A", text: "4" }, { label: "B", text: "5" }, { label: "C", text: "6" }, { label: "D", text: "7" }], correctAnswer: "C", explanation: "3(x-2) = 12 \u2192 x-2 = 4 \u2192 x = 6.", tip: "\ud83d\udca1 TRUCO: Primero divide ambos lados por el n\u00famero que multiplica al par\u00e9ntesis. Luego despeja." },
  { id: "mat-8", subject: "matematicas", topic: "\u00c1lgebra", difficulty: "facil", text: "\u00bfCu\u00e1l es el valor de x en la ecuaci\u00f3n: x/4 + 3 = 7?", options: [{ label: "A", text: "10" }, { label: "B", text: "12" }, { label: "C", text: "16" }, { label: "D", text: "28" }], correctAnswer: "C", explanation: "x/4 + 3 = 7 \u2192 x/4 = 4 \u2192 x = 16.", tip: "\ud83d\udca1 TRUCO: Paso 1: a\u00edsla la fracci\u00f3n. Paso 2: multiplica ambos lados por el denominador." },
  { id: "mat-9", subject: "matematicas", topic: "\u00c1lgebra", difficulty: "facil", text: "Si el doble de un n\u00famero m\u00e1s 8 es igual a 24, \u00bfcu\u00e1l es el n\u00famero?", options: [{ label: "A", text: "6" }, { label: "B", text: "8" }, { label: "C", text: "10" }, { label: "D", text: "12" }], correctAnswer: "B", explanation: "2x + 8 = 24 \u2192 2x = 16 \u2192 x = 8.", tip: "\ud83d\udca1 TRUCO: Traduce las palabras a ecuaci\u00f3n: 'el doble' = 2x, 'm\u00e1s' = +, 'es igual a' = =." },
  { id: "mat-10", subject: "matematicas", topic: "\u00c1lgebra", difficulty: "medio", text: "\u00bfCu\u00e1l es la soluci\u00f3n del sistema: x + y = 10, x - y = 4?", options: [{ label: "A", text: "x=6, y=4" }, { label: "B", text: "x=7, y=3" }, { label: "C", text: "x=8, y=2" }, { label: "D", text: "x=5, y=5" }], correctAnswer: "B", explanation: "Sumando ambas ecuaciones: 2x = 14 \u2192 x = 7. Reemplazando: 7 + y = 10 \u2192 y = 3.", tip: "\ud83d\udca1 TRUCO: Para sistemas de ecuaciones, SUMA o RESTA las ecuaciones para eliminar una variable." },
  { id: "mat-11", subject: "matematicas", topic: "Geometr\u00eda", difficulty: "facil", text: "\u00bfCu\u00e1l es el \u00e1rea de un rect\u00e1ngulo de base 8 cm y altura 5 cm?", options: [{ label: "A", text: "13 cm\u00b2" }, { label: "B", text: "26 cm\u00b2" }, { label: "C", text: "40 cm\u00b2" }, { label: "D", text: "20 cm\u00b2" }], correctAnswer: "C", explanation: "\u00c1rea del rect\u00e1ngulo = base \u00d7 altura = 8 \u00d7 5 = 40 cm\u00b2.", tip: "\ud83d\udca1 TRUCO: Rect\u00e1ngulo = base \u00d7 altura. Cuadrado = lado\u00b2. Tri\u00e1ngulo = base \u00d7 altura \u00f7 2. Memoriza estas tres." },
  { id: "mat-12", subject: "matematicas", topic: "Geometr\u00eda", difficulty: "facil", text: "Un tri\u00e1ngulo tiene base de 10 cm y altura de 6 cm. \u00bfCu\u00e1l es su \u00e1rea?", options: [{ label: "A", text: "60 cm\u00b2" }, { label: "B", text: "30 cm\u00b2" }, { label: "C", text: "16 cm\u00b2" }, { label: "D", text: "45 cm\u00b2" }], correctAnswer: "B", explanation: "\u00c1rea = (base \u00d7 altura) \u00f7 2 = (10 \u00d7 6) \u00f7 2 = 30 cm\u00b2.", tip: "\ud83d\udca1 TRUCO: El tri\u00e1ngulo es SIEMPRE la mitad del rect\u00e1ngulo con la misma base y altura. Si sabes el rect\u00e1ngulo, divide entre 2." },
  { id: "mat-13", subject: "matematicas", topic: "Geometr\u00eda", difficulty: "medio", text: "\u00bfCu\u00e1nto mide la circunferencia de un c\u00edrculo con radio de 7 cm? (\u03c0 \u2248 3.14)", options: [{ label: "A", text: "21.98 cm" }, { label: "B", text: "43.96 cm" }, { label: "C", text: "49 cm" }, { label: "D", text: "153.86 cm" }], correctAnswer: "B", explanation: "Circunferencia = 2\u03c0r = 2 \u00d7 3.14 \u00d7 7 = 43.96 cm.", tip: "\ud83d\udca1 TRUCO: Circunferencia = 2\u03c0r (alrededor del c\u00edrculo). \u00c1rea = \u03c0r\u00b2 (lo que cubre el c\u00edrculo). No las confundas." },
  { id: "mat-14", subject: "matematicas", topic: "Geometr\u00eda", difficulty: "facil", text: "\u00bfCu\u00e1l es el volumen de una caja rectangular de 4 cm \u00d7 3 cm \u00d7 5 cm?", options: [{ label: "A", text: "12 cm\u00b3" }, { label: "B", text: "60 cm\u00b3" }, { label: "C", text: "35 cm\u00b3" }, { label: "D", text: "24 cm\u00b3" }], correctAnswer: "B", explanation: "Volumen = largo \u00d7 ancho \u00d7 alto = 4 \u00d7 3 \u00d7 5 = 60 cm\u00b3.", tip: "\ud83d\udca1 TRUCO: El volumen son 3 dimensiones multiplicadas. Si te dan 3 medidas, multipl\u00edcalas todas." },
  { id: "mat-15", subject: "matematicas", topic: "Geometr\u00eda", difficulty: "medio", text: "En un tri\u00e1ngulo rect\u00e1ngulo, si los catetos miden 3 y 4, \u00bfcu\u00e1nto mide la hipotenusa?", options: [{ label: "A", text: "5" }, { label: "B", text: "6" }, { label: "C", text: "7" }, { label: "D", text: "12" }], correctAnswer: "A", explanation: "Teorema de Pit\u00e1goras: h\u00b2 = 3\u00b2 + 4\u00b2 = 9 + 16 = 25 \u2192 h = 5.", tip: "\ud83d\udca1 TRUCO: Memoriza las tripletas pitag\u00f3ricas: (3,4,5), (5,12,13), (8,15,17). Aparecen MUCHO en el ICFES." },
  { id: "mat-16", subject: "matematicas", topic: "Estad\u00edstica", difficulty: "facil", text: "Las edades de 5 estudiantes son: 15, 16, 14, 17, 18. \u00bfCu\u00e1l es el promedio?", options: [{ label: "A", text: "15" }, { label: "B", text: "16" }, { label: "C", text: "17" }, { label: "D", text: "14" }], correctAnswer: "B", explanation: "Promedio = (15+16+14+17+18) \u00f7 5 = 80 \u00f7 5 = 16.", tip: "\ud83d\udca1 TRUCO: Promedio = suma de todos \u00f7 cantidad. Es el centro de los datos." },
  { id: "mat-17", subject: "matematicas", topic: "Estad\u00edstica", difficulty: "facil", text: "En un grupo, las notas fueron: 3.0, 4.5, 3.0, 5.0, 3.0, 4.0. \u00bfCu\u00e1l es la moda?", options: [{ label: "A", text: "4.5" }, { label: "B", text: "3.0" }, { label: "C", text: "5.0" }, { label: "D", text: "4.0" }], correctAnswer: "B", explanation: "La moda es el valor que m\u00e1s se repite. El 3.0 aparece 3 veces.", tip: "\ud83d\udca1 TRUCO: Moda = MOda = el que M\u00e1s se repite. Como la moda en la ropa: lo que m\u00e1s usan." },
  { id: "mat-18", subject: "matematicas", topic: "Estad\u00edstica", difficulty: "facil", text: "Los datos ordenados son: 2, 4, 6, 8, 10. \u00bfCu\u00e1l es la mediana?", options: [{ label: "A", text: "4" }, { label: "B", text: "6" }, { label: "C", text: "8" }, { label: "D", text: "5" }], correctAnswer: "B", explanation: "La mediana es el valor central. En 5 datos ordenados, es el tercero: 6.", tip: "\ud83d\udca1 TRUCO: Mediana = el del MEDIO. Si hay n\u00famero par de datos, promedia los dos del centro." },
  { id: "mat-19", subject: "matematicas", topic: "Estad\u00edstica", difficulty: "facil", text: "En una encuesta, 40 personas prefieren f\u00fatbol, 30 baloncesto y 10 voleibol. \u00bfQu\u00e9 porcentaje prefiere f\u00fatbol?", options: [{ label: "A", text: "40%" }, { label: "B", text: "50%" }, { label: "C", text: "60%" }, { label: "D", text: "35%" }], correctAnswer: "B", explanation: "Total = 80. Porcentaje de f\u00fatbol = 40/80 \u00d7 100 = 50%.", tip: "\ud83d\udca1 TRUCO: Porcentaje = (parte \u00f7 total) \u00d7 100. SIEMPRE calcula primero el total." },
  { id: "mat-20", subject: "matematicas", topic: "Estad\u00edstica", difficulty: "facil", text: "Si lanzo un dado justo, \u00bfcu\u00e1l es la probabilidad de obtener un n\u00famero par?", options: [{ label: "A", text: "1/2" }, { label: "B", text: "1/3" }, { label: "C", text: "1/6" }, { label: "D", text: "2/3" }], correctAnswer: "A", explanation: "N\u00fameros pares: 2, 4, 6 \u2192 3 de 6 posibles = 3/6 = 1/2.", tip: "\ud83d\udca1 TRUCO: Probabilidad = casos favorables \u00f7 casos totales. En un dado: 6 caras posibles." },
  { id: "mat-21", subject: "matematicas", topic: "Aritm\u00e9tica", difficulty: "facil", text: "\u00bfCu\u00e1l es el m\u00ednimo com\u00fan m\u00faltiplo (MCM) de 4 y 6?", options: [{ label: "A", text: "24" }, { label: "B", text: "12" }, { label: "C", text: "6" }, { label: "D", text: "2" }], correctAnswer: "B", explanation: "M\u00faltiplos de 4: 4, 8, 12, 16... M\u00faltiplos de 6: 6, 12, 18... El menor m\u00faltiplo com\u00fan es 12.", tip: "\ud83d\udca1 TRUCO: Para MCM peque\u00f1os, lista los m\u00faltiplos de cada n\u00famero hasta encontrar el primero que coincida." },
  { id: "mat-22", subject: "matematicas", topic: "Aritm\u00e9tica", difficulty: "facil", text: "Un bus recorre 240 km en 3 horas. \u00bfCu\u00e1l es su velocidad promedio?", options: [{ label: "A", text: "60 km/h" }, { label: "B", text: "80 km/h" }, { label: "C", text: "120 km/h" }, { label: "D", text: "70 km/h" }], correctAnswer: "B", explanation: "Velocidad = distancia \u00f7 tiempo = 240 \u00f7 3 = 80 km/h.", tip: "\ud83d\udca1 TRUCO: Velocidad = Distancia \u00f7 Tiempo. Memoriza el tri\u00e1ngulo D-V-T." },
  { id: "mat-23", subject: "matematicas", topic: "Aritm\u00e9tica", difficulty: "medio", text: "Si 5 obreros terminan una obra en 12 d\u00edas, \u00bfen cu\u00e1ntos d\u00edas la terminan 10 obreros?", options: [{ label: "A", text: "24 d\u00edas" }, { label: "B", text: "6 d\u00edas" }, { label: "C", text: "8 d\u00edas" }, { label: "D", text: "10 d\u00edas" }], correctAnswer: "B", explanation: "Es inversamente proporcional: m\u00e1s obreros = menos d\u00edas. 5\u00d712 = 10\u00d7x \u2192 x = 6 d\u00edas.", tip: "\ud83d\udca1 TRUCO: Si m\u00e1s personas hacen el trabajo \u2192 MENOS tiempo. Multiplica los datos iniciales y divide por el nuevo n\u00famero." },
  { id: "mat-24", subject: "matematicas", topic: "Aritm\u00e9tica", difficulty: "medio", text: "\u00bfCu\u00e1nto es 2/3 + 1/4?", options: [{ label: "A", text: "3/7" }, { label: "B", text: "11/12" }, { label: "C", text: "5/12" }, { label: "D", text: "3/12" }], correctAnswer: "B", explanation: "MCM de 3 y 4 = 12. 2/3 = 8/12, 1/4 = 3/12. 8/12 + 3/12 = 11/12.", tip: "\ud83d\udca1 TRUCO: Para sumar fracciones diferentes: 1) busca denominador com\u00fan, 2) convierte, 3) suma numeradores." },
  { id: "mat-25", subject: "matematicas", topic: "Aritm\u00e9tica", difficulty: "facil", text: "\u00bfCu\u00e1nto es 15% de 200?", options: [{ label: "A", text: "15" }, { label: "B", text: "30" }, { label: "C", text: "25" }, { label: "D", text: "35" }], correctAnswer: "B", explanation: "15% de 200 = 200 \u00d7 0.15 = 30.", tip: "\ud83d\udca1 TRUCO: 15% = 10% + 5%. El 10% de 200 = 20. El 5% = 10. Total = 30." },
  { id: "mat-26", subject: "matematicas", topic: "\u00c1lgebra", difficulty: "medio", text: "\u00bfCu\u00e1l es la pendiente de la recta que pasa por los puntos (1, 3) y (4, 9)?", options: [{ label: "A", text: "2" }, { label: "B", text: "3" }, { label: "C", text: "6" }, { label: "D", text: "1" }], correctAnswer: "A", explanation: "Pendiente = (y2-y1)/(x2-x1) = (9-3)/(4-1) = 6/3 = 2.", tip: "\ud83d\udca1 TRUCO: Pendiente = cu\u00e1nto sube (vertical) \u00f7 cu\u00e1nto avanza (horizontal). Piensa en subir escaleras." },
  { id: "mat-27", subject: "matematicas", topic: "\u00c1lgebra", difficulty: "facil", text: "Si f(x) = 2x + 3, \u00bfcu\u00e1nto es f(5)?", options: [{ label: "A", text: "10" }, { label: "B", text: "13" }, { label: "C", text: "15" }, { label: "D", text: "8" }], correctAnswer: "B", explanation: "f(5) = 2(5) + 3 = 10 + 3 = 13.", tip: "\ud83d\udca1 TRUCO: f(5) significa 'reemplaza x por 5 en la f\u00f3rmula'. Solo sustituye y calcula." },
  { id: "mat-28", subject: "matematicas", topic: "\u00c1lgebra", difficulty: "medio", text: "\u00bfCu\u00e1les son las soluciones de x\u00b2 - 9 = 0?", options: [{ label: "A", text: "x = 3 y x = -3" }, { label: "B", text: "x = 9 y x = -9" }, { label: "C", text: "x = 3 solamente" }, { label: "D", text: "x = 0 y x = 9" }], correctAnswer: "A", explanation: "x\u00b2 = 9 \u2192 x = \u00b1\u221a9 = \u00b13. Entonces x = 3 o x = -3.", tip: "\ud83d\udca1 TRUCO: x\u00b2 = k tiene DOS soluciones: +\u221ak y -\u221ak. \u00a1No olvides la negativa!" },
  { id: "mat-29", subject: "matematicas", topic: "Geometr\u00eda", difficulty: "facil", text: "\u00bfCu\u00e1ntos grados suman los \u00e1ngulos internos de un tri\u00e1ngulo?", options: [{ label: "A", text: "90\u00b0" }, { label: "B", text: "180\u00b0" }, { label: "C", text: "360\u00b0" }, { label: "D", text: "270\u00b0" }], correctAnswer: "B", explanation: "Los \u00e1ngulos internos de un tri\u00e1ngulo siempre suman 180\u00b0.", tip: "\ud83d\udca1 TRUCO: Tri\u00e1ngulo=180\u00b0, Cuadril\u00e1tero=360\u00b0. F\u00f3rmula general: (n-2)\u00d7180\u00b0 donde n=n\u00famero de lados." },
  { id: "mat-30", subject: "matematicas", topic: "Geometr\u00eda", difficulty: "facil", text: "Si un cuadrado tiene per\u00edmetro de 24 cm, \u00bfcu\u00e1nto mide cada lado?", options: [{ label: "A", text: "4 cm" }, { label: "B", text: "6 cm" }, { label: "C", text: "8 cm" }, { label: "D", text: "12 cm" }], correctAnswer: "B", explanation: "Per\u00edmetro del cuadrado = 4 \u00d7 lado \u2192 lado = 24 \u00f7 4 = 6 cm.", tip: "\ud83d\udca1 TRUCO: Per\u00edmetro = suma de todos los lados. En el cuadrado (4 lados iguales): P \u00f7 4 = lado." },
  { id: "mat-31", subject: "matematicas", topic: "\u00c1lgebra", difficulty: "medio", text: "Un n\u00famero aumentado en su 25% es igual a 100. \u00bfCu\u00e1l es el n\u00famero?", options: [{ label: "A", text: "75" }, { label: "B", text: "80" }, { label: "C", text: "85" }, { label: "D", text: "90" }], correctAnswer: "B", explanation: "x + 0.25x = 100 \u2192 1.25x = 100 \u2192 x = 80.", tip: "\ud83d\udca1 TRUCO: 'Aumentado en 25%' = multiplicar por 1.25. Para encontrar el original, divide el resultado entre 1.25." },
  { id: "mat-32", subject: "matematicas", topic: "Aritm\u00e9tica", difficulty: "facil", text: "Un art\u00edculo costaba $80.000 y aument\u00f3 un 15%. \u00bfCu\u00e1nto cuesta ahora?", options: [{ label: "A", text: "$92.000" }, { label: "B", text: "$95.000" }, { label: "C", text: "$88.000" }, { label: "D", text: "$90.000" }], correctAnswer: "A", explanation: "15% de $80.000 = $12.000. Nuevo precio = $80.000 + $12.000 = $92.000.", tip: "\ud83d\udca1 TRUCO: Aumento del 15% = precio \u00d7 1.15 = $80.000 \u00d7 1.15 = $92.000. M\u00e1s r\u00e1pido que calcular el porcentaje aparte." },
  { id: "mat-33", subject: "matematicas", topic: "Estad\u00edstica", difficulty: "facil", text: "En un sal\u00f3n de 30 estudiantes, 18 aprobaron el examen. \u00bfCu\u00e1l es la probabilidad de que un estudiante elegido al azar haya aprobado?", options: [{ label: "A", text: "3/5" }, { label: "B", text: "2/5" }, { label: "C", text: "1/2" }, { label: "D", text: "2/3" }], correctAnswer: "A", explanation: "P(aprobar) = 18/30 = 3/5.", tip: "\ud83d\udca1 TRUCO: Simplifica fracciones dividiendo ambos n\u00fameros por su MCD. 18\u00f76=3, 30\u00f76=5." },
  { id: "mat-34", subject: "matematicas", topic: "\u00c1lgebra", difficulty: "facil", text: "Si el triple de un n\u00famero disminuido en 7 es igual a 20, \u00bfcu\u00e1l es el n\u00famero?", options: [{ label: "A", text: "7" }, { label: "B", text: "8" }, { label: "C", text: "9" }, { label: "D", text: "10" }], correctAnswer: "C", explanation: "3x - 7 = 20 \u2192 3x = 27 \u2192 x = 9.", tip: "\ud83d\udca1 TRUCO: Traduce: 'triple'=3x, 'disminuido en'=menos, 'es igual'=signo igual." },
  { id: "mat-35", subject: "matematicas", topic: "Geometr\u00eda", difficulty: "medio", text: "\u00bfCu\u00e1l es el \u00e1rea de un c\u00edrculo con radio 5 cm? (\u03c0 \u2248 3.14)", options: [{ label: "A", text: "31.4 cm\u00b2" }, { label: "B", text: "78.5 cm\u00b2" }, { label: "C", text: "15.7 cm\u00b2" }, { label: "D", text: "25 cm\u00b2" }], correctAnswer: "B", explanation: "\u00c1rea = \u03c0r\u00b2 = 3.14 \u00d7 25 = 78.5 cm\u00b2.", tip: "\ud83d\udca1 TRUCO: \u00c1rea del c\u00edrculo = \u03c0 \u00d7 radio\u00b2. Primero eleva al cuadrado, luego multiplica por \u03c0." },
  { id: "mat-36", subject: "matematicas", topic: "Aritm\u00e9tica", difficulty: "facil", text: "\u00bfCu\u00e1l es el resultado de \u221a144?", options: [{ label: "A", text: "11" }, { label: "B", text: "12" }, { label: "C", text: "13" }, { label: "D", text: "14" }], correctAnswer: "B", explanation: "12 \u00d7 12 = 144, entonces \u221a144 = 12.", tip: "\ud83d\udca1 TRUCO: Memoriza las ra\u00edces perfectas: \u221a1=1, \u221a4=2, \u221a9=3, \u221a16=4, \u221a25=5... \u221a144=12, \u221a169=13." },
  { id: "mat-37", subject: "matematicas", topic: "\u00c1lgebra", difficulty: "medio", text: "\u00bfCu\u00e1l expresi\u00f3n es equivalente a 2(3x + 4) - 5?", options: [{ label: "A", text: "6x + 3" }, { label: "B", text: "6x + 8" }, { label: "C", text: "6x - 1" }, { label: "D", text: "5x + 3" }], correctAnswer: "A", explanation: "2(3x+4)-5 = 6x+8-5 = 6x+3.", tip: "\ud83d\udca1 TRUCO: Primero distribuye (multiplica cada t\u00e9rmino dentro del par\u00e9ntesis), luego combina t\u00e9rminos semejantes." },
  { id: "mat-38", subject: "matematicas", topic: "Estad\u00edstica", difficulty: "facil", text: "Si una moneda se lanza 100 veces y cae cara 45 veces, \u00bfcu\u00e1l es la frecuencia relativa de cara?", options: [{ label: "A", text: "0.55" }, { label: "B", text: "0.45" }, { label: "C", text: "45" }, { label: "D", text: "0.50" }], correctAnswer: "B", explanation: "Frecuencia relativa = 45/100 = 0.45.", tip: "\ud83d\udca1 TRUCO: Frecuencia relativa = veces que ocurre \u00f7 total de intentos. Siempre da un n\u00famero entre 0 y 1." },
  { id: "mat-39", subject: "matematicas", topic: "Aritm\u00e9tica", difficulty: "facil", text: "Juan compr\u00f3 3 camisas a $35.000 cada una y 2 pantalones a $55.000 cada uno. \u00bfCu\u00e1nto gast\u00f3 en total?", options: [{ label: "A", text: "$195.000" }, { label: "B", text: "$215.000" }, { label: "C", text: "$205.000" }, { label: "D", text: "$225.000" }], correctAnswer: "B", explanation: "Camisas: 3 \u00d7 $35.000 = $105.000. Pantalones: 2 \u00d7 $55.000 = $110.000. Total = $215.000.", tip: "\ud83d\udca1 TRUCO: En problemas de compras, calcula cada tipo de producto por separado y luego suma." },
  { id: "mat-40", subject: "matematicas", topic: "Aritm\u00e9tica", difficulty: "facil", text: "Si un reloj se atrasa 5 minutos cada hora, \u00bfcu\u00e1ntos minutos se habr\u00e1 atrasado despu\u00e9s de 6 horas?", options: [{ label: "A", text: "25 minutos" }, { label: "B", text: "30 minutos" }, { label: "C", text: "35 minutos" }, { label: "D", text: "20 minutos" }], correctAnswer: "B", explanation: "5 minutos/hora \u00d7 6 horas = 30 minutos de atraso.", tip: "\ud83d\udca1 TRUCO: Tasa \u00d7 tiempo = total. Si algo ocurre a raz\u00f3n constante, solo multiplica." },
  { id: "mat-41", subject: "matematicas", topic: "\u00c1lgebra", difficulty: "medio", text: "La funci\u00f3n y = -2x + 6, \u00bfen qu\u00e9 punto corta al eje x?", options: [{ label: "A", text: "(3, 0)" }, { label: "B", text: "(0, 6)" }, { label: "C", text: "(2, 0)" }, { label: "D", text: "(-3, 0)" }], correctAnswer: "A", explanation: "Corta el eje x cuando y=0: 0 = -2x + 6 \u2192 2x = 6 \u2192 x = 3. Punto (3,0).", tip: "\ud83d\udca1 TRUCO: Eje x = donde y es 0. Eje y = donde x es 0. Reemplaza el que corresponda." },
  { id: "mat-42", subject: "matematicas", topic: "Geometr\u00eda", difficulty: "facil", text: "Dos \u00e1ngulos son complementarios. Si uno mide 35\u00b0, \u00bfcu\u00e1nto mide el otro?", options: [{ label: "A", text: "145\u00b0" }, { label: "B", text: "55\u00b0" }, { label: "C", text: "65\u00b0" }, { label: "D", text: "125\u00b0" }], correctAnswer: "B", explanation: "Complementarios suman 90\u00b0. Otro = 90\u00b0 - 35\u00b0 = 55\u00b0.", tip: "\ud83d\udca1 TRUCO: Complementarios = 90\u00b0 (como una esquina). Suplementarios = 180\u00b0 (como una l\u00ednea recta)." },
  { id: "mat-43", subject: "matematicas", topic: "Aritm\u00e9tica", difficulty: "medio", text: "\u00bfCu\u00e1l de las siguientes fracciones es mayor: 3/4 o 5/7?", options: [{ label: "A", text: "3/4 es mayor" }, { label: "B", text: "5/7 es mayor" }, { label: "C", text: "Son iguales" }, { label: "D", text: "No se pueden comparar" }], correctAnswer: "A", explanation: "3/4 = 21/28, 5/7 = 20/28. Como 21/28 > 20/28, entonces 3/4 > 5/7.", tip: "\ud83d\udca1 TRUCO: Para comparar fracciones, ponlas con el mismo denominador y compara numeradores." },
  { id: "mat-44", subject: "matematicas", topic: "\u00c1lgebra", difficulty: "medio", text: "\u00bfCu\u00e1l es el valor de 5\u00b2 - 3\u00b2 ?", options: [{ label: "A", text: "4" }, { label: "B", text: "16" }, { label: "C", text: "22" }, { label: "D", text: "8" }], correctAnswer: "B", explanation: "5\u00b2 - 3\u00b2 = 25 - 9 = 16. Tambi\u00e9n: (5-3)(5+3) = 2\u00d78 = 16.", tip: "\ud83d\udca1 TRUCO: a\u00b2-b\u00b2 = (a-b)(a+b). Esta f\u00f3rmula ahorra tiempo en el ICFES." },
  { id: "mat-45", subject: "matematicas", topic: "Estad\u00edstica", difficulty: "medio", text: "Un dado se lanza dos veces. \u00bfCu\u00e1l es la probabilidad de obtener 6 ambas veces?", options: [{ label: "A", text: "1/6" }, { label: "B", text: "1/12" }, { label: "C", text: "1/36" }, { label: "D", text: "2/6" }], correctAnswer: "C", explanation: "P(6 y 6) = 1/6 \u00d7 1/6 = 1/36.", tip: "\ud83d\udca1 TRUCO: Para eventos independientes, MULTIPLICA las probabilidades. P(A y B) = P(A) \u00d7 P(B)." },
  { id: "mat-46", subject: "matematicas", topic: "Geometr\u00eda", difficulty: "facil", text: "Un terreno rectangular mide 15 m de largo y 10 m de ancho. \u00bfCu\u00e1ntos metros de cerca se necesitan para rodearlo?", options: [{ label: "A", text: "50 m" }, { label: "B", text: "25 m" }, { label: "C", text: "150 m" }, { label: "D", text: "30 m" }], correctAnswer: "A", explanation: "Per\u00edmetro = 2(largo + ancho) = 2(15 + 10) = 50 m.", tip: "\ud83d\udca1 TRUCO: Cerca/valla alrededor = PER\u00cdMETRO. Pasto/piso dentro = \u00c1REA. La palabra clave te dice qu\u00e9 f\u00f3rmula usar." },
  { id: "mat-47", subject: "matematicas", topic: "Aritm\u00e9tica", difficulty: "facil", text: "Si un kilo de arroz cuesta $3.200 y un kilo de fr\u00edjol cuesta $5.800, \u00bfcu\u00e1nto cuestan 2 kilos de arroz y 3 de fr\u00edjol?", options: [{ label: "A", text: "$23.800" }, { label: "B", text: "$24.000" }, { label: "C", text: "$23.000" }, { label: "D", text: "$25.400" }], correctAnswer: "A", explanation: "Arroz: 2 \u00d7 $3.200 = $6.400. Fr\u00edjol: 3 \u00d7 $5.800 = $17.400. Total = $23.800.", tip: "\ud83d\udca1 TRUCO: Organiza por producto, calcula cada uno, y suma al final. As\u00ed evitas errores." },
  { id: "mat-48", subject: "matematicas", topic: "\u00c1lgebra", difficulty: "medio", text: "Si x = -2, \u00bfcu\u00e1nto vale x\u00b3 + 2x?", options: [{ label: "A", text: "-12" }, { label: "B", text: "12" }, { label: "C", text: "-4" }, { label: "D", text: "4" }], correctAnswer: "A", explanation: "(-2)\u00b3 + 2(-2) = -8 + (-4) = -12.", tip: "\ud83d\udca1 TRUCO: Exponente impar de n\u00famero negativo = resultado negativo. (-2)\u00b3 = -8, no 8." },
  { id: "mat-49", subject: "matematicas", topic: "Estad\u00edstica", difficulty: "facil", text: "Los datos son: 5, 8, 10, 10, 12, 15, 20. \u00bfCu\u00e1l es el rango?", options: [{ label: "A", text: "10" }, { label: "B", text: "15" }, { label: "C", text: "12" }, { label: "D", text: "5" }], correctAnswer: "B", explanation: "Rango = valor m\u00e1ximo - valor m\u00ednimo = 20 - 5 = 15.", tip: "\ud83d\udca1 TRUCO: Rango = mayor - menor. Mide cu\u00e1nto se dispersan los datos." },
  { id: "mat-50", subject: "matematicas", topic: "Aritm\u00e9tica", difficulty: "medio", text: "\u00bfCu\u00e1nto es 0.25 \u00d7 0.4?", options: [{ label: "A", text: "0.1" }, { label: "B", text: "1.0" }, { label: "C", text: "0.01" }, { label: "D", text: "0.65" }], correctAnswer: "A", explanation: "0.25 \u00d7 0.4 = 1/4 \u00d7 2/5 = 2/20 = 0.1.", tip: "\ud83d\udca1 TRUCO: Convierte decimales a fracciones si es m\u00e1s f\u00e1cil. 0.25 = 1/4, 0.5 = 1/2, 0.1 = 1/10." },
  { id: "cn-1", subject: "ciencias", topic: "Biolog\u00eda", difficulty: "facil", text: "\u00bfCu\u00e1l es la unidad b\u00e1sica de la vida?", options: [{ label: "A", text: "El \u00e1tomo" }, { label: "B", text: "La mol\u00e9cula" }, { label: "C", text: "La c\u00e9lula" }, { label: "D", text: "El tejido" }], correctAnswer: "C", explanation: "La c\u00e9lula es la unidad estructural y funcional b\u00e1sica de todos los seres vivos.", tip: "\ud83d\udd2c TRUCO: C\u00e9lula = unidad de VIDA. \u00c1tomo = unidad de MATERIA. No las confundas." },
  { id: "cn-2", subject: "ciencias", topic: "Biolog\u00eda", difficulty: "facil", text: "\u00bfQu\u00e9 organelo celular se encarga de la respiraci\u00f3n celular y producci\u00f3n de energ\u00eda?", options: [{ label: "A", text: "El n\u00facleo" }, { label: "B", text: "La mitocondria" }, { label: "C", text: "El ribosoma" }, { label: "D", text: "El aparato de Golgi" }], correctAnswer: "B", explanation: "La mitocondria es la 'central energ\u00e9tica' de la c\u00e9lula. Produce ATP mediante respiraci\u00f3n celular.", tip: "\ud83d\udd2c TRUCO: Mitocondria = energ\u00eda. Piensa en 'mito-C\u00d3NDOR': el c\u00f3ndor necesita ENERG\u00cdA para volar." },
  { id: "cn-3", subject: "ciencias", topic: "Biolog\u00eda", difficulty: "facil", text: "\u00bfCu\u00e1l es la diferencia principal entre c\u00e9lula animal y vegetal?", options: [{ label: "A", text: "Solo la vegetal tiene n\u00facleo" }, { label: "B", text: "La vegetal tiene pared celular y cloroplastos, la animal no" }, { label: "C", text: "Solo la animal tiene membrana" }, { label: "D", text: "La animal es m\u00e1s grande que la vegetal" }], correctAnswer: "B", explanation: "Las c\u00e9lulas vegetales tienen pared celular (rigidez) y cloroplastos (fotos\u00edntesis), que las animales no poseen.", tip: "\ud83d\udd2c TRUCO: VEGETAL tiene lo VERDE (cloroplastos) y PARED (como una casa). ANIMAL tiene m\u00e1s flexibilidad." },
  { id: "cn-4", subject: "ciencias", topic: "Biolog\u00eda", difficulty: "facil", text: "El ADN se encuentra principalmente en:", options: [{ label: "A", text: "La membrana celular" }, { label: "B", text: "El citoplasma" }, { label: "C", text: "El n\u00facleo de la c\u00e9lula" }, { label: "D", text: "Los ribosomas" }], correctAnswer: "C", explanation: "El ADN est\u00e1 en el n\u00facleo celular, donde almacena la informaci\u00f3n gen\u00e9tica del organismo.", tip: "\ud83d\udd2c TRUCO: ADN = instrucciones de la vida. Est\u00e1 en el N\u00daCLEO, que es como el 'cerebro' de la c\u00e9lula." },
  { id: "cn-5", subject: "ciencias", topic: "Biolog\u00eda", difficulty: "facil", text: "\u00bfQu\u00e9 tipo de reproducci\u00f3n produce individuos gen\u00e9ticamente id\u00e9nticos?", options: [{ label: "A", text: "Reproducci\u00f3n sexual" }, { label: "B", text: "Reproducci\u00f3n asexual" }, { label: "C", text: "Fecundaci\u00f3n externa" }, { label: "D", text: "Polinizaci\u00f3n cruzada" }], correctAnswer: "B", explanation: "La reproducci\u00f3n asexual produce clones (individuos id\u00e9nticos) porque no hay mezcla de material gen\u00e9tico.", tip: "\ud83d\udd2c TRUCO: Asexual = sin mezcla = clones id\u00e9nticos. Sexual = mezcla de genes = todos diferentes." },
  { id: "cn-6", subject: "ciencias", topic: "Biolog\u00eda", difficulty: "facil", text: "En una cadena alimentaria: pasto \u2192 conejo \u2192 zorro \u2192 \u00e1guila, \u00bfqui\u00e9n es el consumidor secundario?", options: [{ label: "A", text: "El pasto" }, { label: "B", text: "El conejo" }, { label: "C", text: "El zorro" }, { label: "D", text: "El \u00e1guila" }], correctAnswer: "C", explanation: "Productor=pasto, Consumidor 1\u00b0=conejo (come plantas), Consumidor 2\u00b0=zorro (come al que come plantas).", tip: "\ud83d\udd2c TRUCO: Cuenta los eslabones despu\u00e9s de la planta: 1\u00b0=herb\u00edvoro, 2\u00b0=come al herb\u00edvoro, 3\u00b0=come al 2\u00b0." },
  { id: "cn-7", subject: "ciencias", topic: "Biolog\u00eda", difficulty: "facil", text: "\u00bfCu\u00e1l es la funci\u00f3n principal del sistema circulatorio?", options: [{ label: "A", text: "Digerir los alimentos" }, { label: "B", text: "Transportar sangre, ox\u00edgeno y nutrientes por todo el cuerpo" }, { label: "C", text: "Producir hormonas" }, { label: "D", text: "Filtrar las toxinas del cuerpo" }], correctAnswer: "B", explanation: "El sistema circulatorio (coraz\u00f3n, vasos sangu\u00edneos) transporta sangre con ox\u00edgeno y nutrientes.", tip: "\ud83d\udd2c TRUCO: Circulatorio = CIRCULA la sangre. Piensa en el coraz\u00f3n como una bomba que empuja la sangre." },
  { id: "cn-8", subject: "ciencias", topic: "Biolog\u00eda", difficulty: "facil", text: "\u00bfQu\u00e9 vitamina produce el cuerpo al exponerse al sol?", options: [{ label: "A", text: "Vitamina A" }, { label: "B", text: "Vitamina C" }, { label: "C", text: "Vitamina D" }, { label: "D", text: "Vitamina B12" }], correctAnswer: "C", explanation: "La piel produce vitamina D cuando se expone a la luz solar ultravioleta.", tip: "\ud83d\udd2c TRUCO: Vitamina D = sol (D de Day/D\u00eda). Es la \u00fanica que el cuerpo produce con ayuda del sol." },
  { id: "cn-9", subject: "ciencias", topic: "Biolog\u00eda", difficulty: "facil", text: "\u00bfCu\u00e1ntos cromosomas tiene un ser humano normal?", options: [{ label: "A", text: "23" }, { label: "B", text: "46" }, { label: "C", text: "48" }, { label: "D", text: "44" }], correctAnswer: "B", explanation: "Los humanos tienen 46 cromosomas (23 pares). 23 del padre + 23 de la madre.", tip: "\ud83d\udd2c TRUCO: 46 cromosomas = 23 pares. Cada padre aporta la mitad (23). El par 23 determina el sexo (XX o XY)." },
  { id: "cn-10", subject: "ciencias", topic: "Biolog\u00eda", difficulty: "facil", text: "\u00bfQu\u00e9 proceso realizan las plantas para producir su propio alimento?", options: [{ label: "A", text: "Respiraci\u00f3n" }, { label: "B", text: "Fermentaci\u00f3n" }, { label: "C", text: "Fotos\u00edntesis" }, { label: "D", text: "Digesti\u00f3n" }], correctAnswer: "C", explanation: "La fotos\u00edntesis convierte luz solar + CO\u2082 + agua en glucosa y ox\u00edgeno.", tip: "\ud83d\udd2c TRUCO: FOTO = luz, S\u00cdNTESIS = producir. Las plantas PRODUCEN alimento con LUZ." },
  { id: "cn-11", subject: "ciencias", topic: "Qu\u00edmica", difficulty: "facil", text: "\u00bfCu\u00e1l es la f\u00f3rmula qu\u00edmica del agua?", options: [{ label: "A", text: "CO\u2082" }, { label: "B", text: "H\u2082O" }, { label: "C", text: "NaCl" }, { label: "D", text: "O\u2082" }], correctAnswer: "B", explanation: "H\u2082O = 2 \u00e1tomos de hidr\u00f3geno + 1 de ox\u00edgeno.", tip: "\ud83e\uddea TRUCO: Memoriza las f\u00f3rmulas b\u00e1sicas: H\u2082O=agua, CO\u2082=di\u00f3xido carbono, NaCl=sal, O\u2082=ox\u00edgeno." },
  { id: "cn-12", subject: "ciencias", topic: "Qu\u00edmica", difficulty: "medio", text: "\u00bfQu\u00e9 tipo de enlace se forma cuando los \u00e1tomos COMPARTEN electrones?", options: [{ label: "A", text: "Enlace i\u00f3nico" }, { label: "B", text: "Enlace covalente" }, { label: "C", text: "Enlace met\u00e1lico" }, { label: "D", text: "Enlace por puente de hidr\u00f3geno" }], correctAnswer: "B", explanation: "El enlace covalente ocurre cuando dos \u00e1tomos comparten electrones.", tip: "\ud83e\uddea TRUCO: COvalente = COmparten. I\u00d3Nico = IONes (uno da, otro recibe electrones)." },
  { id: "cn-13", subject: "ciencias", topic: "Qu\u00edmica", difficulty: "facil", text: "\u00bfCu\u00e1l es el pH de una sustancia neutra?", options: [{ label: "A", text: "0" }, { label: "B", text: "7" }, { label: "C", text: "14" }, { label: "D", text: "1" }], correctAnswer: "B", explanation: "pH 7 = neutro (como el agua pura). Menor a 7 = \u00e1cido. Mayor a 7 = b\u00e1sico/alcalino.", tip: "\ud83e\uddea TRUCO: pH: 0-6 = \u00c1CIDO (lim\u00f3n, vinagre). 7 = NEUTRO (agua). 8-14 = B\u00c1SICO (jab\u00f3n, cloro)." },
  { id: "cn-14", subject: "ciencias", topic: "Qu\u00edmica", difficulty: "facil", text: "\u00bfQu\u00e9 part\u00edcula subat\u00f3mica tiene carga positiva?", options: [{ label: "A", text: "Electr\u00f3n" }, { label: "B", text: "Neutr\u00f3n" }, { label: "C", text: "Prot\u00f3n" }, { label: "D", text: "Fot\u00f3n" }], correctAnswer: "C", explanation: "Prot\u00f3n = carga positiva (+). Electr\u00f3n = negativa (-). Neutr\u00f3n = sin carga (neutro).", tip: "\ud83e\uddea TRUCO: PROt\u00f3n = POsitivo (ambas empiezan con P). Electr\u00f3n = nEgativo. Neutr\u00f3n = Neutro." },
  { id: "cn-15", subject: "ciencias", topic: "Qu\u00edmica", difficulty: "facil", text: "\u00bfQu\u00e9 gas se libera durante la fotos\u00edntesis?", options: [{ label: "A", text: "Di\u00f3xido de carbono" }, { label: "B", text: "Nitr\u00f3geno" }, { label: "C", text: "Ox\u00edgeno" }, { label: "D", text: "Metano" }], correctAnswer: "C", explanation: "La fotos\u00edntesis: CO\u2082 + H\u2082O + luz \u2192 glucosa + O\u2082. Libera ox\u00edgeno.", tip: "\ud83e\uddea TRUCO: Fotos\u00edntesis y respiraci\u00f3n son OPUESTOS. Fotos\u00edntesis libera O\u2082, respiraci\u00f3n libera CO\u2082." },
  { id: "cn-16", subject: "ciencias", topic: "Qu\u00edmica", difficulty: "medio", text: "\u00bfCu\u00e1ntos elementos tiene la tabla peri\u00f3dica actualmente?", options: [{ label: "A", text: "92" }, { label: "B", text: "108" }, { label: "C", text: "118" }, { label: "D", text: "126" }], correctAnswer: "C", explanation: "La tabla peri\u00f3dica tiene 118 elementos confirmados hasta la fecha.", tip: "\ud83e\uddea TRUCO: Son 118 elementos. Los primeros 92 son naturales, el resto son sint\u00e9ticos (creados en laboratorio)." },
  { id: "cn-17", subject: "ciencias", topic: "F\u00edsica", difficulty: "facil", text: "\u00bfCu\u00e1l es la unidad de medida de la fuerza?", options: [{ label: "A", text: "Julio (J)" }, { label: "B", text: "Newton (N)" }, { label: "C", text: "Vatio (W)" }, { label: "D", text: "Pascal (Pa)" }], correctAnswer: "B", explanation: "La fuerza se mide en Newtons (N), en honor a Isaac Newton.", tip: "\ud83d\udd27 TRUCO: Newton = fuerza. Julio = energ\u00eda/trabajo. Vatio = potencia. Pascal = presi\u00f3n." },
  { id: "cn-18", subject: "ciencias", topic: "F\u00edsica", difficulty: "facil", text: "Si un objeto se mueve a velocidad constante, la aceleraci\u00f3n es:", options: [{ label: "A", text: "Positiva" }, { label: "B", text: "Negativa" }, { label: "C", text: "Cero" }, { label: "D", text: "Variable" }], correctAnswer: "C", explanation: "Aceleraci\u00f3n = cambio de velocidad. Si la velocidad no cambia, la aceleraci\u00f3n es 0.", tip: "\ud83d\udd27 TRUCO: Aceleraci\u00f3n = CAMBIO en velocidad. Sin cambio = sin aceleraci\u00f3n = 0." },
  { id: "cn-19", subject: "ciencias", topic: "F\u00edsica", difficulty: "facil", text: "\u00bfQu\u00e9 ley de Newton dice 'A toda acci\u00f3n corresponde una reacci\u00f3n igual y opuesta'?", options: [{ label: "A", text: "Primera ley" }, { label: "B", text: "Segunda ley" }, { label: "C", text: "Tercera ley" }, { label: "D", text: "Ley de gravitaci\u00f3n" }], correctAnswer: "C", explanation: "La tercera ley de Newton establece que las fuerzas vienen en pares: acci\u00f3n y reacci\u00f3n.", tip: "\ud83d\udd27 TRUCO: 1\u00aa=inercia (quieto se queda quieto). 2\u00aa=F=m\u00d7a. 3\u00aa=acci\u00f3n-reacci\u00f3n." },
  { id: "cn-20", subject: "ciencias", topic: "F\u00edsica", difficulty: "facil", text: "\u00bfQu\u00e9 tipo de energ\u00eda tiene un objeto en movimiento?", options: [{ label: "A", text: "Energ\u00eda potencial" }, { label: "B", text: "Energ\u00eda cin\u00e9tica" }, { label: "C", text: "Energ\u00eda t\u00e9rmica" }, { label: "D", text: "Energ\u00eda qu\u00edmica" }], correctAnswer: "B", explanation: "Energ\u00eda cin\u00e9tica = energ\u00eda del movimiento. Potencial = energ\u00eda almacenada por posici\u00f3n.", tip: "\ud83d\udd27 TRUCO: CIN\u00c9tica = CINE = movimiento. POtencial = POsici\u00f3n (algo alto tiene potencial de caer)." },
  { id: "cn-21", subject: "ciencias", topic: "Medio ambiente", difficulty: "facil", text: "\u00bfQu\u00e9 gas es el principal causante del efecto invernadero?", options: [{ label: "A", text: "Ox\u00edgeno" }, { label: "B", text: "Nitr\u00f3geno" }, { label: "C", text: "Di\u00f3xido de carbono" }, { label: "D", text: "Helio" }], correctAnswer: "C", explanation: "El CO\u2082 es el principal gas de efecto invernadero producido por actividades humanas.", tip: "\ud83c\udf0d TRUCO: CO\u2082 viene de quemar combustibles f\u00f3siles (gasolina, carb\u00f3n, gas natural). Es el principal villano del cambio clim\u00e1tico." },
  { id: "cn-22", subject: "ciencias", topic: "Medio ambiente", difficulty: "facil", text: "\u00bfCu\u00e1l es la capa de la atm\u00f3sfera que nos protege de los rayos ultravioleta?", options: [{ label: "A", text: "Trop\u00f3sfera" }, { label: "B", text: "Capa de ozono (estrat\u00f3sfera)" }, { label: "C", text: "Mes\u00f3sfera" }, { label: "D", text: "Term\u00f3sfera" }], correctAnswer: "B", explanation: "La capa de ozono (O\u2083) en la estrat\u00f3sfera filtra los rayos UV da\u00f1inos del sol.", tip: "\ud83c\udf0d TRUCO: OZONO = O\u2083 = protecci\u00f3n UV. Est\u00e1 en la estrat\u00f3sfera, como un escudo solar." },
  { id: "cn-23", subject: "ciencias", topic: "Biolog\u00eda", difficulty: "facil", text: "\u00bfQu\u00e9 sistema del cuerpo humano se encarga de la defensa contra enfermedades?", options: [{ label: "A", text: "Sistema digestivo" }, { label: "B", text: "Sistema inmunol\u00f3gico" }, { label: "C", text: "Sistema nervioso" }, { label: "D", text: "Sistema endocrino" }], correctAnswer: "B", explanation: "El sistema inmunol\u00f3gico (gl\u00f3bulos blancos, anticuerpos) nos defiende de virus, bacterias y otros pat\u00f3genos.", tip: "\ud83d\udd2c TRUCO: Inmuno = inmunidad = DEFENSA. Los gl\u00f3bulos blancos son los 'soldados' del cuerpo." },
  { id: "cn-24", subject: "ciencias", topic: "Biolog\u00eda", difficulty: "facil", text: "\u00bfCu\u00e1l es el \u00f3rgano m\u00e1s grande del cuerpo humano?", options: [{ label: "A", text: "El h\u00edgado" }, { label: "B", text: "El cerebro" }, { label: "C", text: "La piel" }, { label: "D", text: "Los pulmones" }], correctAnswer: "C", explanation: "La piel es el \u00f3rgano m\u00e1s grande, cubriendo aproximadamente 2 m\u00b2 en un adulto.", tip: "\ud83d\udd2c TRUCO: La piel S\u00cd es un \u00f3rgano (el m\u00e1s grande). Protege, regula temperatura y permite el sentido del tacto." },
  { id: "cn-25", subject: "ciencias", topic: "Qu\u00edmica", difficulty: "facil", text: "\u00bfQu\u00e9 cambio de estado ocurre cuando el agua l\u00edquida se convierte en vapor?", options: [{ label: "A", text: "Fusi\u00f3n" }, { label: "B", text: "Solidificaci\u00f3n" }, { label: "C", text: "Evaporaci\u00f3n" }, { label: "D", text: "Condensaci\u00f3n" }], correctAnswer: "C", explanation: "Evaporaci\u00f3n = l\u00edquido a gas. Condensaci\u00f3n = gas a l\u00edquido (opuesto).", tip: "\ud83e\uddea TRUCO: Fusi\u00f3n=s\u00f3lido\u2192l\u00edquido. Evaporaci\u00f3n=l\u00edquido\u2192gas. Condensaci\u00f3n=gas\u2192l\u00edquido. Solidificaci\u00f3n=l\u00edquido\u2192s\u00f3lido." },
  { id: "cn-26", subject: "ciencias", topic: "F\u00edsica", difficulty: "medio", text: "\u00bfCu\u00e1l es la velocidad de la luz aproximadamente?", options: [{ label: "A", text: "300.000 km/s" }, { label: "B", text: "300.000 m/s" }, { label: "C", text: "30.000 km/s" }, { label: "D", text: "3.000.000 km/s" }], correctAnswer: "A", explanation: "La velocidad de la luz es aproximadamente 300.000 km/s o 3\u00d710\u2078 m/s.", tip: "\ud83d\udd27 TRUCO: Luz = 300.000 km/s. Sonido = 340 m/s. La luz es MUCHO m\u00e1s r\u00e1pida que el sonido." },
  { id: "cn-27", subject: "ciencias", topic: "Biolog\u00eda", difficulty: "dificil", text: "\u00bfQu\u00e9 tipo de selecci\u00f3n natural favorece a los individuos con caracter\u00edsticas intermedias?", options: [{ label: "A", text: "Selecci\u00f3n direccional" }, { label: "B", text: "Selecci\u00f3n estabilizadora" }, { label: "C", text: "Selecci\u00f3n disruptiva" }, { label: "D", text: "Selecci\u00f3n artificial" }], correctAnswer: "B", explanation: "La selecci\u00f3n estabilizadora favorece los fenotipos intermedios, reduciendo la variaci\u00f3n.", tip: "\ud83d\udd2c TRUCO: Estabilizadora = favorece el PROMEDIO. Direccional = favorece un EXTREMO. Disruptiva = favorece AMBOS extremos." },
  { id: "cn-28", subject: "ciencias", topic: "Qu\u00edmica", difficulty: "facil", text: "\u00bfCu\u00e1l de los siguientes es un ejemplo de cambio qu\u00edmico?", options: [{ label: "A", text: "Derretir hielo" }, { label: "B", text: "Romper un vaso" }, { label: "C", text: "Quemar papel" }, { label: "D", text: "Cortar madera" }], correctAnswer: "C", explanation: "Quemar papel es un cambio qu\u00edmico porque se transforma en ceniza y gases; no se puede revertir.", tip: "\ud83e\uddea TRUCO: Cambio QU\u00cdMICO = se crea algo nuevo (no puedes volver atr\u00e1s). Cambio F\u00cdSICO = misma sustancia, diferente forma." },
  { id: "cn-29", subject: "ciencias", topic: "F\u00edsica", difficulty: "medio", text: "\u00bfQu\u00e9 tipo de onda es el sonido?", options: [{ label: "A", text: "Onda electromagn\u00e9tica" }, { label: "B", text: "Onda mec\u00e1nica longitudinal" }, { label: "C", text: "Onda transversal" }, { label: "D", text: "Onda estacionaria" }], correctAnswer: "B", explanation: "El sonido es una onda mec\u00e1nica (necesita medio material) longitudinal (vibra en la misma direcci\u00f3n que avanza).", tip: "\ud83d\udd27 TRUCO: Sonido = necesita aire/medio para viajar (por eso en el espacio no hay sonido). Luz = no necesita medio." },
  { id: "cn-30", subject: "ciencias", topic: "Medio ambiente", difficulty: "facil", text: "\u00bfQu\u00e9 recurso natural es NO renovable?", options: [{ label: "A", text: "Energ\u00eda solar" }, { label: "B", text: "Petr\u00f3leo" }, { label: "C", text: "Agua" }, { label: "D", text: "Viento" }], correctAnswer: "B", explanation: "El petr\u00f3leo tarda millones de a\u00f1os en formarse, por eso es no renovable.", tip: "\ud83c\udf0d TRUCO: Renovable = se regenera r\u00e1pido (sol, viento, agua). No renovable = se acaba (petr\u00f3leo, gas, carb\u00f3n mineral)." },
  { id: "cn-31", subject: "ciencias", topic: "Biolog\u00eda", difficulty: "facil", text: "\u00bfCu\u00e1l es la funci\u00f3n principal de los gl\u00f3bulos rojos?", options: [{ label: "A", text: "Combatir infecciones" }, { label: "B", text: "Transportar ox\u00edgeno" }, { label: "C", text: "Coagular la sangre" }, { label: "D", text: "Producir anticuerpos" }], correctAnswer: "B", explanation: "Los gl\u00f3bulos rojos (eritrocitos) transportan ox\u00edgeno mediante la hemoglobina.", tip: "\ud83d\udd2c TRUCO: Rojos = ox\u00edgeno (rojos como la sangre oxigenada). Blancos = defensa. Plaquetas = coagulaci\u00f3n." },
  { id: "cn-32", subject: "ciencias", topic: "Biolog\u00eda", difficulty: "facil", text: "\u00bfQu\u00e9 hormona regula los niveles de az\u00facar en la sangre?", options: [{ label: "A", text: "Adrenalina" }, { label: "B", text: "Insulina" }, { label: "C", text: "Testosterona" }, { label: "D", text: "Tiroxina" }], correctAnswer: "B", explanation: "La insulina (producida por el p\u00e1ncreas) permite que las c\u00e9lulas absorban glucosa de la sangre.", tip: "\ud83d\udd2c TRUCO: Insulina = az\u00facar en sangre. Si falta insulina = diabetes. El p\u00e1ncreas la produce." },
  { id: "cn-33", subject: "ciencias", topic: "Qu\u00edmica", difficulty: "medio", text: "\u00bfQu\u00e9 elemento qu\u00edmico tiene el s\u00edmbolo 'Fe'?", options: [{ label: "A", text: "Fl\u00faor" }, { label: "B", text: "F\u00f3sforo" }, { label: "C", text: "Hierro" }, { label: "D", text: "Fermio" }], correctAnswer: "C", explanation: "Fe viene del lat\u00edn 'Ferrum' que significa hierro.", tip: "\ud83e\uddea TRUCO: Muchos s\u00edmbolos vienen del lat\u00edn: Fe=hierro(Ferrum), Au=oro(Aurum), Ag=plata(Argentum), Cu=cobre(Cuprum)." },
  { id: "cn-34", subject: "ciencias", topic: "F\u00edsica", difficulty: "medio", text: "Un objeto cae libremente. \u00bfQu\u00e9 le pasa a su velocidad?", options: [{ label: "A", text: "Permanece constante" }, { label: "B", text: "Aumenta uniformemente" }, { label: "C", text: "Disminuye" }, { label: "D", text: "Var\u00eda aleatoriamente" }], correctAnswer: "B", explanation: "En ca\u00edda libre, la velocidad aumenta 9.8 m/s cada segundo debido a la gravedad.", tip: "\ud83d\udd27 TRUCO: Gravedad = 9.8 m/s\u00b2. Cada segundo que cae, el objeto va 9.8 m/s m\u00e1s r\u00e1pido." },
  { id: "cn-35", subject: "ciencias", topic: "Biolog\u00eda", difficulty: "medio", text: "\u00bfCu\u00e1l es el proceso por el cual las c\u00e9lulas se dividen para crecer y reparar tejidos?", options: [{ label: "A", text: "Meiosis" }, { label: "B", text: "Mitosis" }, { label: "C", text: "Fotos\u00edntesis" }, { label: "D", text: "Fermentaci\u00f3n" }], correctAnswer: "B", explanation: "La mitosis produce 2 c\u00e9lulas id\u00e9nticas. Es para crecimiento y reparaci\u00f3n.", tip: "\ud83d\udd2c TRUCO: MItosis = MIsmas c\u00e9lulas (2 iguales, para crecer). MEIosis = MEdia (4 c\u00e9lulas con la mitad de cromosomas, para reproducci\u00f3n)." },
  { id: "cn-36", subject: "ciencias", topic: "Qu\u00edmica", difficulty: "facil", text: "\u00bfQu\u00e9 le pasa a la materia cuando se calienta?", options: [{ label: "A", text: "Se contrae" }, { label: "B", text: "Se expande" }, { label: "C", text: "No cambia" }, { label: "D", text: "Pierde masa" }], correctAnswer: "B", explanation: "Al calentar, las part\u00edculas se mueven m\u00e1s r\u00e1pido y se separan, causando expansi\u00f3n.", tip: "\ud83e\uddea TRUCO: Calor = part\u00edculas m\u00e1s r\u00e1pidas = m\u00e1s espacio = expansi\u00f3n. Por eso los rieles del tren tienen espacios." },
  { id: "cn-37", subject: "ciencias", topic: "Medio ambiente", difficulty: "medio", text: "\u00bfCu\u00e1l es la principal causa de la deforestaci\u00f3n en Colombia?", options: [{ label: "A", text: "Incendios naturales" }, { label: "B", text: "Expansi\u00f3n de la frontera agr\u00edcola y ganadera" }, { label: "C", text: "Terremotos" }, { label: "D", text: "Inundaciones" }], correctAnswer: "B", explanation: "La principal causa es la expansi\u00f3n de la ganader\u00eda y agricultura, que requiere talar bosques para cultivar o criar ganado.", tip: "\ud83c\udf0d TRUCO: Deforestaci\u00f3n en Colombia: 70%+ es por ganader\u00eda extensiva. Es un problema de uso del suelo." },
  { id: "cn-38", subject: "ciencias", topic: "F\u00edsica", difficulty: "facil", text: "\u00bfCu\u00e1l es la ley de la conservaci\u00f3n de la energ\u00eda?", options: [{ label: "A", text: "La energ\u00eda se crea y se destruye" }, { label: "B", text: "La energ\u00eda no se crea ni se destruye, solo se transforma" }, { label: "C", text: "La energ\u00eda solo se puede crear" }, { label: "D", text: "La energ\u00eda siempre disminuye" }], correctAnswer: "B", explanation: "La primera ley de la termodin\u00e1mica: la energ\u00eda se transforma pero la cantidad total permanece constante.", tip: "\ud83d\udd27 TRUCO: La energ\u00eda es como el dinero: puedes cambiarlo de forma (pesos a d\u00f3lares) pero no crearlo de la nada." },
  { id: "cn-39", subject: "ciencias", topic: "Biolog\u00eda", difficulty: "medio", text: "\u00bfQu\u00e9 \u00f3rgano produce la bilis para ayudar en la digesti\u00f3n de grasas?", options: [{ label: "A", text: "El est\u00f3mago" }, { label: "B", text: "El p\u00e1ncreas" }, { label: "C", text: "El h\u00edgado" }, { label: "D", text: "El intestino delgado" }], correctAnswer: "C", explanation: "El h\u00edgado produce la bilis, que se almacena en la ves\u00edcula biliar y ayuda a descomponer las grasas.", tip: "\ud83d\udd2c TRUCO: H\u00edgado = f\u00e1brica de bilis + desintoxicaci\u00f3n. P\u00e1ncreas = insulina + jugos digestivos." },
  { id: "cn-40", subject: "ciencias", topic: "Qu\u00edmica", difficulty: "facil", text: "\u00bfQu\u00e9 tipo de mezcla es el agua con sal?", options: [{ label: "A", text: "Mezcla heterog\u00e9nea" }, { label: "B", text: "Mezcla homog\u00e9nea (soluci\u00f3n)" }, { label: "C", text: "Compuesto qu\u00edmico" }, { label: "D", text: "Elemento puro" }], correctAnswer: "B", explanation: "Es homog\u00e9nea porque la sal se disuelve completamente y no se ven las partes por separado.", tip: "\ud83e\uddea TRUCO: HOMOg\u00e9nea = se ve IGUAL en todas partes (como agua con sal). HETEROg\u00e9nea = se ven partes distintas (como ensalada)." },
  { id: "cn-41", subject: "ciencias", topic: "Biolog\u00eda", difficulty: "medio", text: "\u00bfQu\u00e9 estructura del ADN descubrieron Watson y Crick?", options: [{ label: "A", text: "Cadena simple" }, { label: "B", text: "Doble h\u00e9lice" }, { label: "C", text: "Triple h\u00e9lice" }, { label: "D", text: "Estructura circular" }], correctAnswer: "B", explanation: "Watson y Crick descubrieron en 1953 que el ADN tiene forma de doble h\u00e9lice (escalera retorcida).", tip: "\ud83d\udd2c TRUCO: ADN = doble h\u00e9lice = escalera de caracol. Los 'pelda\u00f1os' son las bases nitrogenadas (A-T, G-C)." },
  { id: "cn-42", subject: "ciencias", topic: "F\u00edsica", difficulty: "facil", text: "\u00bfQu\u00e9 sucede cuando dos fuerzas iguales y opuestas act\u00faan sobre un objeto?", options: [{ label: "A", text: "El objeto acelera" }, { label: "B", text: "El objeto permanece en equilibrio" }, { label: "C", text: "El objeto gira" }, { label: "D", text: "El objeto se destruye" }], correctAnswer: "B", explanation: "Fuerzas iguales y opuestas se cancelan, produciendo equilibrio (fuerza neta = 0).", tip: "\ud83d\udd27 TRUCO: Equilibrio = fuerzas se cancelan. Un libro sobre la mesa est\u00e1 en equilibrio: gravedad hacia abajo = mesa empuja hacia arriba." },
  { id: "cn-43", subject: "ciencias", topic: "Medio ambiente", difficulty: "facil", text: "\u00bfQu\u00e9 es la biodegradaci\u00f3n?", options: [{ label: "A", text: "La destrucci\u00f3n de ecosistemas" }, { label: "B", text: "La descomposici\u00f3n natural de materiales por organismos vivos" }, { label: "C", text: "La contaminaci\u00f3n del aire" }, { label: "D", text: "La erosi\u00f3n del suelo" }], correctAnswer: "B", explanation: "La biodegradaci\u00f3n es cuando bacterias, hongos y otros organismos descomponen materiales org\u00e1nicos naturalmente.", tip: "\ud83c\udf0d TRUCO: BIO=vida + DEGRADACI\u00d3N=descomponer. Los microorganismos 'comen' los materiales org\u00e1nicos." },
  { id: "cn-44", subject: "ciencias", topic: "Biolog\u00eda", difficulty: "facil", text: "\u00bfCu\u00e1l es la funci\u00f3n del sistema nervioso?", options: [{ label: "A", text: "Transportar ox\u00edgeno" }, { label: "B", text: "Coordinar las funciones del cuerpo mediante se\u00f1ales el\u00e9ctricas" }, { label: "C", text: "Producir hormonas" }, { label: "D", text: "Digerir alimentos" }], correctAnswer: "B", explanation: "El sistema nervioso (cerebro, m\u00e9dula, nervios) coordina TODAS las funciones mediante impulsos el\u00e9ctricos.", tip: "\ud83d\udd2c TRUCO: Sistema nervioso = red el\u00e9ctrica del cuerpo. El cerebro es la 'computadora central'." },
  { id: "cn-45", subject: "ciencias", topic: "Qu\u00edmica", difficulty: "facil", text: "\u00bfCu\u00e1ntos \u00e1tomos de hidr\u00f3geno hay en una mol\u00e9cula de metano (CH\u2084)?", options: [{ label: "A", text: "1" }, { label: "B", text: "2" }, { label: "C", text: "3" }, { label: "D", text: "4" }], correctAnswer: "D", explanation: "CH\u2084: C=1 carbono, H\u2084=4 hidr\u00f3genos. El sub\u00edndice indica la cantidad de \u00e1tomos.", tip: "\ud83e\uddea TRUCO: El n\u00famero peque\u00f1o abajo (sub\u00edndice) indica CU\u00c1NTOS \u00e1tomos de ese elemento hay. Sin n\u00famero = 1." },
  { id: "cn-46", subject: "ciencias", topic: "F\u00edsica", difficulty: "medio", text: "\u00bfQu\u00e9 es la presi\u00f3n atmosf\u00e9rica?", options: [{ label: "A", text: "La presi\u00f3n del agua en el mar" }, { label: "B", text: "El peso del aire de la atm\u00f3sfera sobre la superficie terrestre" }, { label: "C", text: "La presi\u00f3n dentro de un gas cerrado" }, { label: "D", text: "La fuerza del viento" }], correctAnswer: "B", explanation: "La presi\u00f3n atmosf\u00e9rica es el peso de la columna de aire que est\u00e1 sobre nosotros.", tip: "\ud83d\udd27 TRUCO: Vivimos en el fondo de un 'oc\u00e9ano de aire'. Ese aire pesa y nos presiona = presi\u00f3n atmosf\u00e9rica." },
  { id: "cn-47", subject: "ciencias", topic: "Biolog\u00eda", difficulty: "medio", text: "\u00bfCu\u00e1l es la diferencia entre bacterias y virus?", options: [{ label: "A", text: "Las bacterias son m\u00e1s peque\u00f1as" }, { label: "B", text: "Los virus no son c\u00e9lulas y necesitan un hu\u00e9sped para reproducirse" }, { label: "C", text: "Las bacterias siempre causan enfermedades" }, { label: "D", text: "Los virus tienen n\u00facleo" }], correctAnswer: "B", explanation: "Los virus no son seres vivos por s\u00ed solos: necesitan invadir c\u00e9lulas para reproducirse. Las bacterias s\u00ed son c\u00e9lulas independientes.", tip: "\ud83d\udd2c TRUCO: Bacteria = ser vivo independiente (c\u00e9lula). Virus = NO es c\u00e9lula, es un 'par\u00e1sito gen\u00e9tico' que necesita c\u00e9lulas para vivir." },
  { id: "cn-48", subject: "ciencias", topic: "Qu\u00edmica", difficulty: "medio", text: "\u00bfQu\u00e9 tipo de reacci\u00f3n es: 2H\u2082 + O\u2082 \u2192 2H\u2082O?", options: [{ label: "A", text: "Descomposici\u00f3n" }, { label: "B", text: "S\u00edntesis (combinaci\u00f3n)" }, { label: "C", text: "Sustituci\u00f3n" }, { label: "D", text: "Neutralizaci\u00f3n" }], correctAnswer: "B", explanation: "Dos o m\u00e1s sustancias se combinan para formar una nueva: es una reacci\u00f3n de s\u00edntesis.", tip: "\ud83e\uddea TRUCO: S\u00edntesis = varios \u2192 uno. Descomposici\u00f3n = uno \u2192 varios. Son opuestas." },
  { id: "cn-49", subject: "ciencias", topic: "F\u00edsica", difficulty: "medio", text: "\u00bfCu\u00e1l es la diferencia entre masa y peso?", options: [{ label: "A", text: "Son lo mismo" }, { label: "B", text: "La masa es la cantidad de materia; el peso es la fuerza gravitacional sobre esa masa" }, { label: "C", text: "El peso se mide en kilogramos" }, { label: "D", text: "La masa cambia seg\u00fan el lugar" }], correctAnswer: "B", explanation: "Masa = cu\u00e1nta materia tienes (no cambia). Peso = fuerza de gravedad sobre tu masa (cambia seg\u00fan el planeta).", tip: "\ud83d\udd27 TRUCO: Tu MASA es igual en la Tierra y la Luna. Tu PESO en la Luna es 1/6 del de la Tierra porque hay menos gravedad." },
  { id: "cn-50", subject: "ciencias", topic: "Medio ambiente", difficulty: "medio", text: "\u00bfCu\u00e1l es el principal efecto del calentamiento global en los oc\u00e9anos?", options: [{ label: "A", text: "Los oc\u00e9anos se congelan" }, { label: "B", text: "Aumenta el nivel del mar por derretimiento de glaciares y expansi\u00f3n t\u00e9rmica" }, { label: "C", text: "Los oc\u00e9anos se vac\u00edan" }, { label: "D", text: "El agua se vuelve dulce" }], correctAnswer: "B", explanation: "El calentamiento derrite glaciares y expande el agua, elevando el nivel del mar.", tip: "\ud83c\udf0d TRUCO: Calentamiento \u2192 derretimiento de hielo + agua se expande al calentarse \u2192 nivel del mar sube." },
  { id: "soc-1", subject: "sociales", topic: "Historia de Colombia", difficulty: "facil", text: "\u00bfEn qu\u00e9 a\u00f1o se proclam\u00f3 la independencia de Colombia?", options: [{ label: "A", text: "1810" }, { label: "B", text: "1819" }, { label: "C", text: "1821" }, { label: "D", text: "1830" }], correctAnswer: "A", explanation: "El 20 de julio de 1810 se dio el grito de independencia en Bogot\u00e1. La independencia definitiva fue en 1819 con la Batalla de Boyac\u00e1.", tip: "\ud83d\udcc5 TRUCO: 1810 = grito de independencia. 1819 = Batalla de Boyac\u00e1 (independencia definitiva). Ambas fechas son importantes." },
  { id: "soc-2", subject: "sociales", topic: "Historia de Colombia", difficulty: "facil", text: "\u00bfQui\u00e9n fue el libertador de Colombia?", options: [{ label: "A", text: "Antonio Nari\u00f1o" }, { label: "B", text: "Sim\u00f3n Bol\u00edvar" }, { label: "C", text: "Francisco de Paula Santander" }, { label: "D", text: "Rafael N\u00fa\u00f1ez" }], correctAnswer: "B", explanation: "Sim\u00f3n Bol\u00edvar es conocido como 'El Libertador' por liderar la independencia de varias naciones sudamericanas.", tip: "\ud83d\udcc5 TRUCO: Bol\u00edvar = El Libertador. Santander = El Hombre de las Leyes. Nari\u00f1o = tradujo los Derechos del Hombre." },
  { id: "soc-3", subject: "sociales", topic: "Constituci\u00f3n pol\u00edtica", difficulty: "facil", text: "\u00bfEn qu\u00e9 a\u00f1o se promulg\u00f3 la actual Constituci\u00f3n de Colombia?", options: [{ label: "A", text: "1886" }, { label: "B", text: "1991" }, { label: "C", text: "1810" }, { label: "D", text: "2000" }], correctAnswer: "B", explanation: "La Constituci\u00f3n actual es de 1991. Reemplaz\u00f3 la de 1886.", tip: "\ud83d\udcc5 TRUCO: 1886 = constituci\u00f3n anterior. 1991 = constituci\u00f3n actual (la que rige hoy). Es una de las preguntas m\u00e1s frecuentes del ICFES." },
  { id: "soc-4", subject: "sociales", topic: "Constituci\u00f3n pol\u00edtica", difficulty: "facil", text: "Seg\u00fan la Constituci\u00f3n de 1991, \u00bfcu\u00e1ntos departamentos tiene Colombia?", options: [{ label: "A", text: "28" }, { label: "B", text: "30" }, { label: "C", text: "32" }, { label: "D", text: "34" }], correctAnswer: "C", explanation: "Colombia tiene 32 departamentos y un Distrito Capital (Bogot\u00e1).", tip: "\ud83d\udcc5 TRUCO: 32 departamentos + 1 Distrito Capital = la organizaci\u00f3n territorial de Colombia." },
  { id: "soc-5", subject: "sociales", topic: "Constituci\u00f3n pol\u00edtica", difficulty: "facil", text: "\u00bfCu\u00e1les son las tres ramas del poder p\u00fablico en Colombia?", options: [{ label: "A", text: "Militar, civil y religiosa" }, { label: "B", text: "Ejecutiva, legislativa y judicial" }, { label: "C", text: "Municipal, departamental y nacional" }, { label: "D", text: "Presidencial, parlamentaria y judicial" }], correctAnswer: "B", explanation: "Las tres ramas son: Ejecutiva (Presidente), Legislativa (Congreso) y Judicial (Cortes/tribunales).", tip: "\ud83d\udccb TRUCO: Ejecutiva = EJECUTA (Presidente hace). Legislativa = LEGISLA (Congreso hace leyes). Judicial = JUZGA (Cortes aplican justicia)." },
  { id: "soc-6", subject: "sociales", topic: "Constituci\u00f3n pol\u00edtica", difficulty: "facil", text: "\u00bfCu\u00e1ntos a\u00f1os dura el per\u00edodo presidencial en Colombia?", options: [{ label: "A", text: "2 a\u00f1os" }, { label: "B", text: "4 a\u00f1os" }, { label: "C", text: "5 a\u00f1os" }, { label: "D", text: "6 a\u00f1os" }], correctAnswer: "B", explanation: "El per\u00edodo presidencial en Colombia es de 4 a\u00f1os, sin reelecci\u00f3n inmediata (seg\u00fan la reforma de 2015).", tip: "\ud83d\udccb TRUCO: Presidente = 4 a\u00f1os. Gobernadores y alcaldes = 4 a\u00f1os. Congresistas = 4 a\u00f1os." },
  { id: "soc-7", subject: "sociales", topic: "Geograf\u00eda", difficulty: "facil", text: "\u00bfCu\u00e1les son los dos oc\u00e9anos que ba\u00f1an las costas de Colombia?", options: [{ label: "A", text: "Atl\u00e1ntico y Pac\u00edfico" }, { label: "B", text: "Pac\u00edfico e \u00cdndico" }, { label: "C", text: "Atl\u00e1ntico e \u00cdndico" }, { label: "D", text: "\u00c1rtico y Pac\u00edfico" }], correctAnswer: "A", explanation: "Colombia tiene costas en el Oc\u00e9ano Atl\u00e1ntico (Mar Caribe) y en el Oc\u00e9ano Pac\u00edfico.", tip: "\ud83c\udf0e TRUCO: Colombia es el \u00daNICO pa\u00eds de Sudam\u00e9rica con costas en AMBOS oc\u00e9anos. Es un dato clave." },
  { id: "soc-8", subject: "sociales", topic: "Geograf\u00eda", difficulty: "facil", text: "\u00bfCu\u00e1l es el r\u00edo m\u00e1s importante de Colombia?", options: [{ label: "A", text: "R\u00edo Amazonas" }, { label: "B", text: "R\u00edo Cauca" }, { label: "C", text: "R\u00edo Magdalena" }, { label: "D", text: "R\u00edo Orinoco" }], correctAnswer: "C", explanation: "El r\u00edo Magdalena es el m\u00e1s importante: recorre 1.540 km y ha sido la principal arteria fluvial del pa\u00eds.", tip: "\ud83c\udf0e TRUCO: Magdalena = r\u00edo m\u00e1s importante por navegaci\u00f3n e historia. Amazonas = el m\u00e1s caudaloso del mundo (pasa por Colombia al sur)." },
  { id: "soc-9", subject: "sociales", topic: "Geograf\u00eda", difficulty: "facil", text: "\u00bfEn cu\u00e1ntas regiones naturales se divide Colombia?", options: [{ label: "A", text: "4" }, { label: "B", text: "5" }, { label: "C", text: "6" }, { label: "D", text: "7" }], correctAnswer: "C", explanation: "Las 6 regiones naturales son: Andina, Caribe, Pac\u00edfica, Orinoqu\u00eda, Amazon\u00eda e Insular.", tip: "\ud83c\udf0e TRUCO: Memoriza: ACAPOI (Andina, Caribe, Amazon\u00eda, Pac\u00edfica, Orinoqu\u00eda, Insular)." },
  { id: "soc-10", subject: "sociales", topic: "Econom\u00eda b\u00e1sica", difficulty: "facil", text: "\u00bfQu\u00e9 es la inflaci\u00f3n?", options: [{ label: "A", text: "La disminuci\u00f3n de los precios" }, { label: "B", text: "El aumento generalizado y sostenido de los precios" }, { label: "C", text: "El aumento del empleo" }, { label: "D", text: "La producci\u00f3n de m\u00e1s dinero" }], correctAnswer: "B", explanation: "Inflaci\u00f3n = los precios suben de manera generalizada. Tu dinero compra menos cosas.", tip: "\ud83d\udcb0 TRUCO: Inflaci\u00f3n = tu plata vale MENOS. Si antes compraba 10 huevos con $5.000 y ahora solo 8, hay inflaci\u00f3n." },
  { id: "soc-11", subject: "sociales", topic: "Econom\u00eda b\u00e1sica", difficulty: "facil", text: "\u00bfQu\u00e9 es el PIB?", options: [{ label: "A", text: "El presupuesto del gobierno" }, { label: "B", text: "El Producto Interno Bruto: valor total de bienes y servicios producidos en un pa\u00eds" }, { label: "C", text: "La deuda externa del pa\u00eds" }, { label: "D", text: "Los impuestos recaudados" }], correctAnswer: "B", explanation: "PIB = todo lo que produce un pa\u00eds en un a\u00f1o. Es la medida principal de la econom\u00eda.", tip: "\ud83d\udcb0 TRUCO: PIB = la 'nota' de la econom\u00eda de un pa\u00eds. M\u00e1s PIB = econom\u00eda m\u00e1s grande." },
  { id: "soc-12", subject: "sociales", topic: "Historia de Colombia", difficulty: "medio", text: "\u00bfQu\u00e9 fue la Violencia en Colombia (1948-1958)?", options: [{ label: "A", text: "Una guerra contra otro pa\u00eds" }, { label: "B", text: "Un per\u00edodo de conflicto bipartidista entre liberales y conservadores" }, { label: "C", text: "Una revoluci\u00f3n industrial" }, { label: "D", text: "Una epidemia" }], correctAnswer: "B", explanation: "La Violencia fue un per\u00edodo de guerra civil entre los partidos Liberal y Conservador que dej\u00f3 m\u00e1s de 200.000 muertos.", tip: "\ud83d\udcc5 TRUCO: La Violencia (con may\u00fascula) = 1948-1958 = conflicto Liberal vs. Conservador. Se inici\u00f3 tras el asesinato de Jorge Eli\u00e9cer Gait\u00e1n." },
  { id: "soc-13", subject: "sociales", topic: "Historia de Colombia", difficulty: "medio", text: "\u00bfQu\u00e9 evento desencaden\u00f3 el Bogotazo en 1948?", options: [{ label: "A", text: "Una crisis econ\u00f3mica" }, { label: "B", text: "El asesinato de Jorge Eli\u00e9cer Gait\u00e1n" }, { label: "C", text: "Un terremoto en Bogot\u00e1" }, { label: "D", text: "Una elecci\u00f3n presidencial fraudulenta" }], correctAnswer: "B", explanation: "El 9 de abril de 1948, el asesinato del l\u00edder liberal Jorge Eli\u00e9cer Gait\u00e1n provoc\u00f3 una revuelta popular masiva conocida como el Bogotazo.", tip: "\ud83d\udcc5 TRUCO: Gait\u00e1n = l\u00edder popular liberal. Su muerte = Bogotazo = inicio de La Violencia." },
  { id: "soc-14", subject: "sociales", topic: "Constituci\u00f3n pol\u00edtica", difficulty: "facil", text: "\u00bfQu\u00e9 es la tutela en Colombia?", options: [{ label: "A", text: "Un tipo de impuesto" }, { label: "B", text: "Un mecanismo para proteger los derechos fundamentales de las personas" }, { label: "C", text: "Un partido pol\u00edtico" }, { label: "D", text: "Un tipo de elecci\u00f3n" }], correctAnswer: "B", explanation: "La acci\u00f3n de tutela (art\u00edculo 86) es un mecanismo r\u00e1pido para proteger derechos fundamentales cuando son vulnerados.", tip: "\ud83d\udccb TRUCO: Tutela = protecci\u00f3n R\u00c1PIDA de derechos fundamentales. Cualquier persona puede interponerla, sin necesidad de abogado." },
  { id: "soc-15", subject: "sociales", topic: "Constituci\u00f3n pol\u00edtica", difficulty: "facil", text: "\u00bfCu\u00e1les son los derechos fundamentales seg\u00fan la Constituci\u00f3n de 1991?", options: [{ label: "A", text: "Solo el derecho a la propiedad" }, { label: "B", text: "Vida, libertad, igualdad, intimidad, libre desarrollo de la personalidad, entre otros" }, { label: "C", text: "Solo el derecho al trabajo" }, { label: "D", text: "Solo los derechos econ\u00f3micos" }], correctAnswer: "B", explanation: "Los derechos fundamentales incluyen vida, libertad, igualdad, intimidad, debido proceso, entre muchos otros (T\u00edtulo II).", tip: "\ud83d\udccb TRUCO: Los derechos fundamentales est\u00e1n en los art\u00edculos 11 al 41 de la Constituci\u00f3n. El m\u00e1s importante: derecho a la VIDA (art. 11)." },
  { id: "soc-16", subject: "sociales", topic: "Geograf\u00eda", difficulty: "medio", text: "\u00bfCu\u00e1l es el pico m\u00e1s alto de Colombia?", options: [{ label: "A", text: "Nevado del Ruiz" }, { label: "B", text: "Pico Crist\u00f3bal Col\u00f3n" }, { label: "C", text: "Nevado del Huila" }, { label: "D", text: "Cerro Taman\u00e1" }], correctAnswer: "B", explanation: "El Pico Crist\u00f3bal Col\u00f3n (5.775 m) en la Sierra Nevada de Santa Marta es el punto m\u00e1s alto de Colombia.", tip: "\ud83c\udf0e TRUCO: Sierra Nevada de Santa Marta = la monta\u00f1a costera m\u00e1s alta del mundo. Tiene dos picos: Col\u00f3n y Bol\u00edvar (5.775 m ambos)." },
  { id: "soc-17", subject: "sociales", topic: "Econom\u00eda b\u00e1sica", difficulty: "facil", text: "\u00bfQu\u00e9 es la oferta y la demanda?", options: [{ label: "A", text: "Dos tipos de impuestos" }, { label: "B", text: "La cantidad de producto disponible (oferta) y la cantidad que la gente quiere comprar (demanda)" }, { label: "C", text: "Tipos de empresas" }, { label: "D", text: "Formas de gobierno" }], correctAnswer: "B", explanation: "Oferta = lo que venden los productores. Demanda = lo que quieren comprar los consumidores.", tip: "\ud83d\udcb0 TRUCO: Mucha demanda + poca oferta = precio SUBE. Poca demanda + mucha oferta = precio BAJA. Es la ley b\u00e1sica del mercado." },
  { id: "soc-18", subject: "sociales", topic: "Historia de Colombia", difficulty: "facil", text: "\u00bfCu\u00e1l fue el nombre del territorio que hoy es Colombia durante la colonia espa\u00f1ola?", options: [{ label: "A", text: "Nueva Espa\u00f1a" }, { label: "B", text: "Nueva Granada" }, { label: "C", text: "R\u00edo de la Plata" }, { label: "D", text: "Alto Per\u00fa" }], correctAnswer: "B", explanation: "El Virreinato de la Nueva Granada comprend\u00eda los territorios actuales de Colombia, Ecuador, Panam\u00e1 y Venezuela.", tip: "\ud83d\udcc5 TRUCO: Nueva Granada = Colombia colonial. Nueva Espa\u00f1a = M\u00e9xico. R\u00edo de la Plata = Argentina." },
  { id: "soc-19", subject: "sociales", topic: "Constituci\u00f3n pol\u00edtica", difficulty: "medio", text: "\u00bfQu\u00e9 organismo se encarga de vigilar la correcta utilizaci\u00f3n de los recursos p\u00fablicos?", options: [{ label: "A", text: "La Fiscal\u00eda" }, { label: "B", text: "La Contralor\u00eda General" }, { label: "C", text: "La Procuradur\u00eda" }, { label: "D", text: "La Defensor\u00eda del Pueblo" }], correctAnswer: "B", explanation: "La Contralor\u00eda vigila el uso de los recursos p\u00fablicos (dinero del Estado). La Procuradur\u00eda vigila a los funcionarios.", tip: "\ud83d\udccb TRUCO: Contralor\u00eda = CONTROLA el dinero p\u00fablico. Procuradur\u00eda = vigila el comportamiento de los funcionarios. Defensor\u00eda = defiende derechos ciudadanos." },
  { id: "soc-20", subject: "sociales", topic: "Geograf\u00eda", difficulty: "facil", text: "\u00bfQu\u00e9 pa\u00eds NO limita con Colombia?", options: [{ label: "A", text: "Venezuela" }, { label: "B", text: "Brasil" }, { label: "C", text: "Chile" }, { label: "D", text: "Per\u00fa" }], correctAnswer: "C", explanation: "Colombia limita con Venezuela, Brasil, Per\u00fa, Ecuador y Panam\u00e1. Chile est\u00e1 mucho m\u00e1s al sur.", tip: "\ud83c\udf0e TRUCO: Vecinos de Colombia: Venezuela, Brasil, Per\u00fa, Ecuador, Panam\u00e1. Memoriza: VeBraPeEcPa." },
  { id: "soc-21", subject: "sociales", topic: "Historia de Colombia", difficulty: "medio", text: "\u00bfQu\u00e9 fue el Frente Nacional (1958-1974)?", options: [{ label: "A", text: "Un partido pol\u00edtico" }, { label: "B", text: "Un acuerdo para alternar el poder entre liberales y conservadores cada 4 a\u00f1os" }, { label: "C", text: "Una alianza militar" }, { label: "D", text: "Un tratado comercial" }], correctAnswer: "B", explanation: "El Frente Nacional fue un pacto donde liberales y conservadores se turnaban la presidencia para terminar La Violencia.", tip: "\ud83d\udcc5 TRUCO: Frente Nacional = paz entre partidos, pero excluy\u00f3 a otros movimientos pol\u00edticos. Dur\u00f3 16 a\u00f1os (4 per\u00edodos de 4 a\u00f1os)." },
  { id: "soc-22", subject: "sociales", topic: "Constituci\u00f3n pol\u00edtica", difficulty: "facil", text: "\u00bfA partir de qu\u00e9 edad pueden votar los colombianos?", options: [{ label: "A", text: "16 a\u00f1os" }, { label: "B", text: "18 a\u00f1os" }, { label: "C", text: "21 a\u00f1os" }, { label: "D", text: "25 a\u00f1os" }], correctAnswer: "B", explanation: "En Colombia se puede votar a partir de los 18 a\u00f1os de edad.", tip: "\ud83d\udccb TRUCO: 18 a\u00f1os = mayor\u00eda de edad = puedes votar, firmar contratos, etc." },
  { id: "soc-23", subject: "sociales", topic: "Econom\u00eda b\u00e1sica", difficulty: "medio", text: "\u00bfQui\u00e9n es el encargado de la pol\u00edtica monetaria en Colombia?", options: [{ label: "A", text: "El Presidente" }, { label: "B", text: "El Ministerio de Hacienda" }, { label: "C", text: "El Banco de la Rep\u00fablica" }, { label: "D", text: "La Contralor\u00eda" }], correctAnswer: "C", explanation: "El Banco de la Rep\u00fablica es el banco central de Colombia, encargado de la pol\u00edtica monetaria, controlar la inflaci\u00f3n y emitir moneda.", tip: "\ud83d\udcb0 TRUCO: Banco de la Rep\u00fablica = banco de los bancos. Controla cu\u00e1nto dinero circula y las tasas de inter\u00e9s." },
  { id: "soc-24", subject: "sociales", topic: "Historia de Colombia", difficulty: "facil", text: "\u00bfCu\u00e1ndo se firm\u00f3 el acuerdo de paz con las FARC?", options: [{ label: "A", text: "2012" }, { label: "B", text: "2016" }, { label: "C", text: "2018" }, { label: "D", text: "2020" }], correctAnswer: "B", explanation: "El acuerdo de paz se firm\u00f3 en noviembre de 2016 en el Teatro Col\u00f3n de Bogot\u00e1.", tip: "\ud83d\udcc5 TRUCO: 2016 = firma del acuerdo de paz. 2012 = inicio de las negociaciones en La Habana." },
  { id: "soc-25", subject: "sociales", topic: "Geograf\u00eda", difficulty: "facil", text: "\u00bfCu\u00e1l es la capital del departamento de Antioquia?", options: [{ label: "A", text: "Bucaramanga" }, { label: "B", text: "Medell\u00edn" }, { label: "C", text: "Cali" }, { label: "D", text: "Barranquilla" }], correctAnswer: "B", explanation: "Medell\u00edn es la capital de Antioquia y la segunda ciudad m\u00e1s grande de Colombia.", tip: "\ud83c\udf0e TRUCO: Memoriza las capitales principales: Antioquia=Medell\u00edn, Valle=Cali, Atl\u00e1ntico=Barranquilla, Santander=Bucaramanga." },
  { id: "soc-26", subject: "sociales", topic: "Constituci\u00f3n pol\u00edtica", difficulty: "medio", text: "\u00bfQu\u00e9 es un Estado Social de Derecho?", options: [{ label: "A", text: "Un Estado donde el presidente tiene poder absoluto" }, { label: "B", text: "Un Estado que garantiza derechos fundamentales y busca la justicia social" }, { label: "C", text: "Un Estado sin leyes" }, { label: "D", text: "Un Estado gobernado por militares" }], correctAnswer: "B", explanation: "Un Estado Social de Derecho combina el imperio de la ley con la obligaci\u00f3n del Estado de garantizar derechos y bienestar social.", tip: "\ud83d\udccb TRUCO: SOCIAL = se preocupa por la gente. DE DERECHO = gobernado por leyes, no por caprichos." },
  { id: "soc-27", subject: "sociales", topic: "Geograf\u00eda", difficulty: "facil", text: "\u00bfCu\u00e1l es la regi\u00f3n m\u00e1s poblada de Colombia?", options: [{ label: "A", text: "Regi\u00f3n Caribe" }, { label: "B", text: "Regi\u00f3n Andina" }, { label: "C", text: "Regi\u00f3n Pac\u00edfica" }, { label: "D", text: "Regi\u00f3n Amaz\u00f3nica" }], correctAnswer: "B", explanation: "La regi\u00f3n Andina concentra m\u00e1s del 70% de la poblaci\u00f3n colombiana, incluyendo Bogot\u00e1, Medell\u00edn y Cali.", tip: "\ud83c\udf0e TRUCO: Regi\u00f3n Andina = la m\u00e1s poblada y econ\u00f3micamente activa. Incluye las 3 ciudades m\u00e1s grandes." },
  { id: "soc-28", subject: "sociales", topic: "Econom\u00eda b\u00e1sica", difficulty: "facil", text: "\u00bfQu\u00e9 son los impuestos?", options: [{ label: "A", text: "Donaciones voluntarias al gobierno" }, { label: "B", text: "Pagos obligatorios que hacen los ciudadanos al Estado para financiar servicios p\u00fablicos" }, { label: "C", text: "Pr\u00e9stamos del gobierno a los ciudadanos" }, { label: "D", text: "Ahorros del gobierno" }], correctAnswer: "B", explanation: "Los impuestos son pagos obligatorios que financian educaci\u00f3n, salud, infraestructura y otros servicios p\u00fablicos.", tip: "\ud83d\udcb0 TRUCO: Impuestos = el precio de vivir en sociedad. IVA = impuesto al consumo. Renta = impuesto a las ganancias." },
  { id: "soc-29", subject: "sociales", topic: "Historia de Colombia", difficulty: "medio", text: "\u00bfQui\u00e9n fue el primer presidente de Colombia (Gran Colombia)?", options: [{ label: "A", text: "Francisco de Paula Santander" }, { label: "B", text: "Sim\u00f3n Bol\u00edvar" }, { label: "C", text: "Tom\u00e1s Cipriano de Mosquera" }, { label: "D", text: "Antonio Nari\u00f1o" }], correctAnswer: "B", explanation: "Sim\u00f3n Bol\u00edvar fue el primer presidente de la Gran Colombia (1819-1830). Santander fue el vicepresidente.", tip: "\ud83d\udcc5 TRUCO: Bol\u00edvar = presidente de la Gran Colombia. Santander = vicepresidente y 'organizador'." },
  { id: "soc-30", subject: "sociales", topic: "Constituci\u00f3n pol\u00edtica", difficulty: "medio", text: "\u00bfQu\u00e9 mecanismos de participaci\u00f3n ciudadana establece la Constituci\u00f3n de 1991?", options: [{ label: "A", text: "Solo el voto" }, { label: "B", text: "Voto, plebiscito, referendo, consulta popular, cabildo abierto, iniciativa legislativa y revocatoria del mandato" }, { label: "C", text: "Solo protestas y marchas" }, { label: "D", text: "Solo peticiones al presidente" }], correctAnswer: "B", explanation: "La Constituci\u00f3n de 1991 establece 7 mecanismos de participaci\u00f3n (art\u00edculo 103).", tip: "\ud83d\udccb TRUCO: Son 7 mecanismos. El m\u00e1s conocido es el VOTO. El m\u00e1s usado despu\u00e9s es la CONSULTA POPULAR." },
  { id: "soc-31", subject: "sociales", topic: "Geograf\u00eda", difficulty: "medio", text: "\u00bfCu\u00e1l es el departamento m\u00e1s grande de Colombia por extensi\u00f3n?", options: [{ label: "A", text: "Antioquia" }, { label: "B", text: "Amazonas" }, { label: "C", text: "Vichada" }, { label: "D", text: "Meta" }], correctAnswer: "B", explanation: "El departamento del Amazonas tiene 109.665 km\u00b2, el m\u00e1s extenso de Colombia.", tip: "\ud83c\udf0e TRUCO: Amazonas = el m\u00e1s GRANDE por territorio. Bogot\u00e1 = la m\u00e1s poblada. Antioquia = el m\u00e1s productivo." },
  { id: "soc-32", subject: "sociales", topic: "Econom\u00eda b\u00e1sica", difficulty: "facil", text: "\u00bfCu\u00e1les son los principales productos de exportaci\u00f3n de Colombia?", options: [{ label: "A", text: "Solo caf\u00e9" }, { label: "B", text: "Petr\u00f3leo, caf\u00e9, carb\u00f3n, flores y banano" }, { label: "C", text: "Solo petr\u00f3leo" }, { label: "D", text: "Solo esmeraldas" }], correctAnswer: "B", explanation: "Colombia exporta principalmente petr\u00f3leo, caf\u00e9, carb\u00f3n, flores, banano, esmeraldas y oro.", tip: "\ud83d\udcb0 TRUCO: Petr\u00f3leo es el #1 en exportaciones. Caf\u00e9 es el m\u00e1s emblem\u00e1tico. Colombia = primer productor mundial de esmeraldas." },
  { id: "soc-33", subject: "sociales", topic: "Historia de Colombia", difficulty: "medio", text: "\u00bfQu\u00e9 cultura precolombina habit\u00f3 la regi\u00f3n de San Agust\u00edn, Huila?", options: [{ label: "A", text: "Los Muiscas" }, { label: "B", text: "Los Taironas" }, { label: "C", text: "La cultura de San Agust\u00edn" }, { label: "D", text: "Los Quimbayas" }], correctAnswer: "C", explanation: "La cultura de San Agust\u00edn dej\u00f3 un impresionante legado de esculturas y tumbas megal\u00edticas en el Huila.", tip: "\ud83d\udcc5 TRUCO: San Agust\u00edn (Huila) = esculturas de piedra. Muiscas = altiplano cundiboyacense. Taironas = Sierra Nevada." },
  { id: "soc-34", subject: "sociales", topic: "Constituci\u00f3n pol\u00edtica", difficulty: "medio", text: "\u00bfQui\u00e9n es el defensor de los derechos humanos en Colombia?", options: [{ label: "A", text: "El Fiscal General" }, { label: "B", text: "El Defensor del Pueblo" }, { label: "C", text: "El Presidente" }, { label: "D", text: "El Procurador" }], correctAnswer: "B", explanation: "El Defensor del Pueblo vela por la promoci\u00f3n y protecci\u00f3n de los derechos humanos.", tip: "\ud83d\udccb TRUCO: Defensor del Pueblo = defiende a los ciudadanos. Procurador = vigila a los funcionarios. Fiscal = investiga delitos." },
  { id: "soc-35", subject: "sociales", topic: "Geograf\u00eda", difficulty: "facil", text: "\u00bfCu\u00e1l es la isla colombiana m\u00e1s grande en el Caribe?", options: [{ label: "A", text: "Providencia" }, { label: "B", text: "San Andr\u00e9s" }, { label: "C", text: "Gorgona" }, { label: "D", text: "Malpelo" }], correctAnswer: "B", explanation: "San Andr\u00e9s es la isla m\u00e1s grande del archipi\u00e9lago de San Andr\u00e9s, Providencia y Santa Catalina.", tip: "\ud83c\udf0e TRUCO: San Andr\u00e9s = Caribe. Gorgona = Pac\u00edfico. Malpelo = Pac\u00edfico (la m\u00e1s lejana)." },
  { id: "soc-36", subject: "sociales", topic: "Historia de Colombia", difficulty: "medio", text: "\u00bfQu\u00e9 signific\u00f3 el 'descubrimiento' de Am\u00e9rica en 1492?", options: [{ label: "A", text: "Crist\u00f3bal Col\u00f3n lleg\u00f3 a un continente ya habitado por pueblos ind\u00edgenas" }, { label: "B", text: "Am\u00e9rica estaba completamente vac\u00eda" }, { label: "C", text: "Los ind\u00edgenas invitaron a los europeos" }, { label: "D", text: "Am\u00e9rica fue creada en 1492" }], correctAnswer: "A", explanation: "Am\u00e9rica ya estaba habitada por millones de personas. El 'descubrimiento' fue el encuentro entre dos mundos.", tip: "\ud83d\udcc5 TRUCO: El ICFES valora la visi\u00f3n cr\u00edtica. No fue un 'descubrimiento' sino un ENCUENTRO entre culturas. Los pueblos ind\u00edgenas ya ten\u00edan civilizaciones avanzadas." },
  { id: "soc-37", subject: "sociales", topic: "Econom\u00eda b\u00e1sica", difficulty: "facil", text: "\u00bfQu\u00e9 es el desempleo?", options: [{ label: "A", text: "Cuando las empresas cierran" }, { label: "B", text: "La proporci\u00f3n de personas en edad de trabajar que buscan empleo y no lo encuentran" }, { label: "C", text: "Cuando nadie trabaja" }, { label: "D", text: "Cuando los salarios son bajos" }], correctAnswer: "B", explanation: "La tasa de desempleo mide el porcentaje de la poblaci\u00f3n activa que no tiene trabajo pero lo busca.", tip: "\ud83d\udcb0 TRUCO: Solo cuentan como desempleados los que BUSCAN trabajo activamente. Un jubilado o estudiante no es 'desempleado'." },
  { id: "soc-38", subject: "sociales", topic: "Constituci\u00f3n pol\u00edtica", difficulty: "medio", text: "\u00bfQu\u00e9 es el habeas corpus?", options: [{ label: "A", text: "Un tipo de impuesto" }, { label: "B", text: "El derecho a que un juez revise la legalidad de una detenci\u00f3n" }, { label: "C", text: "Una ley de comercio" }, { label: "D", text: "Un tipo de elecci\u00f3n" }], correctAnswer: "B", explanation: "El habeas corpus protege contra detenciones ilegales: el detenido tiene derecho a ser llevado ante un juez.", tip: "\ud83d\udccb TRUCO: Habeas corpus = 'que tengas el cuerpo' (en lat\u00edn). Protege tu LIBERTAD contra detenciones arbitrarias." },
  { id: "soc-39", subject: "sociales", topic: "Geograf\u00eda", difficulty: "medio", text: "\u00bfQu\u00e9 es un p\u00e1ramo y por qu\u00e9 es importante?", options: [{ label: "A", text: "Un tipo de desierto sin importancia" }, { label: "B", text: "Un ecosistema de alta monta\u00f1a que produce y regula el agua" }, { label: "C", text: "Una playa tropical" }, { label: "D", text: "Un bosque denso" }], correctAnswer: "B", explanation: "Los p\u00e1ramos son ecosistemas de alta monta\u00f1a (3.000-5.000 m) que act\u00faan como f\u00e1bricas de agua. Colombia tiene el 50% de los p\u00e1ramos del mundo.", tip: "\ud83c\udf0e TRUCO: Colombia = 50% de los p\u00e1ramos del mundo. Los p\u00e1ramos son las F\u00c1BRICAS DE AGUA. El p\u00e1ramo de Sumapaz (cerca de Bogot\u00e1) es el m\u00e1s grande del mundo." },
  { id: "soc-40", subject: "sociales", topic: "Historia de Colombia", difficulty: "medio", text: "\u00bfQu\u00e9 cultura ind\u00edgena colombiana era famosa por su orfebrer\u00eda en oro?", options: [{ label: "A", text: "Los Taironas" }, { label: "B", text: "Los Quimbayas" }, { label: "C", text: "Los Muiscas" }, { label: "D", text: "Los Way\u00fau" }], correctAnswer: "B", explanation: "Los Quimbayas fueron reconocidos por su excepcional trabajo en orfebrer\u00eda. El poporo Quimbaya es una de las piezas m\u00e1s famosas del Museo del Oro.", tip: "\ud83d\udcc5 TRUCO: Quimbayas = ORO (orfebrer\u00eda). Muiscas = ceremonia de El Dorado. Taironas = Ciudad Perdida." },
  { id: "soc-41", subject: "sociales", topic: "Econom\u00eda b\u00e1sica", difficulty: "facil", text: "\u00bfQu\u00e9 es el IVA?", options: [{ label: "A", text: "Un tipo de ahorro" }, { label: "B", text: "El Impuesto al Valor Agregado que se cobra sobre bienes y servicios" }, { label: "C", text: "Una tarjeta de cr\u00e9dito" }, { label: "D", text: "Un tipo de inversi\u00f3n" }], correctAnswer: "B", explanation: "El IVA es un impuesto indirecto que se aplica al consumo de bienes y servicios. En Colombia la tarifa general es del 19%.", tip: "\ud83d\udcb0 TRUCO: IVA en Colombia = 19% general. Algunos productos de la canasta familiar est\u00e1n exentos (sin IVA) como la leche y los huevos." },
  { id: "soc-42", subject: "sociales", topic: "Constituci\u00f3n pol\u00edtica", difficulty: "facil", text: "\u00bfCu\u00e1ntas c\u00e1maras tiene el Congreso colombiano?", options: [{ label: "A", text: "Una" }, { label: "B", text: "Dos: Senado y C\u00e1mara de Representantes" }, { label: "C", text: "Tres" }, { label: "D", text: "Cuatro" }], correctAnswer: "B", explanation: "El Congreso es bicameral: Senado (100 senadores + curules especiales) y C\u00e1mara de Representantes (166+ representantes).", tip: "\ud83d\udccb TRUCO: Senado = representa a TODO el pa\u00eds. C\u00e1mara = representa a cada departamento." },
  { id: "soc-43", subject: "sociales", topic: "Geograf\u00eda", difficulty: "facil", text: "\u00bfCu\u00e1l es el clima predominante de la regi\u00f3n Caribe colombiana?", options: [{ label: "A", text: "Fr\u00edo de monta\u00f1a" }, { label: "B", text: "C\u00e1lido tropical" }, { label: "C", text: "Templado lluvioso" }, { label: "D", text: "Polar" }], correctAnswer: "B", explanation: "La regi\u00f3n Caribe tiene clima c\u00e1lido tropical con temperaturas promedio de 28\u00b0C.", tip: "\ud83c\udf0e TRUCO: En Colombia, el clima depende de la ALTITUD, no de las estaciones: 0-1000m=c\u00e1lido, 1000-2000m=templado, 2000-3000m=fr\u00edo, +3000m=p\u00e1ramo." },
  { id: "soc-44", subject: "sociales", topic: "Historia de Colombia", difficulty: "medio", text: "\u00bfQui\u00e9n tradujo los Derechos del Hombre y del Ciudadano al espa\u00f1ol?", options: [{ label: "A", text: "Sim\u00f3n Bol\u00edvar" }, { label: "B", text: "Antonio Nari\u00f1o" }, { label: "C", text: "Francisco de Paula Santander" }, { label: "D", text: "Camilo Torres" }], correctAnswer: "B", explanation: "Antonio Nari\u00f1o tradujo la Declaraci\u00f3n de los Derechos del Hombre en 1793 y la distribuy\u00f3 en la Nueva Granada.", tip: "\ud83d\udcc5 TRUCO: Nari\u00f1o = precursor de la independencia. Tradujo los derechos del hombre = plant\u00f3 la semilla de la independencia." },
  { id: "soc-45", subject: "sociales", topic: "Econom\u00eda b\u00e1sica", difficulty: "facil", text: "\u00bfQu\u00e9 es el salario m\u00ednimo?", options: [{ label: "A", text: "El salario m\u00e1s alto que se puede ganar" }, { label: "B", text: "La cantidad m\u00ednima legal que un empleador debe pagar a un trabajador" }, { label: "C", text: "El salario promedio del pa\u00eds" }, { label: "D", text: "Un impuesto sobre los salarios" }], correctAnswer: "B", explanation: "El SMLMV (Salario M\u00ednimo Legal Mensual Vigente) es la cantidad m\u00ednima que un empleador debe pagar.", tip: "\ud83d\udcb0 TRUCO: SMLMV se ajusta cada a\u00f1o (generalmente en enero). Incluye auxilio de transporte para quienes ganan hasta 2 SMLMV." },
  { id: "soc-46", subject: "sociales", topic: "Constituci\u00f3n pol\u00edtica", difficulty: "medio", text: "\u00bfQu\u00e9 es el derecho de petici\u00f3n?", options: [{ label: "A", text: "El derecho a votar" }, { label: "B", text: "El derecho a presentar solicitudes respetuosas a las autoridades y obtener respuesta" }, { label: "C", text: "El derecho a protestar" }, { label: "D", text: "El derecho a un abogado" }], correctAnswer: "B", explanation: "El derecho de petici\u00f3n (art. 23) permite a cualquier persona solicitar informaci\u00f3n o hacer peticiones a las autoridades, quienes deben responder.", tip: "\ud83d\udccb TRUCO: Derecho de petici\u00f3n = las autoridades DEBEN responder en 15 d\u00edas h\u00e1biles. Si no responden, se viola tu derecho." },
  { id: "soc-47", subject: "sociales", topic: "Geograf\u00eda", difficulty: "facil", text: "\u00bfQu\u00e9 es la l\u00ednea del Ecuador y c\u00f3mo afecta a Colombia?", options: [{ label: "A", text: "Es un r\u00edo que divide a Colombia" }, { label: "B", text: "Es la l\u00ednea imaginaria que divide la Tierra en hemisferio norte y sur; pasa cerca de Colombia" }, { label: "C", text: "Es la frontera con Ecuador" }, { label: "D", text: "Es una carretera" }], correctAnswer: "B", explanation: "La l\u00ednea del Ecuador pasa por la parte sur de Colombia (departamento de Amazonas), d\u00e1ndole un clima tropical.", tip: "\ud83c\udf0e TRUCO: Colombia est\u00e1 CASI en la l\u00ednea del Ecuador = no tiene estaciones (verano/invierno). El clima depende de la altitud." },
  { id: "soc-48", subject: "sociales", topic: "Historia de Colombia", difficulty: "medio", text: "\u00bfQu\u00e9 fue la Expedici\u00f3n Bot\u00e1nica?", options: [{ label: "A", text: "Una guerra contra Espa\u00f1a" }, { label: "B", text: "Una investigaci\u00f3n cient\u00edfica liderada por Jos\u00e9 Celestino Mutis para estudiar la flora colombiana" }, { label: "C", text: "Un viaje comercial" }, { label: "D", text: "Una misi\u00f3n religiosa" }], correctAnswer: "B", explanation: "La Expedici\u00f3n Bot\u00e1nica (1783-1816) clasific\u00f3 miles de plantas de la Nueva Granada bajo la direcci\u00f3n de Jos\u00e9 Celestino Mutis.", tip: "\ud83d\udcc5 TRUCO: Mutis = Expedici\u00f3n Bot\u00e1nica = estudio de la flora. Los dibujos bot\u00e1nicos de esta expedici\u00f3n son Patrimonio de la Humanidad." },
  { id: "soc-49", subject: "sociales", topic: "Constituci\u00f3n pol\u00edtica", difficulty: "medio", text: "\u00bfCu\u00e1l es la funci\u00f3n de la Fiscal\u00eda General de la Naci\u00f3n?", options: [{ label: "A", text: "Recaudar impuestos" }, { label: "B", text: "Investigar delitos y acusar ante los jueces" }, { label: "C", text: "Hacer leyes" }, { label: "D", text: "Gobernar los departamentos" }], correctAnswer: "B", explanation: "La Fiscal\u00eda investiga delitos, recoge evidencia y acusa a los presuntos responsables ante los jueces.", tip: "\ud83d\udccb TRUCO: Fiscal\u00eda = INVESTIGA delitos y ACUSA. Los jueces JUZGAN y condenan. Son funciones diferentes." },
  { id: "soc-50", subject: "sociales", topic: "Econom\u00eda b\u00e1sica", difficulty: "medio", text: "\u00bfQu\u00e9 es una cooperativa?", options: [{ label: "A", text: "Una empresa del gobierno" }, { label: "B", text: "Una organizaci\u00f3n donde los socios son due\u00f1os y se benefician colectivamente" }, { label: "C", text: "Un banco" }, { label: "D", text: "Un sindicato" }], correctAnswer: "B", explanation: "Las cooperativas son organizaciones donde los asociados son due\u00f1os, toman decisiones democr\u00e1ticamente y comparten beneficios.", tip: "\ud83d\udcb0 TRUCO: Cooperativa = todos son due\u00f1os y deciden juntos. Es diferente de una empresa donde hay un due\u00f1o y empleados." },
  { id: "eng-1", subject: "ingles", topic: "Gram\u00e1tica", difficulty: "facil", text: "Complete: She _____ to school every day.", options: [{ label: "A", text: "go" }, { label: "B", text: "goes" }, { label: "C", text: "going" }, { label: "D", text: "gone" }], correctAnswer: "B", explanation: "Con 'she' (tercera persona singular) en presente simple, el verbo lleva 's': goes.", tip: "\ud83c\uddec\ud83c\udde7 TRUCO: He/She/It = verbo + S en presente simple. I/You/We/They = verbo sin S." },
  { id: "eng-2", subject: "ingles", topic: "Gram\u00e1tica", difficulty: "facil", text: "Choose the correct sentence:", options: [{ label: "A", text: "She don't like coffee" }, { label: "B", text: "She doesn't likes coffee" }, { label: "C", text: "She doesn't like coffee" }, { label: "D", text: "She not like coffee" }], correctAnswer: "C", explanation: "Para negar en presente simple con he/she/it: doesn't + verbo BASE (sin s).", tip: "\ud83c\uddec\ud83c\udde7 TRUCO: Negativo con he/she/it = doesn't + verbo SIN 's'. La 's' ya est\u00e1 en 'doesn't'." },
  { id: "eng-3", subject: "ingles", topic: "Gram\u00e1tica", difficulty: "facil", text: "Complete: They _____ playing soccer when it started to rain.", options: [{ label: "A", text: "was" }, { label: "B", text: "were" }, { label: "C", text: "are" }, { label: "D", text: "is" }], correctAnswer: "B", explanation: "'They' usa 'were' en pasado continuo: They were playing.", tip: "\ud83c\uddec\ud83c\udde7 TRUCO: Was = I/He/She/It. Were = You/We/They. Memoriza: 'I WAS, they WERE'." },
  { id: "eng-4", subject: "ingles", topic: "Vocabulario", difficulty: "facil", text: "What does 'however' mean in Spanish?", options: [{ label: "A", text: "Porque" }, { label: "B", text: "Sin embargo" }, { label: "C", text: "Adem\u00e1s" }, { label: "D", text: "Por ejemplo" }], correctAnswer: "B", explanation: "However = sin embargo. Es un conector de contraste.", tip: "\ud83c\uddec\ud83c\udde7 TRUCO: Conectores clave: However=sin embargo, Therefore=por lo tanto, Moreover=adem\u00e1s, Nevertheless=no obstante." },
  { id: "eng-5", subject: "ingles", topic: "Vocabulario", difficulty: "facil", text: "What is the opposite of 'expensive'?", options: [{ label: "A", text: "Beautiful" }, { label: "B", text: "Cheap" }, { label: "C", text: "Big" }, { label: "D", text: "New" }], correctAnswer: "B", explanation: "Expensive = caro. Cheap = barato. Son opuestos.", tip: "\ud83c\uddec\ud83c\udde7 TRUCO: Memoriza pares de opuestos: expensive/cheap, big/small, hot/cold, fast/slow, easy/hard." },
  { id: "eng-6", subject: "ingles", topic: "Reading comprehension", difficulty: "facil", text: "Read: 'Maria wakes up at 6 AM every morning. She takes a shower, has breakfast, and leaves for work at 7:30. She works as a teacher at a local school.'\n\nWhat time does Maria leave for work?", options: [{ label: "A", text: "6:00 AM" }, { label: "B", text: "7:00 AM" }, { label: "C", text: "7:30 AM" }, { label: "D", text: "8:00 AM" }], correctAnswer: "C", explanation: "El texto dice claramente: 'leaves for work at 7:30'.", tip: "\ud83c\uddec\ud83c\udde7 TRUCO: En reading comprehension, busca la INFORMACI\u00d3N EXACTA en el texto. No adivines." },
  { id: "eng-7", subject: "ingles", topic: "Gram\u00e1tica", difficulty: "facil", text: "Complete: I have _____ been to Paris.", options: [{ label: "A", text: "ever" }, { label: "B", text: "never" }, { label: "C", text: "always" }, { label: "D", text: "yet" }], correctAnswer: "B", explanation: "'I have never been to Paris' = Nunca he estado en Par\u00eds. 'Never' expresa negaci\u00f3n.", tip: "\ud83c\uddec\ud83c\udde7 TRUCO: Present perfect + never = algo que NUNCA has hecho. Have you EVER...? = \u00bfAlguna vez has...?" },
  { id: "eng-8", subject: "ingles", topic: "Gram\u00e1tica", difficulty: "facil", text: "Which is correct?\n\n_____ you like some coffee?", options: [{ label: "A", text: "Do" }, { label: "B", text: "Would" }, { label: "C", text: "Are" }, { label: "D", text: "Is" }], correctAnswer: "B", explanation: "'Would you like...?' es la forma educada de ofrecer algo.", tip: "\ud83c\uddec\ud83c\udde7 TRUCO: 'Would you like...?' = \u00bfTe gustar\u00eda...? (ofrecer). 'Do you like...?' = \u00bfTe gusta...? (preguntar gusto general)." },
  { id: "eng-9", subject: "ingles", topic: "Vocabulario", difficulty: "facil", text: "What does 'deadline' mean?", options: [{ label: "A", text: "L\u00ednea de muerte" }, { label: "B", text: "Fecha l\u00edmite de entrega" }, { label: "C", text: "Una l\u00ednea en el piso" }, { label: "D", text: "Un tipo de cuerda" }], correctAnswer: "B", explanation: "Deadline = fecha l\u00edmite para entregar algo. No se traduce literalmente.", tip: "\ud83c\uddec\ud83c\udde7 TRUCO: Cuidado con las traducciones literales. 'Deadline' NO es 'l\u00ednea de muerte'. Busca el SIGNIFICADO, no la traducci\u00f3n palabra por palabra." },
  { id: "eng-10", subject: "ingles", topic: "Reading comprehension", difficulty: "facil", text: "Read: 'The Amazon rainforest produces about 20% of the world's oxygen. It is home to millions of species of plants and animals. Deforestation is the biggest threat to this ecosystem.'\n\nWhat is the biggest threat to the Amazon?", options: [{ label: "A", text: "Pollution" }, { label: "B", text: "Deforestation" }, { label: "C", text: "Climate change" }, { label: "D", text: "Tourism" }], correctAnswer: "B", explanation: "El texto dice: 'Deforestation is the biggest threat'.", tip: "\ud83c\uddec\ud83c\udde7 TRUCO: 'Biggest threat' = la mayor amenaza. Lee la pregunta PRIMERO, luego busca la respuesta en el texto." },
  { id: "eng-11", subject: "ingles", topic: "Gram\u00e1tica", difficulty: "medio", text: "Complete: If it rains, I _____ stay at home.", options: [{ label: "A", text: "would" }, { label: "B", text: "will" }, { label: "C", text: "am" }, { label: "D", text: "was" }], correctAnswer: "B", explanation: "First conditional: If + present simple, will + verb. Expresa una posibilidad real.", tip: "\ud83c\uddec\ud83c\udde7 TRUCO: If + presente \u2192 WILL (posibilidad real). If + pasado \u2192 WOULD (situaci\u00f3n imaginaria)." },
  { id: "eng-12", subject: "ingles", topic: "Gram\u00e1tica", difficulty: "facil", text: "Choose the correct comparative: This book is _____ than that one.", options: [{ label: "A", text: "more interesting" }, { label: "B", text: "more interestinger" }, { label: "C", text: "interestinger" }, { label: "D", text: "most interesting" }], correctAnswer: "A", explanation: "Adjetivos largos (3+ s\u00edlabas) usan 'more' para comparar: more interesting.", tip: "\ud83c\uddec\ud83c\udde7 TRUCO: Adjetivo corto (1-2 s\u00edlabas) \u2192 agrega -er (bigger, taller). Adjetivo largo \u2192 more + adjetivo (more beautiful)." },
  { id: "eng-13", subject: "ingles", topic: "Vocabulario", difficulty: "facil", text: "What does 'environment' mean?", options: [{ label: "A", text: "Entretenimiento" }, { label: "B", text: "Medio ambiente" }, { label: "C", text: "Inversi\u00f3n" }, { label: "D", text: "Evento" }], correctAnswer: "B", explanation: "Environment = medio ambiente.", tip: "\ud83c\uddec\ud83c\udde7 TRUCO: Palabras clave del ICFES en ingl\u00e9s: environment=medio ambiente, development=desarrollo, government=gobierno." },
  { id: "eng-14", subject: "ingles", topic: "Gram\u00e1tica", difficulty: "medio", text: "Complete: She has lived here _____ 2015.", options: [{ label: "A", text: "for" }, { label: "B", text: "since" }, { label: "C", text: "during" }, { label: "D", text: "ago" }], correctAnswer: "B", explanation: "Since = desde (un punto en el tiempo). For = durante (un per\u00edodo de tiempo).", tip: "\ud83c\uddec\ud83c\udde7 TRUCO: SINCE + momento espec\u00edfico (since 2015, since Monday). FOR + duraci\u00f3n (for 3 years, for 2 hours)." },
  { id: "eng-15", subject: "ingles", topic: "Gram\u00e1tica", difficulty: "medio", text: "Which sentence is in passive voice?", options: [{ label: "A", text: "The dog bit the boy" }, { label: "B", text: "The boy was bitten by the dog" }, { label: "C", text: "The dog is biting" }, { label: "D", text: "The boy runs fast" }], correctAnswer: "B", explanation: "Voz pasiva: sujeto + was/were + past participle + by + agente. 'The boy was bitten by the dog'.", tip: "\ud83c\uddec\ud83c\udde7 TRUCO: Pasiva = el sujeto RECIBE la acci\u00f3n. Busca 'was/were + participio' como se\u00f1al de voz pasiva." },
  { id: "eng-16", subject: "ingles", topic: "Reading comprehension", difficulty: "facil", text: "Read: 'John has been working at the hospital for 10 years. He started as a nurse and now he is the head of the department. His colleagues respect him for his dedication.'\n\nHow long has John worked at the hospital?", options: [{ label: "A", text: "5 years" }, { label: "B", text: "8 years" }, { label: "C", text: "10 years" }, { label: "D", text: "15 years" }], correctAnswer: "C", explanation: "El texto dice: 'for 10 years'.", tip: "\ud83c\uddec\ud83c\udde7 TRUCO: 'How long...?' pregunta por DURACI\u00d3N. Busca 'for' seguido de un n\u00famero en el texto." },
  { id: "eng-17", subject: "ingles", topic: "Gram\u00e1tica", difficulty: "medio", text: "Complete: I wish I _____ taller.", options: [{ label: "A", text: "am" }, { label: "B", text: "was/were" }, { label: "C", text: "will be" }, { label: "D", text: "have been" }], correctAnswer: "B", explanation: "'I wish + past simple' expresa un deseo sobre algo que no es real ahora.", tip: "\ud83c\uddec\ud83c\udde7 TRUCO: 'I wish' = ojal\u00e1. Despu\u00e9s de 'wish' se usa PASADO para hablar de deseos presentes (irreales)." },
  { id: "eng-18", subject: "ingles", topic: "Vocabulario", difficulty: "facil", text: "What is the meaning of 'although'?", options: [{ label: "A", text: "Porque" }, { label: "B", text: "Aunque" }, { label: "C", text: "Cuando" }, { label: "D", text: "Donde" }], correctAnswer: "B", explanation: "Although = aunque. Introduce una idea contraria a lo esperado.", tip: "\ud83c\uddec\ud83c\udde7 TRUCO: Although/Even though/Despite = aunque (contraste). Because/Since = porque (causa)." },
  { id: "eng-19", subject: "ingles", topic: "Gram\u00e1tica", difficulty: "medio", text: "Choose the correct form: He enjoys _____ books.", options: [{ label: "A", text: "read" }, { label: "B", text: "reading" }, { label: "C", text: "to read" }, { label: "D", text: "reads" }], correctAnswer: "B", explanation: "Despu\u00e9s de 'enjoy' siempre va el verbo en gerundio (-ing): enjoy reading.", tip: "\ud83c\uddec\ud83c\udde7 TRUCO: Verbos que van con -ing: enjoy, avoid, finish, mind, suggest. Verbos con 'to': want, need, decide, hope." },
  { id: "eng-20", subject: "ingles", topic: "Reading comprehension", difficulty: "medio", text: "Read: 'Global warming is causing sea levels to rise. Scientists predict that by 2100, many coastal cities could be underwater. This would affect millions of people worldwide.'\n\nAccording to the text, what could happen by 2100?", options: [{ label: "A", text: "All cities will disappear" }, { label: "B", text: "Many coastal cities could be underwater" }, { label: "C", text: "The ocean will dry up" }, { label: "D", text: "Global warming will stop" }], correctAnswer: "B", explanation: "El texto dice: 'many coastal cities could be underwater'.", tip: "\ud83c\uddec\ud83c\udde7 TRUCO: La palabra 'could' indica posibilidad, no certeza. El ICFES valora que distingas entre 'will' (certeza) y 'could/might' (posibilidad)." },
  { id: "eng-21", subject: "ingles", topic: "Gram\u00e1tica", difficulty: "facil", text: "Complete: _____ you ever eaten sushi?", options: [{ label: "A", text: "Do" }, { label: "B", text: "Did" }, { label: "C", text: "Have" }, { label: "D", text: "Are" }], correctAnswer: "C", explanation: "Present perfect: Have/Has + subject + ever + past participle. 'Have you ever eaten sushi?'", tip: "\ud83c\uddec\ud83c\udde7 TRUCO: 'Have you ever...?' = \u00bfAlguna vez has...? Es la pregunta de experiencia m\u00e1s com\u00fan en ingl\u00e9s." },
  { id: "eng-22", subject: "ingles", topic: "Vocabulario", difficulty: "facil", text: "What does 'achieve' mean?", options: [{ label: "A", text: "Evitar" }, { label: "B", text: "Lograr/Alcanzar" }, { label: "C", text: "Archivar" }, { label: "D", text: "Recibir" }], correctAnswer: "B", explanation: "Achieve = lograr, alcanzar una meta. Achievement = logro.", tip: "\ud83c\uddec\ud83c\udde7 TRUCO: Achieve suena como 'a-chiv' pero NO es 'archivar'. Significa LOGRAR. Cuidado con los falsos amigos." },
  { id: "eng-23", subject: "ingles", topic: "Gram\u00e1tica", difficulty: "medio", text: "Choose: Neither Tom _____ Jerry came to the party.", options: [{ label: "A", text: "or" }, { label: "B", text: "and" }, { label: "C", text: "nor" }, { label: "D", text: "but" }], correctAnswer: "C", explanation: "Neither...nor = ni...ni. Either...or = o...o.", tip: "\ud83c\uddec\ud83c\udde7 TRUCO: Neither + NOR (ambos con N). Either + OR (sin N). Siempre van en pareja." },
  { id: "eng-24", subject: "ingles", topic: "Reading comprehension", difficulty: "facil", text: "Read: 'The Colombian government has invested heavily in education over the past decade. As a result, literacy rates have increased from 88% to 95%. However, rural areas still lag behind urban centers.'\n\nWhat has improved in Colombia?", options: [{ label: "A", text: "Employment rates" }, { label: "B", text: "Literacy rates" }, { label: "C", text: "Tourism" }, { label: "D", text: "Healthcare" }], correctAnswer: "B", explanation: "El texto dice: 'literacy rates have increased from 88% to 95%'.", tip: "\ud83c\uddec\ud83c\udde7 TRUCO: 'As a result' = como resultado. Busca qu\u00e9 viene DESPU\u00c9S de esta frase para encontrar el efecto/resultado." },
  { id: "eng-25", subject: "ingles", topic: "Gram\u00e1tica", difficulty: "medio", text: "Which is the correct question tag? You are Colombian, _____?", options: [{ label: "A", text: "are you?" }, { label: "B", text: "aren't you?" }, { label: "C", text: "do you?" }, { label: "D", text: "don't you?" }], correctAnswer: "B", explanation: "Si la oraci\u00f3n es afirmativa, el tag es negativo: 'are' \u2192 'aren't you?'", tip: "\ud83c\uddec\ud83c\udde7 TRUCO: Afirmativo \u2192 tag negativo. Negativo \u2192 tag positivo. 'You like it, DON'T you?' 'You don't like it, DO you?'" },
  { id: "eng-26", subject: "ingles", topic: "Vocabulario", difficulty: "facil", text: "What does 'improve' mean?", options: [{ label: "A", text: "Empeorar" }, { label: "B", text: "Mejorar" }, { label: "C", text: "Improvisar" }, { label: "D", text: "Imprimir" }], correctAnswer: "B", explanation: "Improve = mejorar. Improvement = mejora.", tip: "\ud83c\uddec\ud83c\udde7 TRUCO: Improve \u2260 improvisar (improvise). Cuidado con falsos amigos. Improve = hacer mejor." },
  { id: "eng-27", subject: "ingles", topic: "Gram\u00e1tica", difficulty: "medio", text: "Complete: She _____ her homework before she went out.", options: [{ label: "A", text: "has finished" }, { label: "B", text: "had finished" }, { label: "C", text: "finished" }, { label: "D", text: "was finishing" }], correctAnswer: "B", explanation: "Past perfect (had + participio) se usa para una acci\u00f3n ANTES de otra en el pasado.", tip: "\ud83c\uddec\ud83c\udde7 TRUCO: Past perfect = 'el pasado del pasado'. Algo que pas\u00f3 PRIMERO: 'She HAD finished (primero) before she went out (despu\u00e9s)'." },
  { id: "eng-28", subject: "ingles", topic: "Reading comprehension", difficulty: "facil", text: "Read: 'Despite having a small budget, the school achieved remarkable results. Students performed above the national average in all subjects. The key was the dedication of teachers who volunteered extra hours.'\n\nWhat was the key to the school's success?", options: [{ label: "A", text: "A large budget" }, { label: "B", text: "New technology" }, { label: "C", text: "The dedication of teachers" }, { label: "D", text: "Small class sizes" }], correctAnswer: "C", explanation: "'The key was the dedication of teachers who volunteered extra hours.'", tip: "\ud83c\uddec\ud83c\udde7 TRUCO: 'The key was...' = la clave fue... Busca esta frase exacta para encontrar la respuesta." },
  { id: "eng-29", subject: "ingles", topic: "Gram\u00e1tica", difficulty: "medio", text: "Choose the correct modal: You _____ wear a seatbelt. It's the law.", options: [{ label: "A", text: "should" }, { label: "B", text: "must" }, { label: "C", text: "can" }, { label: "D", text: "might" }], correctAnswer: "B", explanation: "Must = obligaci\u00f3n (es la ley). Should = consejo/recomendaci\u00f3n.", tip: "\ud83c\uddec\ud83c\udde7 TRUCO: Must = OBLIGACI\u00d3N (ley, regla). Should = CONSEJO (recomendaci\u00f3n). Can = capacidad. Might = posibilidad." },
  { id: "eng-30", subject: "ingles", topic: "Vocabulario", difficulty: "facil", text: "What is the plural of 'child'?", options: [{ label: "A", text: "Childs" }, { label: "B", text: "Childes" }, { label: "C", text: "Children" }, { label: "D", text: "Childrens" }], correctAnswer: "C", explanation: "Child \u2192 Children es un plural irregular.", tip: "\ud83c\uddec\ud83c\udde7 TRUCO: Plurales irregulares comunes: child\u2192children, man\u2192men, woman\u2192women, tooth\u2192teeth, foot\u2192feet, mouse\u2192mice." },
  { id: "eng-31", subject: "ingles", topic: "Gram\u00e1tica", difficulty: "dificil", text: "Complete: I'm looking forward _____ you.", options: [{ label: "A", text: "to see" }, { label: "B", text: "to seeing" }, { label: "C", text: "seeing" }, { label: "D", text: "see" }], correctAnswer: "B", explanation: "'Look forward to' + gerundio (-ing). El 'to' aqu\u00ed es preposici\u00f3n, no parte del infinitivo.", tip: "\ud83c\uddec\ud83c\udde7 TRUCO: 'Look forward TO + -ing' (no infinitivo). 'I'm looking forward to SEEING you' = Espero con ansias verte." },
  { id: "eng-32", subject: "ingles", topic: "Vocabulario", difficulty: "facil", text: "What does 'research' mean?", options: [{ label: "A", text: "Buscar de nuevo" }, { label: "B", text: "Investigaci\u00f3n" }, { label: "C", text: "Recurso" }, { label: "D", text: "Rescate" }], correctAnswer: "B", explanation: "Research = investigaci\u00f3n. To research = investigar.", tip: "\ud83c\uddec\ud83c\udde7 TRUCO: Research = investigaci\u00f3n (acad\u00e9mica/cient\u00edfica). NO es 're-search' (buscar de nuevo)." },
  { id: "eng-33", subject: "ingles", topic: "Gram\u00e1tica", difficulty: "facil", text: "Which sentence uses the present perfect correctly?", options: [{ label: "A", text: "I have went to the store" }, { label: "B", text: "I have gone to the store" }, { label: "C", text: "I have go to the store" }, { label: "D", text: "I have going to the store" }], correctAnswer: "B", explanation: "Present perfect = have/has + PAST PARTICIPLE. Go \u2192 gone (irregular).", tip: "\ud83c\uddec\ud83c\udde7 TRUCO: Have + participio pasado. Irregulares comunes: go\u2192gone, eat\u2192eaten, see\u2192seen, do\u2192done, write\u2192written." },
  { id: "eng-34", subject: "ingles", topic: "Reading comprehension", difficulty: "facil", text: "Read: 'Coffee is one of the most popular beverages in the world. Over 2 billion cups are consumed daily. Brazil is the largest producer, followed by Vietnam and Colombia.'\n\nWho is the second largest coffee producer?", options: [{ label: "A", text: "Colombia" }, { label: "B", text: "Brazil" }, { label: "C", text: "Vietnam" }, { label: "D", text: "Indonesia" }], correctAnswer: "C", explanation: "'Brazil is the largest producer, followed by Vietnam and Colombia.' Vietnam is second.", tip: "\ud83c\uddec\ud83c\udde7 TRUCO: 'Followed by' = seguido por. El primero mencionado despu\u00e9s de 'followed by' es el segundo en la lista." },
  { id: "eng-35", subject: "ingles", topic: "Gram\u00e1tica", difficulty: "medio", text: "Complete: If I _____ rich, I would travel the world.", options: [{ label: "A", text: "am" }, { label: "B", text: "were" }, { label: "C", text: "will be" }, { label: "D", text: "have been" }], correctAnswer: "B", explanation: "Second conditional: If + past simple (were), would + verb. Para situaciones hipot\u00e9ticas.", tip: "\ud83c\uddec\ud83c\udde7 TRUCO: 'If I WERE' (no 'was') es la forma correcta en condicional 2. Aunque suene raro, 'were' se usa con todas las personas en condicionales." },
  { id: "eng-36", subject: "ingles", topic: "Vocabulario", difficulty: "medio", text: "What does 'afford' mean?", options: [{ label: "A", text: "Pagar/Poder permitirse econ\u00f3micamente" }, { label: "B", text: "Ofrecer" }, { label: "C", text: "Adornarse" }, { label: "D", text: "Adoptar" }], correctAnswer: "A", explanation: "Afford = poder permitirse algo econ\u00f3micamente. 'I can't afford it' = No me alcanza el dinero.", tip: "\ud83c\uddec\ud83c\udde7 TRUCO: 'Can't afford' = no tengo dinero suficiente para eso. Es una expresi\u00f3n MUY com\u00fan en ingl\u00e9s cotidiano." },
  { id: "eng-37", subject: "ingles", topic: "Gram\u00e1tica", difficulty: "facil", text: "Complete: This is the _____ movie I've ever seen.", options: [{ label: "A", text: "good" }, { label: "B", text: "better" }, { label: "C", text: "best" }, { label: "D", text: "most good" }], correctAnswer: "C", explanation: "Superlativo de 'good' = 'best'. 'The best movie' = la mejor pel\u00edcula.", tip: "\ud83c\uddec\ud83c\udde7 TRUCO: good \u2192 better \u2192 best. bad \u2192 worse \u2192 worst. Memoriza estos irregulares, aparecen MUCHO." },
  { id: "eng-38", subject: "ingles", topic: "Reading comprehension", difficulty: "medio", text: "Read: 'Recycling is essential for reducing waste and conserving resources. By recycling paper, we save trees. By recycling plastic, we reduce ocean pollution. Everyone can contribute by separating their trash.'\n\nWhat is the main purpose of this text?", options: [{ label: "A", text: "To describe how trash is collected" }, { label: "B", text: "To encourage people to recycle" }, { label: "C", text: "To explain how paper is made" }, { label: "D", text: "To discuss ocean biology" }], correctAnswer: "B", explanation: "El texto habla de los beneficios del reciclaje y termina animando a todos a separar basura = su prop\u00f3sito es promover el reciclaje.", tip: "\ud83c\uddec\ud83c\udde7 TRUCO: 'Main purpose' = prop\u00f3sito principal. Lee la PRIMERA y \u00daLTIMA oraci\u00f3n del texto para identificar el prop\u00f3sito." },
  { id: "eng-39", subject: "ingles", topic: "Gram\u00e1tica", difficulty: "medio", text: "Choose: She asked me _____ I was from.", options: [{ label: "A", text: "where" }, { label: "B", text: "what" }, { label: "C", text: "when" }, { label: "D", text: "which" }], correctAnswer: "A", explanation: "'Where are you from?' \u2192 She asked me where I was from (reported question).", tip: "\ud83c\uddec\ud83c\udde7 TRUCO: En reported speech, la pregunta se convierte en oraci\u00f3n: 'Where are you from?' \u2192 'She asked where I was from' (sin signo de interrogaci\u00f3n)." },
  { id: "eng-40", subject: "ingles", topic: "Vocabulario", difficulty: "facil", text: "What does 'available' mean?", options: [{ label: "A", text: "Valioso" }, { label: "B", text: "Disponible" }, { label: "C", text: "Variable" }, { label: "D", text: "Avanzado" }], correctAnswer: "B", explanation: "Available = disponible. 'Is this seat available?' = \u00bfEst\u00e1 libre este asiento?", tip: "\ud83c\uddec\ud83c\udde7 TRUCO: Available = disponible para usar/comprar. 'Currently available' = actualmente disponible." },
  { id: "eng-41", subject: "ingles", topic: "Gram\u00e1tica", difficulty: "medio", text: "Complete: I _____ English for five years.", options: [{ label: "A", text: "study" }, { label: "B", text: "am studying" }, { label: "C", text: "have been studying" }, { label: "D", text: "studied" }], correctAnswer: "C", explanation: "Present perfect continuous: have been + -ing. Se usa para acciones que empezaron en el pasado y contin\u00faan.", tip: "\ud83c\uddec\ud83c\udde7 TRUCO: 'For five years' = durante 5 a\u00f1os (acci\u00f3n que contin\u00faa). Usa present perfect (have been studying), no simple past." },
  { id: "eng-42", subject: "ingles", topic: "Vocabulario", difficulty: "facil", text: "What is a synonym for 'happy'?", options: [{ label: "A", text: "Sad" }, { label: "B", text: "Angry" }, { label: "C", text: "Glad" }, { label: "D", text: "Tired" }], correctAnswer: "C", explanation: "Glad y happy son sin\u00f3nimos: ambos significan contento/feliz.", tip: "\ud83c\uddec\ud83c\udde7 TRUCO: Sin\u00f3nimos de happy: glad, pleased, cheerful, delighted, joyful. En el ICFES a menudo preguntan sin\u00f3nimos." },
  { id: "eng-43", subject: "ingles", topic: "Gram\u00e1tica", difficulty: "medio", text: "Complete: The book _____ by Shakespeare was published in 1599.", options: [{ label: "A", text: "write" }, { label: "B", text: "writing" }, { label: "C", text: "written" }, { label: "D", text: "wrote" }], correctAnswer: "C", explanation: "Participio pasado como adjetivo: 'written by Shakespeare' = escrito por Shakespeare.", tip: "\ud83c\uddec\ud83c\udde7 TRUCO: 'Written by' = escrito por. 'Made by' = hecho por. 'Directed by' = dirigido por. Participio + by = autor/creador." },
  { id: "eng-44", subject: "ingles", topic: "Reading comprehension", difficulty: "facil", text: "Read: 'Solar energy is becoming more affordable every year. In 2010, solar panels cost about $7 per watt. Today, they cost less than $1 per watt. This dramatic decrease has made solar power accessible to more people.'\n\nWhat has happened to the cost of solar panels?", options: [{ label: "A", text: "It has increased dramatically" }, { label: "B", text: "It has stayed the same" }, { label: "C", text: "It has decreased significantly" }, { label: "D", text: "It has fluctuated unpredictably" }], correctAnswer: "C", explanation: "From $7 to less than $1 = significant decrease.", tip: "\ud83c\uddec\ud83c\udde7 TRUCO: Busca los n\u00fameros para comparar: $7 \u2192 menos de $1 = baj\u00f3 mucho. Los datos num\u00e9ricos son la evidencia m\u00e1s clara." },
  { id: "eng-45", subject: "ingles", topic: "Gram\u00e1tica", difficulty: "facil", text: "Choose the correct preposition: I'm interested _____ learning new languages.", options: [{ label: "A", text: "on" }, { label: "B", text: "in" }, { label: "C", text: "at" }, { label: "D", text: "for" }], correctAnswer: "B", explanation: "Interested IN = interesado en. Es una colocaci\u00f3n fija.", tip: "\ud83c\uddec\ud83c\udde7 TRUCO: Adjetivo + preposici\u00f3n fija: interested IN, good AT, afraid OF, different FROM. Memoriza la preposici\u00f3n junto con el adjetivo." },
  { id: "eng-46", subject: "ingles", topic: "Vocabulario", difficulty: "medio", text: "What does 'actually' mean in English?", options: [{ label: "A", text: "Actualmente" }, { label: "B", text: "En realidad/De hecho" }, { label: "C", text: "En el acto" }, { label: "D", text: "Exactamente" }], correctAnswer: "B", explanation: "Actually = en realidad (NO 'actualmente'). 'Currently' = actualmente.", tip: "\ud83c\uddec\ud83c\udde7 TRUCO: FALSO AMIGO: actually \u2260 actualmente. Actually = de hecho/en realidad. Currently = actualmente." },
  { id: "eng-47", subject: "ingles", topic: "Gram\u00e1tica", difficulty: "medio", text: "Complete: He suggested _____ a new restaurant.", options: [{ label: "A", text: "to try" }, { label: "B", text: "trying" }, { label: "C", text: "try" }, { label: "D", text: "tried" }], correctAnswer: "B", explanation: "Suggest + gerundio: He suggested trying. (No 'suggest to try').", tip: "\ud83c\uddec\ud83c\udde7 TRUCO: Suggest, recommend, avoid, enjoy, finish \u2192 siempre van con -ING, nunca con 'to'." },
  { id: "eng-48", subject: "ingles", topic: "Reading comprehension", difficulty: "medio", text: "Read: 'Many students believe that studying the night before an exam is effective. However, research shows that spreading study sessions over several days leads to better retention. Getting enough sleep before the exam is also crucial for performance.'\n\nAccording to the text, what is more effective for studying?", options: [{ label: "A", text: "Studying all night before the exam" }, { label: "B", text: "Spreading study sessions over several days" }, { label: "C", text: "Not studying at all" }, { label: "D", text: "Studying only on weekends" }], correctAnswer: "B", explanation: "'Spreading study sessions over several days leads to better retention.'", tip: "\ud83c\uddec\ud83c\udde7 TRUCO: 'However' cambia la direcci\u00f3n. Lo que viene DESPU\u00c9S de 'however' es generalmente la posici\u00f3n del autor." },
  { id: "eng-49", subject: "ingles", topic: "Gram\u00e1tica", difficulty: "medio", text: "Which is correct? I _____ TV when the phone rang.", options: [{ label: "A", text: "watched" }, { label: "B", text: "was watching" }, { label: "C", text: "have watched" }, { label: "D", text: "watch" }], correctAnswer: "B", explanation: "Past continuous (was watching) para una acci\u00f3n en progreso interrumpida por otra (the phone rang = past simple).", tip: "\ud83c\uddec\ud83c\udde7 TRUCO: Was/Were + -ing = acci\u00f3n larga en progreso. Past simple = acci\u00f3n corta que interrumpe. 'I was watching (largo) when the phone rang (corto)'." },
  { id: "eng-50", subject: "ingles", topic: "Vocabulario", difficulty: "medio", text: "What does 'eventually' mean?", options: [{ label: "A", text: "Eventualmente" }, { label: "B", text: "Finalmente/Al final" }, { label: "C", text: "Posiblemente" }, { label: "D", text: "Evidentemente" }], correctAnswer: "B", explanation: "Eventually = finalmente, al final. NO 'eventualmente'.", tip: "\ud83c\uddec\ud83c\udde7 TRUCO: Otro FALSO AMIGO: eventually \u2260 eventualmente. Eventually = al final/finalmente. 'He eventually passed the exam' = Al final pas\u00f3 el examen." },
];

export const getQuestionsBySubject = (subjectId: string): Question[] =>
  allQuestions.filter((q) => q.subject === subjectId);

export const getQuestionsByTopic = (subjectId: string, topic: string): Question[] =>
  allQuestions.filter((q) => q.subject === subjectId && q.topic === topic);

export const getQuestionsByDifficulty = (difficulty: "facil" | "medio" | "dificil"): Question[] =>
  allQuestions.filter((q) => q.difficulty === difficulty);
